// Функция для отключения анимаций карточек модов
function disableModCardAnimations() {
    // console.log('🚫 Отключение анимаций карточек модов...');
    
    // Проверяем, уже ли добавлены стили
    if (document.getElementById('disable-mod-animations')) {
        // console.log('📌 Стили для отключения анимаций уже добавлены');
        return;
    }
    
    // Создаем и добавляем CSS стили
    const style = document.createElement('style');
    style.id = 'disable-mod-animations';
    style.textContent = `
        /* Отключаем все анимации для карточек модов */
        .mod-card,
        .mod-card *,
        .mod-card *::before,
        .mod-card *::after {
            animation: none !important;
            transition: none !important;
            transform: none !important;
        }
        
        /* Отключаем анимации появления для контейнера модов */
        #modsContainer,
        #modsContainer *,
        .mods-container,
        .mods-container * {
            animation: none !important;
            transition: none !important;
        }
        
        /* Отключаем анимации для изображений модов */
        .mod-card img,
        .mod-card-image-container img {
            animation: none !important;
            transition: none !important;
        }
        
        /* Отключаем анимации для кнопок в карточках */
        .mod-card button,
        .mod-card .download-btn,
        .mod-card .details-btn {
            animation: none !important;
            transition: none !important;
            transform: none !important;
        }
        
        /* Отключаем hover эффекты для карточек */
        .mod-card:hover,
        .mod-card *:hover {
            animation: none !important;
            transition: none !important;
            transform: none !important;
        }
        
        /* Глобальное отключение анимаций для всех элементов внутри карточек */
        .mod-card * {
            animation-duration: 0s !important;
            transition-duration: 0s !important;
            animation-delay: 0s !important;
            transition-delay: 0s !important;
        }
        
        /* Принудительное отключение transform для карточек */
        .mod-card {
            transform: none !important;
            transform-origin: initial !important;
        }
        
        /* Отключаем анимации для VIP карточек */
        .mod-card.vip-mod,
        .mod-card.vip-mod * {
            animation: none !important;
            transition: none !important;
            transform: none !important;
        }
    `;
    
    document.head.appendChild(style);
    console.log('✅ Анимации карточек модов отключены');
}

// Функция для включения анимаций обратно (если нужно)
function enableModCardAnimations() {
    const style = document.getElementById('disable-mod-animations');
    if (style) {
        style.remove();
        console.log('✅ Анимации карточек модов включены');
    }
}

