// Система бегущей строки уведомлений
class NotificationTicker {
    constructor() {
        this.ticker = document.getElementById('notification-ticker');
        this.content = document.getElementById('ticker-content');
        this.messages = [];
        this.currentIndex = 0;
        this.isVisible = false;
        console.log('🏃‍♂️ NotificationTicker инициализирован:', { ticker: !!this.ticker, content: !!this.content });
    }

    // Показать бегущую строку
    show(type = 'info') {
        if (!this.ticker) return;
        
        this.ticker.style.display = 'block';
        this.ticker.className = type;
        this.isVisible = true;
        // console.log('📢 Бегущая строка показана с типом:', type);
    }

    // Скрыть бегущую строку
    hide() {
        if (!this.ticker) return;
        
        this.ticker.style.display = 'none';
        this.isVisible = false;
        // console.log('🔇 Бегущая строка скрыта');
    }

    // Добавить сообщение о предупреждении
    addWarningMessage(username, reason, moderatorName) {
        // Улучшаем отображение имени модератора
        const displayName = moderatorName === 'Администрация' ? 'Администрация сайта' : moderatorName;
        const message = `⚠️ Пользователю ${username} вынесено предупреждение: ${reason} (${displayName})`;
        this.addMessage(message, 'warning');
    }

    // Добавить сообщение о блокировке
    addBanMessage(username, reason, moderatorName) {
        // Улучшаем отображение имени модератора
        const displayName = moderatorName === 'Администрация' ? 'Администрация сайта' : moderatorName;
        const message = `🚫 Пользователь ${username} заблокирован: ${reason} (${displayName})`;
        this.addMessage(message, 'warning');
    }

    // Добавить информационное сообщение
    addInfoMessage(message) {
        this.addMessage(`📢 ${message}`, 'info');
    }

    // Добавить рекламное сообщение
    addAdMessage(message) {
        this.addMessage(`💎 ${message}`, 'success');
    }

    // Добавить общее сообщение
    addMessage(message, type = 'info') {
        this.messages.push({ text: message, type, timestamp: Date.now() });
        
        // Ограничиваем количество сообщений
        if (this.messages.length > 10) {
            this.messages.shift();
        }

        this.updateTicker();
        this.show(type);
        // console.log('📨 Добавлено сообщение в бегущую строку:', message);
    }

    // Обновить содержимое бегущей строки
    updateTicker() {
        if (!this.content) return;

        if (this.messages.length === 0) {
            this.content.textContent = '📢 Добро пожаловать на KEROSMODS.RU! 🚜 Лучшие моды для Farming Simulator!';
            return;
        }

        // Объединяем все сообщения через разделитель
        const messagesText = this.messages.map(msg => msg.text).join(' • ');
        this.content.textContent = messagesText;
        // console.log('🔄 Бегущая строка обновлена:', messagesText);
    }

    // Очистить все сообщения
    clear() {
        this.messages = [];
        this.updateTicker();
        this.hide();
    }

    // Очистить сообщения (без скрытия)
    clearMessages() {
        this.messages = [];
        this.updateTicker();
        console.log('🧹 Сообщения в бегущей строке очищены');
    }
}

