// Функции для проверки индикаторов предупреждений и блокировок
async function checkWarningsAndBansIndicators() {
    try {
        if (!window.supabase) return;

        // Проверяем предупреждения (активные или бессрочные)
        // Используем два отдельных запроса для надёжности
        const now = new Date().toISOString();
        
        // Запрос 1: Бессрочные предупреждения (expires_at is null)
        let warnings = [];
        try {
            const { data: nullWarnings, error: nullError } = await window.supabase
                .from('user_warnings')
                .select('id')
                .is('expires_at', null)
                .limit(1);
            
            if (!nullError && nullWarnings && nullWarnings.length > 0) {
                warnings = nullWarnings;
            }
        } catch (e) {
            console.warn('Ошибка при проверке бессрочных предупреждений:', e);
        }
        
        if (warnings.length === 0) {
            try {
                // Запрос 2: Активные предупреждения (expires_at > now)
                const { data: activeWarnings, error: activeError } = await window.supabase
                    .from('user_warnings')
                    .select('id')
                    .gt('expires_at', now)
                    .limit(1);
                
                if (!activeError && activeWarnings) {
                    warnings = activeWarnings;
                }
            } catch (e) {
                console.warn('Ошибка при проверке активных предупреждений:', e);
            }
        }
        
        const warningsError = null; // Ошибки обрабатываются выше, здесь всегда null для совместимости
            
        if (!warningsError && warnings && warnings.length > 0) {
            const indicator = document.getElementById('warnings-indicator');
            if (indicator) {
                indicator.style.display = 'inline';
                indicator.style.animation = 'blink 1s infinite';
            }
        }

        // Проверяем блокировки (активные или бессрочные)
        // Используем два отдельных запроса для надёжности
        const banNow = new Date().toISOString();
        
        // Запрос 1: Бессрочные блокировки (ends_at is null)
        let bans = [];
        const { data: nullBans, error: nullBansError } = await window.supabase
            .from('comment_bans')
            .select('id')
            .is('ends_at', null)
            .limit(1);
        
        if (!nullBansError && nullBans && nullBans.length > 0) {
            bans = nullBans;
        } else {
            // Запрос 2: Активные блокировки (ends_at > now)
            const { data: activeBans, error: activeBansError } = await window.supabase
                .from('comment_bans')
                .select('id')
                .gt('ends_at', banNow)
                .limit(1);
            
            if (!activeBansError && activeBans) {
                bans = activeBans;
            }
        }
        
        const bansError = nullBansError; // Используем ошибку первого запроса для совместимости

        if (!bansError && bans && bans.length > 0) {
            const indicator = document.getElementById('bans-indicator');
            if (indicator) {
                indicator.style.display = 'inline';
                indicator.style.animation = 'blink 1s infinite';
            }
        }
    } catch (error) {
        console.log('Ошибка проверки индикаторов:', error);
    }
}

