// Функция для загрузки настроек сайта
async function loadSiteSettings() {
    try {
        // console.log('🔧 Загрузка настроек сайта...');
        
        const { data, error } = await window.supabase
            .from('site_settings')
            .select('setting_key, setting_value')
            .in('setting_key', ['allow_user_mod_upload', 'require_mod_approval']);

        if (error) {
            console.warn('⚠️ Настройки не найдены, используем значения по умолчанию:', error);
            window.userModUploadsEnabled = false;
            window.modApprovalRequired = false;
            return { userModUploadsEnabled: false, modApprovalRequired: false };
        }

        const settings = {};
        data?.forEach(setting => {
            settings[setting.setting_key] = setting.setting_value === 'true';
        });

        // Устанавливаем глобальные переменные
        window.userModUploadsEnabled = settings.allow_user_mod_upload || false;
        window.modApprovalRequired = settings.require_mod_approval || false;

        console.log('🎯 Настройки сайта загружены при инициализации:', {
            userModUploadsEnabled: window.userModUploadsEnabled,
            modApprovalRequired: window.modApprovalRequired
        });
        
        // Обновляем видимость кнопки загрузки мода в навигации
        updateUploadModButtonVisibility();
        
        return { userModUploadsEnabled: window.userModUploadsEnabled, modApprovalRequired: window.modApprovalRequired };

    } catch (error) {
        console.error('❌ Ошибка загрузки настроек сайта:', error);
        window.userModUploadsEnabled = false;
        window.modApprovalRequired = false;
        return { userModUploadsEnabled: false, modApprovalRequired: false };
    }
}

// Показать кнопку админ панели для авторизованных админов
function ensureAdminButtonVisible() {
    // Проверяем флаг предотвращения повторных вызовов
    if (isAdminPanelOpening) {
        console.log('⏳ Админ панель уже инициализируется, пропускаем повторный вызов кнопки');
        return;
    }

    // Проверяем, активен ли режим просмотра от лица пользователя
    const isUserViewMode = sessionStorage.getItem('isUserViewMode') === 'true';
    if (isUserViewMode) {
        console.log('👁️‍🗨️ Активен режим просмотра от лица пользователя. Кнопка админ-панели скрыта.');
        // Показываем кнопку для выхода из этого режима
        if (typeof showExitUserViewButton === 'function') {
            showExitUserViewButton();
        }
        return; // Прерываем выполнение, чтобы не показывать админ-кнопку
    }

    console.log('🔍 Проверяем необходимость показа кнопки админ панели');

    if (typeof getCurrentUser === 'function') {
        const currentUser = getCurrentUser();
        // Показываем пульсирующую кнопку только для авторизованных пользователей
        if (currentUser) {
            console.log('✅ Показываем пульсирующую кнопку админ панели для пользователя:', currentUser.email);

            // Проверяем что админ панель не создается уже
            const existingPanel = document.getElementById('admin-panel');
            const existingButton = document.getElementById('pulsing-admin-button');
            const mainAdminButton = document.getElementById('admin-panel-button');

            if (!existingButton && !existingPanel) {
                // Если пульсирующей кнопки нет и панель закрыта, создаем пульсирующую кнопку
                console.log('🆕 Создаем пульсирующую кнопку (панель закрыта)');
                showClassicPulsingAdminButton();
            } else if (existingButton) {
                // Если есть пульсирующая кнопка, отключаем основную
                if (mainAdminButton) {
                    mainAdminButton.style.display = 'none';
                    mainAdminButton.disabled = true;
                    console.log('🔒 Основная кнопка отключена - есть пульсирующая');
                }
            } else {
                // Если есть панель, но нет пульсирующей - включаем основную кнопку
                if (mainAdminButton) {
                    mainAdminButton.style.display = 'inline-flex';
                    mainAdminButton.disabled = false;
                    console.log('🔓 Основная кнопка админ панели включена (панель открыта)');
                }
                console.log('🔧 Кнопка админ-панели активна');
            }
        } else {
            console.log('👤 Пользователь не авторизован, кнопка админ панели не показывается');
        }
    } else {
        console.log('⚠️ Функция getCurrentUser не найдена');
    }
}




