/**
 * Обрабатывает токен подтверждения из URL после регистрации.
 * Supabase добавляет токен в URL в виде #access_token=...&type=signup
 */
function handleEmailConfirmation() {
    // Проверяем, есть ли в URL хэш с токеном
    if (window.location.hash.includes('access_token')) {
        console.log('🔍 Обнаружен токен подтверждения в URL.');

        // Supabase автоматически обрабатывает токен из хэша при инициализации,
        // но мы можем добавить дополнительную логику для обратной связи с пользователем.
        
        // Подписываемся на событие входа в систему
        const { data: { subscription } } = window.supabase.auth.onAuthStateChange((event, session) => {
            if (event === 'SIGNED_IN' && session) {
                console.log('✅ Пользователь успешно вошел в систему после подтверждения email.');
                showNotification('✅ Регистрация успешно подтверждена! Добро пожаловать!', 'success');
                
                // Убираем хэш из URL для чистоты
                history.pushState("", document.title, window.location.pathname + window.location.search);
                
                // Отписываемся, чтобы обработчик не срабатывал повторно
                subscription.unsubscribe();
            }
        });
    }
}

