/**
 * Передает права владельца другому пользователю с полной передачей сайта.
 * @param {string} targetUserId - ID пользователя, которому передаются права.
 */
async function transferOwnership(targetUserId) {
    console.log(`👑 Запуск процесса передачи прав владельца пользователю ${targetUserId}`);
    const password = document.getElementById('ownerTransferPassword').value;

    if (password !== OWNER_TRANSFER_PASSWORD) {
        showNotification('❌ Неверный спец-пароль!', 'error');
        return;
    }

    const currentOwner = getCurrentUser();
    if (!currentOwner) {
        showNotification('❌ Ошибка: не удалось определить текущего владельца.', 'error');
        return;
    }

    try {
        // Получаем данные целевого пользователя
        const { data: targetUser, error: targetError } = await supabase
            .from('profiles')
            .select('username, email, role')
            .eq('id', targetUserId)
            .single();

        if (targetError) throw targetError;

        console.log(`🔄 Передача прав от ${currentOwner.email} к ${targetUser.email}`);

        // 1. Передаем роль владельца
        const { error: transferError } = await window.supabase.rpc('transfer_owner_role', {
            p_new_owner_id: targetUserId,
            p_old_owner_id: currentOwner.id
        });

        if (transferError) throw transferError;

        // 2. Обновляем роль старого владельца на admin_senior (сохраняем высокие права)
        const { error: oldRoleError } = await supabase
            .from('profiles')
            .update({ 
                role: 'admin_senior',
                is_owner: false,
                updated_at: new Date().toISOString()
            })
            .eq('id', currentOwner.id);

        if (oldRoleError) throw oldRoleError;

        // 3. Обновляем роль нового владельца
        const { error: newRoleError } = await supabase
            .from('profiles')
            .update({ 
                role: 'owner',
                is_owner: true,
                updated_at: new Date().toISOString()
            })
            .eq('id', targetUserId);

        if (newRoleError) throw newRoleError;

        // 4. Записываем в лог передачи прав
        const { error: logError } = await supabase
            .from('owner_transfer_log')
            .insert({
                old_owner_id: currentOwner.id,
                new_owner_id: targetUserId,
                transfer_date: new Date().toISOString(),
                transfer_reason: 'Владелец передал права добровольно'
            });

        if (logError) {
            console.warn('⚠️ Не удалось записать в лог передачи прав:', logError);
        }

        // 5. Отправляем уведомление
        showNotification(`👑 Права владельца успешно переданы пользователю ${targetUser.username}!`, 'success');
        showNotification('🔄 Вы стали старшим администратором. Страница будет перезагружена...', 'info');

        // 6. Перезагружаем страницу через 3 секунды
        setTimeout(() => {
            window.location.reload();
        }, 3000);

    } catch (error) {
        console.error('❌ Ошибка передачи прав владельца:', error);
        showNotification(`❌ Ошибка: ${error.message}`, 'error');
    }
}

/**
 * Полностью удаляет владельца сайта (опасная операция!)
 * @param {string} targetUserId - ID владельца для удаления
 */
async function removeOwnerCompletely(targetUserId) {
    console.log(`🗑️ Запуск процесса полного удаления владельца ${targetUserId}`);
    
    // Подтверждение через специальный пароль
    const password = prompt('⚠️ Введите спец-пароль для удаления владельца (ОПАСНАЯ ОПЕРАЦИЯ!):');
    
    if (password !== OWNER_TRANSFER_PASSWORD + '_DELETE') {
        showNotification('❌ Неверный спец-пароль для удаления!', 'error');
        return;
    }

    if (!confirm('⚠️ ВНИМАНИЕ! Это полностью удалит владельца сайта со всеми данными! Все залитые моды будут сохранены, но авторство будет изменено на "Система". Операция необратима!')) {
        return;
    }

    try {
        // 1. Получаем данные владельца
        const { data: ownerData, error: fetchError } = await supabase
            .from('profiles')
            .select('username, email, role')
            .eq('id', targetUserId)
            .single();

        if (fetchError) throw fetchError;

        // 2. Переназначаем все моды владельца на системного пользователя
        const { error: modsError } = await supabase
            .from('mods')
            .update({ 
                author_id: '00000000-0000-0000-0000-000000000000', // Системный ID
                author_name: 'Система KEROSMODS',
                updated_at: new Date().toISOString()
            })
            .eq('author_id', targetUserId);

        if (modsError) {
            console.warn('⚠️ Ошибка при переназначении модов:', modsError);
        }

        // 3. Удаляем профиль владельца
        const { error: deleteError } = await supabase
            .from('profiles')
            .delete()
            .eq('id', targetUserId);

        if (deleteError) throw deleteError;

        // 4. Записываем в лог
        const { error: logError } = await supabase
            .from('owner_transfer_log')
            .insert({
                old_owner_id: targetUserId,
                new_owner_id: null,
                transfer_date: new Date().toISOString(),
                transfer_reason: 'Владелец полностью удален'
            });

        if (logError) {
            console.warn('⚠️ Не удалось записать в лог удаления:', logError);
        }

        showNotification(`🗑️ Владелец ${ownerData.username} полностью удален!`, 'success');
        showNotification('🔄 Все моды переназначены на систему. Страница будет перезагружена...', 'info');

        setTimeout(() => {
            window.location.reload();
        }, 3000);

    } catch (error) {
        console.error('❌ Ошибка удаления владельца:', error);
        showNotification(`❌ Ошибка: ${error.message}`, 'error');
    }
}

