/**
 * Безопасная передача модов от одного владельца другому перед удалением
 * @param {string} fromOwnerId - ID владельца, у которого забираем моды
 * @param {string} toOwnerId - ID владельца, которому передаем моды
 * @param {string} fromOwnerName - Имя владельца, у которого забираем моды
 * @param {string} toOwnerName - Имя владельца, которому передаем моды
 */
async function safeModTransfer(fromOwnerId, toOwnerId, fromOwnerName, toOwnerName) {
    console.log(`🔄 Начало безопасной передачи модов от ${fromOwnerName} к ${toOwnerName}`);
    
    try {
        // Шаг 1: Получаем все моды от удаляемого владельца
        console.log('📋 Шаг 1: Получение списка модов...');
        const { data: mods, error: modsError } = await supabase
            .from('mods')
            .select('*')
            .eq('author_id', fromOwnerId);

        if (modsError) throw modsError;

        console.log(`📦 Найдено модов для передачи: ${mods.length}`);
        showNotification(`📦 Найдено модов для передачи: ${mods.length}`, 'info');

        if (mods.length === 0) {
            showNotification('ℹ️ У владельца нет модов для передачи', 'info');
            return 0;
        }

        // Шаг 2: Передаем каждый мод новому владельцу
        console.log('🔄 Шаг 2: Передача авторства модов...');
        let successCount = 0;
        
        for (const mod of mods) {
            const { error: updateError } = await supabase
                .from('mods')
                .update({
                    author_id: toOwnerId,
                    author_name: toOwnerName,
                    updated_at: new Date().toISOString()
                })
                .eq('id', mod.id);

            if (updateError) {
                console.warn(`⚠️ Ошибка при передаче мода ${mod.name}:`, updateError);
                showNotification(`⚠️ Ошибка при передаче мода ${mod.name}`, 'warning');
            } else {
                console.log(`✅ Мод "${mod.name}" передан владельцу ${toOwnerName}`);
                successCount++;
            }
        }

        // Шаг 3: Записываем в лог передачи
        console.log('📝 Шаг 3: Запись в лог передачи...');
        const { error: logError } = await supabase
            .from('mod_transfer_log')
            .insert({
                from_owner_id: fromOwnerId,
                to_owner_id: toOwnerId,
                transfer_date: new Date().toISOString(),
                mods_count: mods.length,
                success_count: successCount,
                transfer_reason: 'Безопасная передача перед удалением владельца'
            });

        if (logError) {
            console.warn('⚠️ Не удалось записать в лог передачи:', logError);
        }

        console.log(`✅ Передача модов завершена: ${successCount}/${mods.length} успешно`);
        showNotification(`✅ Передано модов: ${successCount}/${mods.length}`, 'success');
        
        return successCount;

    } catch (error) {
        console.error('❌ Ошибка передачи модов:', error);
        showNotification(`❌ Ошибка передачи модов: ${error.message}`, 'error');
        return 0;
    }
}

/**
 * Безопасное удаление владельца с передачей модов другому владельцу
 * @param {string} ownerId - ID владельца для удаления
 * @param {string} newOwnerId - ID владельца, которому передаем моды
 * @param {string} ownerName - Имя удаляемого владельца
 * @param {string} newOwnerName - Имя нового владельца
 */
async function safeOwnerRemoval(ownerId, newOwnerId, ownerName, newOwnerName) {
    console.log(`🗑️ Начало безопасного удаления владельца ${ownerName}`);
    
    if (!confirm(`⚠️ Вы уверены, что хотите удалить владельца ${ownerName} и передать его моды ${newOwnerName}?`)) {
        return;
    }

    try {
        // Шаг 1: Безопасная передача модов
        const transferredCount = await safeModTransfer(ownerId, newOwnerId, ownerName, newOwnerName);
        
        if (transferredCount === 0) {
            showNotification('❌ Не удалось передать моды, отмена удаления', 'error');
            return;
        }

        // Шаг 2: Понижение роли владельца до admin_senior
        console.log('🔄 Шаг 2: Понижение роли владельца...');
        const { error: roleError } = await supabase
            .from('profiles')
            .update({
                role: 'admin_senior',
                is_owner: false,
                updated_at: new Date().toISOString()
            })
            .eq('id', ownerId);

        if (roleError) throw roleError;

        // Шаг 3: Обновляем статистику
        console.log('🔄 Шаг 3: Обновление статистики...');
        await updateUsersStatistics();

        // Шаг 4: Финальное подтверждение
        showNotification(`✅ Владелец ${ownerName} успешно удален!`, 'success');
        showNotification(`📦 Передано модов: ${transferredCount}`, 'success');
        showNotification(`👑 Новый владелец: ${newOwnerName}`, 'success');
        showNotification(`🔄 Бывший владелец стал старшим администратором`, 'info');

        console.log(`✅ Безопасное удаление владельца ${ownerName} завершено`);

        // Обновляем интерфейс
        setTimeout(() => {
            showAllUsersList();
        }, 2000);

    } catch (error) {
        console.error('❌ Ошибка безопасного удаления владельца:', error);
        showNotification(`❌ Ошибка удаления владельца: ${error.message}`, 'error');
    }
}

