                <button onclick="executeSafeTransfer('${fromOwnerId}', '${toOwnerId}', '${fromOwnerName}', '${toOwnerName}')" style="background: linear-gradient(45deg, #00ff41, #00cc33); color: black; padding: 15px 30px; border: 2px solid #00ff41; border-radius: 10px; cursor: pointer; font-weight: bold; font-family: 'Courier New', monospace;">🔄 Выполнить передачу</button>
