/**
 * Выполняет безопасную передачу модов
 */
function executeSafeTransfer(fromOwnerId, toOwnerId, fromOwnerName, toOwnerName) {
    document.querySelector('.safe-transfer-modal')?.remove();
    safeOwnerRemoval(fromOwnerId, toOwnerId, fromOwnerName, toOwnerName);
}

