/**
 * Загружает приватные моды для VIP пользователей.
 */
async function loadVipMods() {
    console.log('💎 Загрузка приватных модов для VIP пользователей');

    try {
        // Определяем игровую версию
        const gameVersion = currentGameVersion || 'fs25';

        // Загружаем приватные моды из базы данных
        const { data: mods, error } = await window.supabase
            .from('mods')
            .select('*')
            .eq('game_version', gameVersion)
            .eq('is_private', true)
            .eq('is_approved', true)
            .order('created_at', { ascending: false });

        if (error) {
            console.error('❌ Ошибка загрузки приватных модов:', error);
            throw error;
        }

        // console.log('✅ Загружено приватных модов:', mods?.length || 0);

        // Отображаем моды в контейнере
        const modsContainer = document.getElementById('modsContainer');
        if (!modsContainer) {
            // console.error('❌ Контейнер модов не найден');
            return;
        }
        // ИСПРАВЛЕНИЕ: Добавляем горизонтальный отступ к контейнеру модов
        modsContainer.style.padding = '0 3cm';
        modsContainer.style.boxSizing = 'border-box'; // Убедимся, что padding учитывается в общей ширине


        if (!mods || mods.length === 0) {
            modsContainer.innerHTML = `
                <div style="text-align: center; padding: 3rem; color: #f44336;">
                    <h3>💎 Приватные моды</h3>
                    <p>VIP модов для игры ${gameVersion} пока нет.</p>
                    <p>Приватные моды доступны только для VIP пользователей!</p>
                </div>
            `;
            return;
        }

        // Создаем HTML для приватных модов
        let modsHtml = '<h3 style="color: #ffd700; text-align: center; margin-bottom: 2rem;">💎 Приватные моды (VIP)</h3>';
        
        // Получаем роль пользователя для проверки прав
        const profile = await getUserRole();
        const canEdit = profile && ['owner', 'admin_senior', 'admin', 'moderator_senior', 'moderator'].includes(profile.role);
        
        for (const mod of mods) {
            modsHtml += `
                <div class="mod-card vip-mod" style="background: linear-gradient(135deg, #2a2a00, #4a4a00); border: 1px solid rgba(255, 215, 0, 0.3); border-radius: 15px; overflow: hidden; margin: 1rem; padding: 1rem; box-shadow: 0 0 15px rgba(255, 215, 0, 0.2);">
                    <div style="display: flex; align-items: center; gap: 1rem; margin-bottom: 1rem;">
                        <span style="font-size: 2rem;">💎</span>
                        <div>
                            <h3 style="color: #ffd700; margin: 0 0 0.5rem 0; text-shadow: 0 0 5px #ffd700;">${mod.name}</h3>
                            <div style="color: #ff9800; font-size: 0.9rem; font-weight: bold;">VIP МОД</div>
                        </div>
                    </div>
                    <p style="color: #ffd700; margin: 0 0 1rem 0; opacity: 0.9;">${mod.description || 'Описание отсутствует'}</p>
                    <div style="display: flex; gap: 1rem; margin-bottom: 1rem; font-size: 0.9rem; color: #ff9800;">
                        <span>📂 ${getRussianCategoryName(mod.category) || 'Без категории'}</span>
                        <span>🎮 ${getRussianGameName(mod.game_version)}</span>
                        <span>📏 ${mod.file_size ? Math.round(mod.file_size / 1024 / 1024) + 'MB' : 'Размер неизвестен'}</span>
                    </div>
                    <div style="display: flex; gap: 0.5rem;">
                        <button onclick="handleDownloadClick('${mod.id}')" style="background: linear-gradient(135deg, #ffd700, #ff8c00); color: #000; border: none; padding: 10px 20px; border-radius: 5px; cursor: pointer; font-weight: bold;">⬇️ Скачать VIP мод</button>
                        <button onclick="showModDetails('${mod.id}')" style="background: linear-gradient(135deg, #ff9800, #f57c00); color: white; border: none; padding: 10px 20px; border-radius: 5px; cursor: pointer; font-weight: bold;">👁️ Подробнее</button>
                        ${canEdit ? `<button onclick="editMod('${mod.id}')" style="background: linear-gradient(135deg, #1a237e, #283593); color: white; border: none; padding: 10px 20px; border-radius: 5px; cursor: pointer; font-weight: bold;">✏️ Редактировать</button>` : ''}
                    </div>
                </div>
            `;
        }

        modsContainer.innerHTML = modsHtml;
        console.log('✅ Приватные моды отображены на странице');

    } catch (error) {
        console.error('❌ Критическая ошибка загрузки приватных модов:', error);
        const modsContainer = document.getElementById('modsContainer');
        if (modsContainer) {
            modsContainer.innerHTML = `
                <div style="text-align: center; padding: 3rem; color: #f44336;">
                    <h3>❌ Ошибка загрузки приватных модов</h3>
                    <p>Произошла ошибка при загрузке приватных модов: ${error.message}</p>
                    <p>VIP моды доступны только для пользователей с активным VIP статусом.</p>
                </div>
            `;
        }
    }
}

/**
 * Простой клиентский роутер для обработки URL.
 */
async function handleRouting() {
    const path = window.location.pathname;
    console.log(`🔄 Обработка маршрута: ${path}`);

    // Паттерн для /admin/users/UUID
    const userRouteMatch = path.match(/^\/admin\/users\/([0-9a-fA-F-]+)$/);

    if (userRouteMatch) {
        const userId = userRouteMatch[1];
        console.log(`- Найден маршрут пользователя: ${userId}`);
        await showUserFromRoute(userId);
    }
}

/**
 * Показывает детали пользователя по ID из URL.
 * @param {string} userId - ID пользователя из URL.
 */
async function showUserFromRoute(userId) {
    try {
        // 1. Проверяем, есть ли права администратора
        const profile = await getUserRole();
        const isAdmin = profile && (profile.isOwner || ['owner', 'admin_senior', 'admin', 'moderator_senior', 'moderator'].includes(profile.role));

        if (!isAdmin) {
            showNotification('❌ У вас нет прав для просмотра этой страницы.', 'error');
            return;
        }

        // 2. Открываем админ-панель
        showAdminPanelReliable();

        // 3. Загружаем данные конкретного пользователя
        showNotification('Загрузка данных пользователя...', 'info');
        const { data: user, error } = await window.supabase
            .from('profiles')
            .select('*')
            .eq('id', userId)
            .single();

        if (error || !user) {
            throw new Error(`Пользователь с ID ${userId} не найден.`);
        }

        // 4. Показываем модальное окно с деталями
        // Используем существующую функцию, передавая необходимые данные
        showUserDetailsModal(user.id, user.ip_address || 'Неизвестен', user.device_fingerprint || 'Неизвестен');

    } catch (error) {
        console.error('❌ Ошибка обработки маршрута пользователя:', error);
        showNotification(`❌ Ошибка: ${error.message}`, 'error');
    }
}

// Восстановление состояния пользователя
function restoreUserState() {
    try {
        // Если мы в режиме имперсонализации, прерываем восстановление обычного состояния
        if (sessionStorage.getItem('impersonatedUser')) {
            console.log('👁️‍🗨️ Режим имперсонализации: стандартное восстановление состояния пропущено.');
            // Логика теперь обрабатывается в authManager.checkExistingSession
            return;
        }

        // Проверяем, активен ли режим просмотра от лица пользователя
        const isUserViewMode = sessionStorage.getItem('isUserViewMode') === 'true';
        if (isUserViewMode) {
            console.log('👁️‍🗨️ Режим просмотра: стандартное восстановление состояния пропущено.');
            // Показываем кнопку выхода из режима просмотра
            showExitUserViewButton();
            return; // Прерываем выполнение, чтобы не показывать админ-элементы
        }

        // ✅ ИСПРАВЛЕНИЕ: Добавляем вызов обработчика подтверждения email
        handleEmailConfirmation();

        // Восстанавливаем текущую страницу для пагинации
        const savedPage = loadFromSessionStorage('currentPage');
        if (savedPage) {
            currentPage = savedPage;
        }

        console.log('🔄 Состояние пользователя восстановлено');
    } catch (error) {
        console.warn('⚠️ Ошибка восстановления состояния:', error);
    }
}

