// Обработка формы входа
async function handleLogin(event) {
    event.preventDefault();

    const login = document.getElementById('loginInput').value;
    const password = document.getElementById('loginPassword').value;

    if (!login || !password) {
        alert('Пожалуйста, заполните все поля');
        return;
    }

    try {
        const result = await loginUser(login, password);

        if (result.success) {
            hideLoginModal();
            // Очищаем форму
            document.getElementById('loginForm').reset();
            // console.log('✅ Вход выполнен успешно');

            // Обновляем UI для авторизованного пользователя
            const guestInfo = document.querySelector('#guest-info');
            const userInfo = document.querySelector('#user-info');
            const logoutBtn = document.querySelector('#logout-button');

            if (guestInfo) guestInfo.style.display = 'none';
            if (userInfo) userInfo.style.display = 'block';
            if (logoutBtn) logoutBtn.style.display = 'block';

            // Обновляем отображаемое имя пользователя со статусом
            const usernameDisplay = document.querySelector('#user-identifier');
            if (usernameDisplay) {
                const currentUser = typeof getCurrentUser === 'function' ? getCurrentUser() : null;
                const username = currentUser?.user_metadata?.username || currentUser?.email || 'Пользователь';
                
                // Устанавливаем время начала сессии если еще не установлено
                if (!sessionStorage.getItem('sessionStartTime')) {
                    sessionStorage.setItem('sessionStartTime', new Date().toISOString());
                }
                
                // Проверяем и защищаем от автоматической блокировки
                if (currentUser && currentUser.id) {
                    setTimeout(async () => {
                        await checkAndProtectFromAutoBan(currentUser.id);
                    }, 3000); // Даем время на полную инициализацию
                }
                
                // Получаем профиль пользователя для статуса
                updateUserDisplayWithStatus(username, currentUser);
            }
        } else {
            const error = result.error;
            let errorMessage = '';
            
            // Безопасно получаем сообщение об ошибке
            if (typeof error === 'string') {
                errorMessage = error;
            } else if (error && error.message) {
                errorMessage = error.message;
            } else {
                errorMessage = 'Неизвестная ошибка';
            }
            
            let translatedMessage = errorMessage;

            // Переводим распространенные ошибки на русский
            if (errorMessage.includes('Invalid login credentials')) {
                translatedMessage = 'Неверный логин/email или пароль';
            } else if (errorMessage.includes('Email not confirmed')) {
                translatedMessage = 'Email не подтвержден';
            } else if (errorMessage.includes('Too many requests')) {
                translatedMessage = 'Слишком много попыток входа. Попробуйте позже';
            } else if (errorMessage.includes('User not found')) {
                translatedMessage = 'Пользователь не найден';
            } else if (errorMessage.includes('Пользователь с таким email не зарегистрирован')) {
                translatedMessage = 'Пользователь с таким email не зарегистрирован';
            } else if (errorMessage.includes('Cannot read properties of undefined (reading \'supabaseKey\')')) {
                translatedMessage = 'Пользователь не зарегистрирован';
            }

            alert('Ошибка входа: ' + translatedMessage);

            // Показываем кнопки входа/регистрации если была ошибка входа
            const guestInfo = document.querySelector('#guest-info');
            const userInfo = document.querySelector('#user-info');
            if (guestInfo) guestInfo.style.display = 'block';
            if (userInfo) userInfo.style.display = 'none';
        }
    } catch (error) {
        // console.error('Ошибка входа:', error);
        let errorMessage = '';
        
        // Безопасно получаем сообщение об ошибке
        if (typeof error === 'string') {
            errorMessage = error;
        } else if (error && error.message) {
            errorMessage = error.message;
        } else {
            errorMessage = 'Неизвестная ошибка';
        }

        // Переводим распространенные ошибки на русский
        if (errorMessage.includes('Invalid login credentials')) {
            errorMessage = 'Неверный логин/email или пароль';
        } else if (errorMessage.includes('Email not confirmed')) {
            errorMessage = 'Email не подтвержден';
        } else if (errorMessage.includes('Too many requests')) {
            errorMessage = 'Слишком много попыток входа. Попробуйте позже';
        } else if (errorMessage.includes('User not found')) {
            errorMessage = 'Пользователь не найден';
        } else if (errorMessage.includes('Неверные данные для входа')) {
            errorMessage = 'Неверный логин/email или пароль';
        } else if (errorMessage.includes('Cannot read properties of undefined (reading \'supabaseKey\')')) {
            errorMessage = 'Пользователь не зарегистрирован';
        }

        alert('Ошибка входа: ' + errorMessage);
    }
}

