// Вся логика регистрации теперь обрабатывается напрямую через authManager.registerUser
// в модальном окне регистрации (файл ui-modals.js или аналогичный).
// Это устраняет дублирование и гарантирует вызов правильной, защищенной функции.

/**
 * Сбрасывает индикатор сложности пароля и сообщение о несовпадении.
 */
function resetPasswordStrengthIndicator() {
    const strengthFill = document.getElementById('strengthFill');
    const strengthText = document.getElementById('strengthText');
    const passwordMatchError = document.getElementById('passwordMatch');

    if (strengthFill && strengthText) {
        // Сбрасываем индикатор в исходное состояние
        strengthFill.style.width = '0%';
        strengthFill.style.backgroundColor = '#ddd';
        strengthText.textContent = 'Слабый пароль';
        strengthText.style.color = '#666';
    }
    // Также скрываем ошибку о несовпадении паролей
    if (passwordMatchError) {
        passwordMatchError.style.display = 'none';
    }
}

// Добавляем обработчики для проверки совпадения паролей в реальном времени
document.addEventListener('DOMContentLoaded', () => {
    const registerPassword = document.getElementById('registerPassword');
    const registerPasswordConfirm = document.getElementById('registerPasswordConfirm');
    const passwordMatchError = document.getElementById('passwordMatch');
    const strengthFill = document.getElementById('strengthFill');
    const strengthText = document.getElementById('strengthText');

    function checkPasswords() {
        if (!passwordMatchError) return;

        if (registerPassword.value && registerPasswordConfirm.value) {
            if (registerPassword.value !== registerPasswordConfirm.value) {
                passwordMatchError.style.display = 'block';
            } else {
                passwordMatchError.style.display = 'none';
            }
        } else {
            passwordMatchError.style.display = 'none';
        }
    }

    function updatePasswordStrength() {
        if (!strengthFill || !strengthText) return;

        const password = registerPassword.value;
        let score = 0;
        if (password.length >= 8) score++;
        if (/[A-Z]/.test(password)) score++;
        if (/[a-z]/.test(password)) score++;
        if (/[0-9]/.test(password)) score++;
        if (/[^A-Za-z0-9]/.test(password)) score++;

        const strength = {
            0: { text: 'Очень слабый', color: '#e74c3c', width: '20%' },
            1: { text: 'Слабый', color: '#e74c3c', width: '20%' },
            2: { text: 'Слабый', color: '#f39c12', width: '40%' },
            3: { text: 'Средний', color: '#f1c40f', width: '60%' },
            4: { text: 'Надежный', color: '#2ecc71', width: '80%' },
            5: { text: 'Очень надежный', color: '#27ae60', width: '100%' }
        };

        const currentStrength = strength[score];
        strengthFill.style.width = currentStrength.width;
        strengthFill.style.backgroundColor = currentStrength.color;
        strengthText.textContent = currentStrength.text;
        strengthText.style.color = currentStrength.color;
    }

    if (registerPassword) registerPassword.addEventListener('input', updatePasswordStrength);
    if (registerPassword) registerPassword.addEventListener('input', checkPasswords);
    if (registerPasswordConfirm) registerPasswordConfirm.addEventListener('input', checkPasswords);
    
    // Инициализация при загрузке страницы
    // console.log('🚀 Инициализация KEROS_MODS при загрузке страницы');
    
    // Загружаем последнюю выбранную игру
    setTimeout(() => {
        loadLastSelectedGame();
    }, 500);
});

// Выход из системы
async function handleLogout() {
    if (confirm('Вы уверены, что хотите выйти?')) {
        // console.log('🚪 Пользователь подтвердил выход. Начинаем процесс...');
        try {
            // Очищаем сохраненную секцию админ-панели при выходе
            localStorage.removeItem('adminLastActiveSection');
            // console.log('🗑️ Сохраненная секция админ-панели очищена при выходе');
            
            // Очищаем время сессии
            sessionStorage.removeItem('sessionStartTime');
            
            // Очищаем таймер VIP
            if (window.vipTimeUpdateInterval) {
                clearInterval(window.vipTimeUpdateInterval);
                window.vipTimeUpdateInterval = null;
                // console.log('🛑 Таймер обновления VIP остановлен');
            }
            
            // Выходим из системы
            if (typeof logoutUser === 'function') {
                await logoutUser();
                // console.log('✅ Функция logoutUser() успешно выполнена.');
            } else {
                // console.warn('⚠️ Функция logoutUser() не найдена, выход может быть неполным.');
            }

            // Явно скрываем все административные панели и кнопки после выхода
            hideAdminPanel();
            hideMiniAdminPanel();
            hideCompactAdminButton();
            // console.log('✅ Все административные панели и кнопки скрыты.');

            showNotification('Вы успешно вышли из системы.', 'success');

        } catch (error) {
            // console.error('Ошибка выхода:', error);
            alert('Ошибка выхода: ' + error.message);
        }
    }
}

