// Прямая загрузка модов из базы данных
async function loadModsDirectly(categoryId, gameVersion) {
    // console.log('🎮 Прямая загрузка модов для категории:', categoryId, 'игра:', gameVersion);
    
    // Проверяем, что gameVersion не является vip_mods при загрузке обычных модов
    if (gameVersion === 'vip_mods' && !['Все', 'fs25', 'fs22', 'fs19'].includes(categoryId)) {
        // console.warn('⚠️ [DEBUG] Подозрительный вызов: gameVersion=vip_mods, categoryId=', categoryId);
    }
    
    if (gameVersion !== 'vip_mods' && ['fs25', 'fs22', 'fs19'].includes(categoryId)) {
        // console.warn('⚠️ [DEBUG] Подозрительный вызов: gameVersion=', gameVersion, ', categoryId=', categoryId);
    }
    
    try {
        // Строим запрос к базе данных
        let query = supabase
            .from('mods')
            .select('*')
            .eq('is_approved', true);

        // Новая логика для VIP раздела
        if (gameVersion === 'vip_mods') {
            // Для VIP разделов categoryId может быть:
            // - "Все" - показать все VIP моды всех версий и категорий
            // - "fs25", "fs22", "fs19" - показать VIP моды для конкретной версии
            // - "objects", "maps", "tractors" и т.д. - показать VIP моды для конкретной категории
            if (categoryId === 'Все') {
                // Показываем все VIP моды всех версий
                query = query.eq('is_private', true);
                // ✅ УБРАНО: showVipCategories('main'); - теперь управляется в switchGameVersion
            } else if (['fs25', 'fs22', 'fs19'].includes(categoryId)) {
                // Показываем VIP моды для конкретной версии игры
                query = query.eq('is_private', true).eq('game_version', categoryId);
                // ✅ УБРАНО: showVipCategories(categoryId); - теперь управляется в switchGameVersion
            } else {
                // Показываем VIP моды для конкретной категории (все версии)
                query = query.eq('is_private', true).eq('category', categoryId);
                // Остаемся в текущем VIP контейнере
            }
        } else {
            // Старая логика для обычных игр - исключаем VIP моды
            query = query.eq('game_version', gameVersion).eq('is_private', false);
            if (categoryId !== 'Все') {
                // Сопоставление категорий для совместимости
                let searchCategory = categoryId;
                if (categoryId === 'russian_mods') {
                    searchCategory = 'russian'; // Ищем в базе то, что реально сохранено
                }
                query = query.eq('category', searchCategory);
            }
        }

        // Добавляем сортировку и лимит
        query = query
            .order('created_at', { ascending: false })
            .limit(20);

        // 🕵️‍♂️ ДИАГНОСТИКА: Логируем параметры запроса
        // Проверяем VIP статус пользователя для правильного отображения VIP модов
        let currentUserVipStatus = false;
        
        // Получаем актуальный VIP статус из базы
        if (window.authManager?.currentUser) {
            try {
                const { data: profile } = await window.supabase
                    .from('profiles')
                    .select('is_vip, role, vip_expires_at')
                    .eq('id', window.authManager.currentUser.id)
                    .single();

                if (profile) {
                    // console.log('🔍 [VIP ПРОВЕРКА] Профиль пользователя:', profile);
                    // console.log('🔍 [VIP ПРОВЕРКА] is_vip:', profile.is_vip, 'role:', profile.role);

                    // 🔧 ИСПРАВЛЕНИЕ: Проверяем и is_vip, и роль для надёжности
                    const vipRoles = ['vip', 'moderator', 'moderator_senior', 'admin', 'admin_senior', 'owner'];
                    const hasRoleAccess = vipRoles.includes(profile.role);
                    const hasVipFlag = profile.is_vip === true;
                    const isNotExpired = !profile.vip_expires_at || new Date(profile.vip_expires_at) > new Date();
                    
                    currentUserVipStatus = (hasVipFlag || hasRoleAccess) && isNotExpired;
                    
                    console.log('🔍 [VIP ПРОВЕРКА] hasRoleAccess:', hasRoleAccess, 'hasVipFlag:', hasVipFlag, 'isNotExpired:', isNotExpired);
                    console.log('🔍 [VIP ПРОВЕРКА] Итоговый доступ:', currentUserVipStatus);
                }
            } catch (error) {
                console.warn('⚠️ Ошибка получения VIP статуса:', error);
                currentUserVipStatus = window.authManager?.currentUser?.is_vip || false;
            }
        }
        
        // console.log('🕵️‍♂️ ДИАГНОСТИКА: Логируем параметры запроса к Supabase:', {
        //     is_approved: true,
        //     is_private: gameVersion === 'vip_mods' ? true : false,
        //     game_version: gameVersion === 'vip_mods' ? categoryId : gameVersion,
        //     category: (gameVersion !== 'vip_mods' && categoryId !== 'Все') ? categoryId : 'не фильтруем (VIP)',
        //     mode: gameVersion === 'vip_mods' ? 'VIP' : 'Обычный'
        // });

        const { data: mods, error } = await query;

        if (error) {
            console.error('❌ Ошибка загрузки модов из базы данных:', error);
            throw error;
        }
        // console.log('✅ Ответ от Supabase получен. Количество модов:', mods?.length || 0);

        // console.log('✅ Загружено модов:', mods?.length || 0);

        // Отображаем моды
        const modsContainer = document.getElementById('modsContainer');
        if (!modsContainer) {
            // console.error('❌ Контейнер модов не найден');
            return;
        }
        // ИСПРАВЛЕНИЕ: Добавляем горизонтальный отступ к контейнеру модов
        modsContainer.style.padding = '0 3cm';
        modsContainer.style.boxSizing = 'border-box'; // Убедимся, что padding учитывается в общей ширине


        if (!mods || mods.length === 0) {
            const russianCategoryName = getRussianCategoryName(categoryId);
            const russianGameName = getRussianGameName(gameVersion);
            modsContainer.innerHTML = `
                <div style="text-align: center; padding: 3rem; color: #f44336;">
                    <h3>📦 Моды не найдены</h3>
                    <p>Для игры "${russianCategoryName}" в категории ${russianGameName}, модов пока нет.</p>
                    <p>Загрузите моды через админ панель или добавьте их вручную в базу данных.</p>
                </div>
            `;
            return;
        }

        // Создаем HTML для модов
        let modsHtml = '';
        // ИСПРАВЛЕНИЕ: Заменяем forEach на асинхронный цикл for...of для корректной работы с await
        for (const mod of mods) {
            // Корректно дожидаемся результата проверки прав
            // ✅ ИСПРАВЛЕНИЕ: Кнопка "Редактировать" убрана из общего списка.
            // Она будет доступна только в модальном окне "Подробнее".
            const editButtonHtml = '';
            
            // Загружаем статистику для каждого мода
            let avgRating = 0;
            let commentCount = 0;
            
            try {
                // Получаем рейтинг мода
                const { data: ratings } = await window.supabase
                    .from('mod_ratings')
                    .select('rating')
                    .eq('mod_id', mod.id);
                
                if (ratings && ratings.length > 0) {
                    avgRating = ratings.reduce((sum, r) => sum + r.rating, 0) / ratings.length;
                }
                
                // Получаем количество комментариев
                const { count } = await window.supabase
                    .from('mod_comments')
                    .select('*', { count: 'exact', head: true })
                    .eq('mod_id', mod.id)
                    .eq('is_deleted', false);
                
                commentCount = count || 0;
            } catch (error) {
                console.warn('⚠️ Не удалось загрузить статистику для мода:', mod.id, error);
            }
            
            // Получаем первое изображение мода для превью
            const cacheBuster = Date.now(); // Для обновления кэша
            let mainImageUrl = 'data:image/svg+xml;base64,'; // Заглушка
            if (mod.images && Array.isArray(mod.images) && mod.images.length > 0 && mod.images[0]) {
                // Проверяем, является ли первый элемент объектом с URL или просто строкой
                const firstImg = mod.images[0];
                if (typeof firstImg === 'object' && firstImg.url) {
                    mainImageUrl = firstImg.url + (firstImg.url.includes('?') ? '&' : '?') + 't=' + cacheBuster;
                } else if (typeof firstImg === 'string') {
                    if (firstImg.startsWith('data:image')) {
                        mainImageUrl = firstImg; // Base64 без cache buster
                    } else if (firstImg.startsWith('http')) {
                        mainImageUrl = firstImg + (firstImg.includes('?') ? '&' : '?') + 't=' + cacheBuster;
                    } else {
                        mainImageUrl = `https://gtixajbcfxwqrtsdxnif.supabase.co/storage/v1/object/public/site-assets/${firstImg}?t=${cacheBuster}`;
                    }
                }
            }

        // Проверяем VIP стат��с мода и доступ пользователя
        // 🔧 ИС��РАВЛЕНИЕ: Про��еряем и is_private, и category
        const isVipMod = mod.is_private === true || mod.category === 'vip_mods';
        const hasVipAccess = currentUserVipStatus || false;
        const canAccessVipMod = isVipMod && hasVipAccess;

        console.log(`🔍 [КАРТОЧКА] Мод "${mod.name}":`, {
            isVipMod,
            is_private: mod.is_private,
            category: mod.category,
            hasVipAccess,
            currentUserVipStatus
        });

        const vipBadge = isVipMod && hasVipAccess ? '<span style="background: linear-gradient(45deg, #ffd700, #ffed4e); color: #000; padding: 4px 8px; border-radius: 12px; font-size: 0.8rem; font-weight: bold; margin-left: 8px;">💎 VIP</span>' : '';
        const vipOnlyBadge = isVipMod && !hasVipAccess ? '<span style="background: linear-gradient(45deg, #f44336, #e53935); color: white; padding: 4px 8px; border-radius: 12px; font-size: 0.8rem; font-weight: bold; margin-left: 8px;">🔒 VIP</span>' : '';
        
        // Особый стиль для VIP модов
        const cardStyle = isVipMod 
            ? 'background: linear-gradient(135deg, #1a2f5e, #2a3f6e); border: 2px solid #ffd700; box-shadow: 0 0 20px rgba(255, 215, 0, 0.3);'
            : 'background: linear-gradient(135deg, #112240, #1a2f5e); border: 1px solid rgba(79, 195, 247, 0.2);';

        modsHtml += `
                <div class="mod-card ${isVipMod ? 'vip-mod' : ''}" style="${cardStyle} border-radius: 15px; overflow: hidden; margin: 1rem auto; padding: 1.5rem; width: 100%; max-width: 950px; box-sizing: border-box;">
                    ${isVipMod ? '<div style="text-align: center; margin-bottom: 1rem;"><span style="background: linear-gradient(45deg, #ffd700, #ffed4e); color: #000; padding: 6px 12px; border-radius: 20px; font-size: 0.9rem; font-weight: bold;">💎 VIP МОД</span></div>' : ''}
                    <div class="mod-card-image-container" style="margin-bottom: 1rem; border-radius: 10px; overflow: hidden; background: #0a192f;">
                    <img data-src="${mainImageUrl}" src="data:image/svg+xml;base64," alt="Превью мода ${mod.name}" loading="lazy" style="width: 100%; height: auto; display: block; aspect-ratio: 16 / 9; object-fit: cover;" onerror="this.src='data:image/svg+xml;base64,';">
                    </div>
                <h3 style="color: ${isVipMod ? '#ffd700' : '#4fc3f7'}; margin: 0 0 1rem 0;">${sanitizeHTML(mod.name)}${vipBadge}${vipOnlyBadge}</h3>
                <p style="color: #8892b0; margin: 0 0 1rem 0;">${sanitizeHTML(mod.description) || 'Описание отсутствует'}</p>
                    <div style="display: flex; gap: 1rem; margin-bottom: 1rem; font-size: 0.9rem; color: #8892b0;">
                        <span>📂 ${getRussianCategoryName(mod.category) || 'Без категории'}</span>
                        <span>🎮 ${getRussianGameName(mod.game_version)}</span>
                        <span>📏 ${mod.file_size ? (mod.file_size / 1024 / 1024).toFixed(2) + 'MB' : 'Размер неизвестен'}</span>
                    </div>
                    <div style="display: flex; gap: 0.5rem;">
                        <button onclick="handleDownloadClick('${mod.id}')" style="background: ${isVipMod ? (hasVipAccess ? 'linear-gradient(45deg, #ffd700, #ffed4e)' : 'linear-gradient(45deg, #9e9e9e, #757575)') : 'linear-gradient(135deg, #1a237e, #283593)'}; color: ${isVipMod ? (hasVipAccess ? '#000' : '#fff') : 'white'}; border: none; padding: 10px 20px; border-radius: 5px; cursor: pointer; font-weight: bold; ${isVipMod && !hasVipAccess ? 'opacity: 0.6; cursor: not-allowed;' : ''}">${isVipMod && !hasVipAccess ? '🔒 VIP' : '⬇️ Скачать'}</button>
                        <button onclick="window.showModDetails('${mod.id}')" style="background: #2196F3; color: white; border: none; padding: 10px 20px; border-radius: 5px; cursor: pointer;">👁️ Подробнее</button>
                        ${editButtonHtml}
                     </div>
                     
                     <!-- Счетчики статистики -->
                     <div style="display: flex; justify-content: space-between; gap: 8px; margin-top: 10px; font-size: 12px;">
                         <div style="background: ${isVipMod ? 'rgba(255,215,0,0.2)' : 'rgba(33,150,243,0.1)'}; border: 1px solid ${isVipMod ? '#FFD700' : '#2196F3'}; border-radius: 12px; padding: 4px 8px; display: flex; align-items: center; gap: 4px; flex: 1; justify-content: center;">
                             <span style="font-size: 12px;">💬</span>
                             <span style="color: ${isVipMod ? '#FFD700' : '#2196F3'}; font-weight: bold;">${commentCount}</span>
                         </div>
                         
                         <div style="background: ${isVipMod ? 'rgba(255,215,0,0.2)' : 'rgba(26,35,126,0.1)'}; border: 1px solid ${isVipMod ? '#FFD700' : '#1a237e'}; border-radius: 12px; padding: 4px 8px; display: flex; align-items: center; gap: 4px; flex: 1; justify-content: center;">
                             <span style="font-size: 12px;">⬇️</span>
                             <span style="color: ${isVipMod ? '#FFD700' : '#1a237e'}; font-weight: bold;">${mod.download_count || 0}</span>
                         </div>
                         
                         <div style="background: ${isVipMod ? 'rgba(255,215,0,0.2)' : 'rgba(255,193,7,0.1)'}; border: 1px solid ${isVipMod ? '#FFD700' : '#FFC107'}; border-radius: 12px; padding: 4px 8px; display: flex; align-items: center; gap: 4px; flex: 1; justify-content: center;">
                             <span style="font-size: 12px;">⭐</span>
                             <span style="color: ${isVipMod ? '#FFD700' : '#FFC107'}; font-weight: bold;">${avgRating.toFixed(1)}</span>
                         </div>
                     </div>
                </div>
            `;
        }

        modsContainer.innerHTML = modsHtml;
        
        // Отключаем анимации карточек модов после загрузки
        setTimeout(disableModCardAnimations, 50);
        
        // console.log('✅ Моды отображены на странице');
        // console.log('🔍 [DEBUG] Количество модов в HTML:', mods?.length || 0);
        // console.log('🔍 [DEBUG] modsContainer.innerHTML.length:', modsContainer.innerHTML.length);

        // Инициализация ленивой загрузки для изображений модов
        const lazyImages = document.querySelectorAll('img[loading="lazy"]');
        if ('IntersectionObserver' in window) {
            const observer = new IntersectionObserver((entries, observer) => {
                entries.forEach(entry => {
                    if (entry.isIntersecting) {
                        const img = entry.target;
                        img.src = img.dataset.src;
                        img.removeAttribute('data-src');
                        observer.unobserve(img);
                    }
                });
            });
            lazyImages.forEach(img => observer.observe(img));
        }


    } catch (error) {
        console.error('❌ Критическая ошибка загрузки модов:', error);
        const modsContainer = document.getElementById('modsContainer');
        if (modsContainer) {
            modsContainer.innerHTML = `
                <div style="text-align: center; padding: 3rem; color: #f44336;">
                    <h3>❌ Ошибка загрузки модов</h3>
                    <p>Произошла ошибка при загрузке модов: ${error.message}</p>
                    <p>Проверьте подключение к базе данных и попробуйте еще раз.</p>
                </div>
            `;
        }
    }
}

// Загрузка модов по категории
async function loadModsByCategory(categoryId, gameVersion = null) {
    console.log('🎮 Загрузка модов для категории:', categoryId, 'игра:', gameVersion);
    
    // Детальная отладка для VIP разделов
    if (gameVersion === 'vip_mods') {
        console.log('💎 VIP режим:');
        console.log('  - categoryId (версия игры):', categoryId);
        console.log('  - gameVersion:', gameVersion);
    }
    
    // Определяем игровую версию, если она не передана явно
    if (!gameVersion) {
        gameVersion = currentGameVersion || 'fs25';
        console.log('🎮 Используем игровую версию по умолчанию:', gameVersion);
    }

    // ПРОВЕРКА ДОСТУПА К VIP-МОДАМ
    if (gameVersion === 'vip_mods') {
        console.log('💎 Запрошен VIP-раздел. Проверяем доступ...');
        
        // 🔧 ИСПРАВЛЕНИЕ: Получаем актуальный профиль с принудительным обновлением
        let profile = await getUserRole(true);
        let retryCount = 0;
        
        while (!profile && retryCount < 3) {
            console.log(`⏳ Профиль не загружен, ждём... (${retryCount + 1}/3)`);
            await new Promise(resolve => setTimeout(resolve, 500));
            profile = await getUserRole(true);
            retryCount++;
        }
        
        if (!profile) {
            console.warn('⚠️ Не удалось загрузить профиль пользователя');
            return;
        }

        console.log('🔍 Профиль пользователя:', profile);
        console.log('🔍 isVip:', profile.isVip, 'role:', profile.role);

        // 🚨 ПРОВЕРКА ИСТЕЧЕНИЯ VIP СТАТУСА
        if (profile && (profile.isVip || profile.role === 'vip') && profile.vipExpiresAt) {
            const expirationDate = new Date(profile.vipExpiresAt);
            const now = new Date();

            console.log('🔍 Проверка VIP истечения:');
            console.log('📅 Текущая дата:', now.toISOString());
            console.log('⏰ Дата истечения VIP:', profile.vipExpiresAt);
            console.log('🔄 Истекло ли:', expirationDate < now);

            if (expirationDate < now) {
                console.log('🔄 VIP истек! Обновляем базу данных...');

                try {
                    const { error: updateError } = await window.supabase
                        .from('profiles')
                        .update({
                            is_vip: false,
                            vip_expires_at: null,
                            vip_started_at: null,
                            role: 'user'
                        })
                        .eq('id', window.authManager?.currentUser?.id);

                    if (updateError) {
                        console.error('❌ Ошибка обновления VIP:', updateError);
                    } else {
                        console.log('✅ VIP статус обновлен в базе данных');

                        // Обновляем локальный профиль
                        profile.is_vip = false;
                        profile.vip_expires_at = null;
                        profile.vip_started_at = null;
                        profile.role = 'user';

                        // Показываем уведомление
                        showNotification('❌ Ваш VIP статус истек! Статус обновлен в системе.', 'error');

                        // Обновляем UI
                        if (window.authManager.updateUIForLoggedInUser) {
                            window.authManager.updateUIForLoggedInUser();
                        }

                        // Перезагружаем страницу
                        setTimeout(() => {
                            window.location.reload();
                        }, 2000);

                        return;
                    }
                } catch (error) {
                    console.error('❌ Критическая ошибка при обновлении VIP:', error);
                }
            }
        }

        const vipRoles = ['vip', 'moderator', 'moderator_senior', 'admin', 'admin_senior', 'owner'];
        const hasVipAccess = profile && (profile.isVip === true || vipRoles.includes(profile.role) || profile.isOwner === true);

        console.log('🔍 hasVipAccess:', hasVipAccess, 'profile.isVip:', profile.isVip, 'profile.role:', profile.role);

        if (!hasVipAccess) {
            console.warn('❌ Доступ к VIP-модам запрещен для пользователя с ролью:', profile?.role);
            return;
        }
        console.log('✅ Доступ к VIP-модам разрешен.');
    }
 
     // Определяем игровую версию
     if (!gameVersion) {
         gameVersion = currentGameVersion || 'fs25';
         console.log('🎮 Используем игровую версию по умолчанию:', gameVersion);
     }
 
     // Обновляем активные состояния категорий
     updateCategoryStates(categoryId, gameVersion);
 
     // Загружаем моды напрямую из базы данных
     loadModsDirectly(categoryId, gameVersion);

     // Сохраняем последнюю выбранную категорию для текущей игры
     if (typeof saveToLocalStorage === 'function') {
        saveToLocalStorage(`lastSelectedCategory_${gameVersion}`, categoryId);
        console.log(`💾 Категория '${categoryId}' сохранена для игры '${gameVersion}'`);
     }
}

// Переключение версии игры
// УДАЛЕНО: Дублирующая функция switchGameVersion - теперь используется только одна функция ниже (строка 4198)

// Показ категорий для выбранной игры
function showGameCategories(gameVersion) {
    // Скрываем все категории
    const allCategories = document.querySelectorAll('.game-categories');
    allCategories.forEach(categories => {
        categories.classList.remove('active');
    });

    // Показываем категории для выбранной игры
    const targetCategories = document.getElementById(`${gameVersion}Categories`);
    if (targetCategories) {
        targetCategories.classList.add('active');

        // Обновляем активную кнопку категории на "Все моды"
        const allModsBtn = targetCategories.querySelector('.category-btn');
        if (allModsBtn) {
            // Снимаем активное состояние со всех категорий
            const allCategoryBtns = document.querySelectorAll('.category-btn');
            allCategoryBtns.forEach(btn => btn.classList.remove('active'));

            // Делаем активной кнопку "Все моды"
            allModsBtn.classList.add('active');
        }
    } else {
        console.error('📂 Контейнер категорий не найден:', `${gameVersion}Categories`);
    }

    console.log('📂 Показаны категории для:', gameVersion);
}

// Показ VIP категорий для конкретной версии
function showVipCategories(version) {
    // Скрываем все VIP категории
    const allVipCategories = document.querySelectorAll('[id^="vip_"]');
    allVipCategories.forEach(categories => {
        categories.classList.remove('active');
    });

    // Показываем нужный VIP контейнер
    let targetContainer;
    if (version === 'main') {
        targetContainer = document.getElementById('vip_modsCategories');
    } else {
        targetContainer = document.getElementById(`vip_${version}Categories`);
    }

    if (targetContainer) {
        targetContainer.classList.add('active');
        
        // Активируем первую кнопку категорий
        const firstBtn = targetContainer.querySelector('.category-btn');
        if (firstBtn) {
            // Снимаем активное состояние со всех категорий
            const allCategoryBtns = document.querySelectorAll('.category-btn');
            allCategoryBtns.forEach(btn => btn.classList.remove('active'));
            
            // Делаем активной первую кнопку
            firstBtn.classList.add('active');
        }
    } else {
        console.error('💎 VIP контейнер не найден:', version);
    }
}

// Загрузка последней выбранной игры при старте страницы
function loadLastSelectedGame() {
    try {
        const lastGame = (typeof storageManager !== 'undefined' && typeof storageManager.getLocalStorage === 'function')
            ? (storageManager.getLocalStorage('selectedGameVersion') || 'fs25')
            : (localStorage.getItem('selectedGameVersion') || 'fs25');

        const lastCategory = (typeof storageManager !== 'undefined' && typeof storageManager.getLocalStorage === 'function')
            ? (storageManager.getLocalStorage(`lastSelectedCategory_${lastGame}`) || 'Все')
            : (localStorage.getItem(`lastSelectedCategory_${lastGame}`) || 'Все');
        
        currentGameVersion = lastGame;

        // Показываем категории для последней выбранной игры и загружаем моды
        setTimeout(() => {
            switchGameVersion(lastGame, lastCategory); // Передаем и категорию
        }, 200); // Уменьшаем задержку для более быстрой загрузки
    } catch (error) {
        console.error("Ошибка при загрузке последней игры/категории:", error);
        // В случае ошибки загружаем настройки по умолчанию
        setTimeout(() => switchGameVersion('fs25', 'Все'), 200);
    }
}

// Обновление цветов заголовков категорий
function updateCategoryTitles(gameVersion) {
    const titleElements = document.querySelectorAll('.category-game-title');

    titleElements.forEach(title => {
        // Убираем все цветовые классы заголовков
        title.classList.remove('fs25-title-color', 'fs22-title-color', 'fs19-title-color', 'vip-title-color');

        // Находим родительский контейнер категорий
        const parentContainer = title.closest('.game-categories');
        if (!parentContainer) return;

        // Применяем цвета только для активного контейнера
        if (parentContainer.classList.contains('active')) {
            // Добавляем соответствующий класс для выбранной игры
            const titleClassMap = {
                'fs25': 'fs25-title-color',
                'fs22': 'fs22-title-color',
                'fs19': 'fs19-title-color',
                'vip_mods': 'vip-title-color'
            };

            const titleClass = titleClassMap[gameVersion];
            if (titleClass) {
                title.classList.add(titleClass);
            }

            // Определяем цвет текста и эмодзи в зависимости от игры
            switch(gameVersion) {
                case 'fs25':
                    title.textContent = '🟢 Farming Simulator 25';
                    break;
                case 'fs22':
                    title.textContent = '🔵 Farming Simulator 22';
                    break;
                case 'fs19':
                    title.textContent = '🟡 Farming Simulator 19';
                    break;
                case 'vip_mods':
                    title.textContent = '💎 VIP Моды';
                    break;
            }
        }
    });
}

// Применение цветовой темы к админ-панели
function applyAdminPanelTheme(gameVersion) {
    const adminPanel = document.getElementById('admin-panel');
    if (!adminPanel) return;

    // Убираем все тематические классы
    adminPanel.classList.remove('fs25-theme', 'fs22-theme', 'fs19-theme', 'vip-theme');

    // Добавляем соответствующий тематический класс
    const themeMap = {
        'fs25': 'fs25-theme',
        'fs22': 'fs22-theme', 
        'fs19': 'fs19-theme',
        'vip_mods': 'vip-theme'
    };

    const themeClass = themeMap[gameVersion];
    if (themeClass) {
        adminPanel.classList.add(themeClass);
        console.log(`🎨 Применена цветовая тема админ-панели: ${themeClass}`);
    }
}

// Загрузка счетчиков модов для категорий
async function loadCategoriesModCount(gameVersion) {
    try {
        
        // Для VIP разделов используем специальную логику
        let query = supabase
            .from('mods')
            .select('category, game_version')
            .eq('is_approved', true);
            
        if (gameVersion === 'vip_mods') {
            // Для VIP разделов считаем только VIP моды
            query = query.eq('is_private', true);
        } else {
            // Для обычных разделов считаем только обычные моды
            query = query.eq('is_private', false).eq('game_version', gameVersion);
        }

        const { data: mods, error } = await query;

        if (error) throw error;
        
        // Считаем количество модов по категориям
        const categoryCounts = {};
        if (mods) {
            mods.forEach(mod => {
                let category = mod.category || 'other';
                
                // Сопоставление категорий для совместимости
                const categoryMapping = {
                    'animal_husbandry': 'animals',
                    'rail_transport': 'railway',
                    'loaders_excavators': 'loaders',
                    'forestry_equipment': 'forestry',
                    'baling_equipment': 'baling',
                    'russian': 'russian_mods'
                };
                
                // Приводим категорию к формату из HTML
                if (categoryMapping[category]) {
                    category = categoryMapping[category];
                }
                
                categoryCounts[category] = (categoryCounts[category] || 0) + 1;
            });
        }
        
        // Обновляем счетчики в кнопках категорий
        let categoryButtons;
        if (gameVersion === 'vip_mods') {
            // Для VIP разделов нужно определить, какой контейнер сейчас активен
            const activeVipContainer = document.querySelector('[id^="vip_"].active');
            if (activeVipContainer) {
                categoryButtons = activeVipContainer.querySelectorAll('.category-btn');
            } else {
                // Если нет активного контейнера, используем основной
                categoryButtons = document.querySelectorAll('#vip_modsCategories .category-btn');
            }
        } else {
            // Для обычных разделов как обычно
            categoryButtons = document.querySelectorAll(`#${gameVersion}Categories .category-btn`);
        }

        categoryButtons.forEach(button => {
            // ✅ ИСПРАВЛЕНИЕ: Получаем название категории и иконку из data-атрибутов, а не из textContent
            const categoryId = button.dataset.categoryId;
            const categoryName = button.dataset.name;
            const icon = button.dataset.icon;
            
            // Для VIP разделов показываем количество VIP модов
            let count = 0;
            if (gameVersion === 'vip_mods') {
                // Для VIP разделов считаем по-разному в зависимости от типа категории
                if (categoryId === 'Все') {
                    // "Все моды" - показываем все VIP моды
                    count = mods.length;
                } else if (['fs25', 'fs22', 'fs19'].includes(categoryId)) {
                    // VIP FS25, VIP FS22, VIP FS19 - считаем VIP моды для конкретной версии
                    count = mods.filter(mod => mod.game_version === categoryId).length;
                } else {
                    // Обычные категории (objects, maps, tractors и т.д.) - считаем VIP моды для конкретной категории
                    count = mods.filter(mod => mod.category === categoryId).length;
                }
            } else {
                // Для обычных разделов используем обычную логику
                count = categoryCounts[categoryId] || 0;
            }

            // Обновляем HTML кнопки, используя данные из атрибутов
            button.innerHTML = `${icon}${categoryName} <span class="category-count-badge">${count}</span>`;
        });

        // 🎨 ВАЖНО: Применяем цветовые классы после обновления счетчиков
        setTimeout(() => {
            applyCategoryColors();
        }, 100);

        // Обновляем кнопку "Все моды"
        const allModsBtn = document.querySelector('.category-btn[onclick*="Все"]');
        if (allModsBtn) {
            const totalCount = mods ? mods.length : 0;
            allModsBtn.innerHTML = `🗂️ Все моды <span class="category-count-badge">${totalCount}</span>`;
        }

    } catch (error) {
        console.error('Ошибка загрузки счетчиков модов:', error);
    }
}

// Обновление активных состояний категорий
function updateCategoryStates(activeCategory, gameVersion) {
    // Снимаем активное состояние со всех категорий
    const allCategories = document.querySelectorAll('.category-btn');
    allCategories.forEach(btn => {
        btn.classList.remove('active');
    });

    // Находим активную категорию и устанавливаем ей активное состояние
    const activeBtn = document.querySelector(`[onclick="loadModsByCategory('${activeCategory}', '${gameVersion}')"]`);
    if (activeBtn) {
        activeBtn.classList.add('active');
    }
}


// Функция обработки клика на скачивание с проверкой блокировки
async function handleDownloadClick(modId) {
    console.log('🔍 [СКАЧАТЬ КЛИК] modId:', modId);
    
    try {
        // Проверяем авторизацию
        if (!window.authManager?.currentUser) {
            console.log('❌ [СКАЧАТЬ КЛИК] Пользователь не авторизован');
            showNotification('🔒 Необходимо войти в систему для скачивания модов', 'error');
            showLoginModal();
            return;
        }

        console.log('✅ [СКАЧАТЬ КЛИК] Пользователь авторизован:', window.authManager.currentUser.email);

        // ПРЯМАЯ ПРОВЕРКА БЛОКИРОВКИ В БД
        const profile = await getUserProfileInfo(window.authManager.currentUser.id);
        console.log('🔍 [СКАЧАТЬ КЛИК] Профиль:', profile);

        if (profile?.is_banned) {
            console.log('❌ [СКАЧАТЬ КЛИК] Пользователь заблокирован');
            const bannedByInfo = await getBannedByInfo(profile.banned_by);

            showNotification(`🚫 Доступ запрещен! Ваш аккаунт заблокирован. Заблокировал: ${bannedByInfo}. Причина: ${profile.ban_reason || 'Грубые нарушения правил'}`, 'error');
            return;
        }

        console.log('✅ [СКАЧАТЬ КЛИК] Пользователь не заблокирован, используем защищенное скачивание...');
        
        // 🔧 ИСПРАВЛЕНИЕ: Используем защищенную систему скачивания
        if (window.secureDownloadManager) {
            console.log('🔐 [СКАЧАТЬ КЛИК] Используем защищенное скачивание...');
            await window.secureDownloadManager.downloadModSecure(modId);
            console.log('✅ [СКАЧАТЬ КЛИК] Защищенное скачивание завершено успешно');
        } else {
            console.warn('⚠️ [СКАЧАТЬ КЛИК] Менеджер защищенного скачивания не найден, используем обычный метод...');
            // Fallback к обычному методу
            downloadMod(modId).then(() => {
                console.log('✅ [СКАЧАТЬ КЛИК] downloadMod завершён успешно');
            }).catch(error => {
                console.error('❌ [СКАЧАТЬ КЛИК] Ошибка downloadMod:', error);
                showNotification('❌ Ошибка скачивания: ' + error.message, 'error');
            });
        }

    } catch (error) {
        console.error('❌ [СКАЧАТЬ КЛИК] Ошибка:', error);
        showNotification('❌ Ошибка при проверке доступа к скачиванию', 'error');
    }
}

// Функция для получения правильной информации о пользователе (как в showBannedUsersList)
async function getUserProfileInfo(userId) {
    try {
        if (!userId) return null;
        
        const { data: profile, error } = await window.supabase
            .from('profiles')
            .select('id, username, email, role, is_banned, ban_reason, banned_by, banned_at, is_vip, vip_expires_at')
            .eq('id', userId)
            .single();
            
        if (error) {
            console.error('❌ Ошибка получения профиля:', error);
            return null;
        }
        
        return profile;
    } catch (error) {
        console.error('❌ Ошибка в getUserProfileInfo:', error);
        return null;
    }
}

// Функция для проверки статуса блокировки пользователя
async function isUserBanned() {
    try {
        if (!window.authManager?.currentUser) return false;
        
        const profile = await getUserProfileInfo(window.authManager.currentUser.id);
        
        if (!profile) {
            return false;
        }
        
        return profile.is_banned || false;
    } catch (error) {
        console.error('❌ Ошибка в isUserBanned:', error);
        return false;
    }
}

