// Переменные медиаплеера
let mediaPlaylistFiles = [];
let mediaPlayerState = {
    currentFile: null,
    currentIndex: -1,
    activePlayer: null
};

/**
 * Сохраняет текущее состояние медиаплеера
 */
function saveMediaPlayerState() {
    // Проверяем, что переменная определена
    if (!mediaPlayerState) {
        // console.warn('⚠️ mediaPlayerState не определен, пропускаем сохранение состояния');
        return null;
    }
    
    const videoPlayer = document.getElementById('media-section-video');
    const audioPlayer = document.getElementById('media-section-audio');
    
    const state = {
        currentFile: mediaPlayerState.currentFile,
        currentIndex: mediaPlayerState.currentIndex,
        playlist: mediaPlaylistFiles || [], // Сохраняем плейлист
        activePlayerType: null,
        currentTime: 0,
        wasPlaying: false,
        src: null,
        volume: 0.5
    };
    
    // Сохраняем состояние даже если на паузе, но есть источник
    if (videoPlayer && videoPlayer.src) {
        state.activePlayerType = 'video';
        state.currentTime = videoPlayer.currentTime;
        state.wasPlaying = !videoPlayer.paused;
        state.src = videoPlayer.src;
        state.volume = videoPlayer.volume;
    } else if (audioPlayer && audioPlayer.src) {
        state.activePlayerType = 'audio';
        state.currentTime = audioPlayer.currentTime;
        state.wasPlaying = !audioPlayer.paused;
        state.src = audioPlayer.src;
        state.volume = audioPlayer.volume;
    }
    
    // console.log('💾 Сохранено состояние медиаплеера:', state);
    return state;
}

/**
 * Восстанавливает состояние медиаплеера
 */
function restoreMediaPlayerState(savedState) {
    // Проверяем, что переменная определена
    if (!mediaPlayerState) {
        // console.warn('⚠️ mediaPlayerState не определен, пропускаем восстановление состояния');
        return;
    }
    
    if (!savedState || !savedState.src) {
        // console.log('📭 Нет сохраненного состояния медиаплеера для восстановления');
        return;
    }
    
    // Восстанавливаем плейлист
    if (savedState.playlist && savedState.playlist.length > 0) {
        mediaPlaylistFiles = savedState.playlist;
        // console.log('📋 Восстановлен плейлист из', savedState.playlist.length, 'файлов');
    }
    
    setTimeout(() => {
        const videoPlayer = document.getElementById('media-section-video');
        const audioPlayer = document.getElementById('media-section-audio');
        
        if (savedState.activePlayerType === 'video' && videoPlayer) {
            videoPlayer.src = savedState.src;
            videoPlayer.volume = savedState.volume;
            videoPlayer.currentTime = savedState.currentTime;
            videoPlayer.style.display = 'block';
            
            // Скрываем аудио плеер
            if (audioPlayer) {
                audioPlayer.style.display = 'none';
                audioPlayer.pause();
            }
            
            // Скрываем placeholder
            const placeholder = document.getElementById('media-placeholder');
            if (placeholder) {
                placeholder.style.display = 'none';
            }
            
            if (savedState.wasPlaying) {
                videoPlayer.play().catch(e => {/* console.log('Не удалось возобновить видео:', e) */});
            }
            
            // Обновляем состояние
            mediaPlayerState.activePlayer = videoPlayer;
            mediaPlayerState.currentFile = savedState.currentFile;
            mediaPlayerState.currentIndex = savedState.currentIndex;
            
        } else if (savedState.activePlayerType === 'audio' && audioPlayer) {
            audioPlayer.src = savedState.src;
            audioPlayer.volume = savedState.volume;
            audioPlayer.currentTime = savedState.currentTime;
            audioPlayer.style.display = 'block';
            
            // Скрываем видео плеер
            if (videoPlayer) {
                videoPlayer.style.display = 'none';
                videoPlayer.pause();
            }
            
            // Скрываем placeholder
            const placeholder = document.getElementById('media-placeholder');
            if (placeholder) {
                placeholder.style.display = 'none';
            }
            
            if (savedState.wasPlaying) {
                audioPlayer.play().catch(e => {/* console.log('Не удалось возобновить аудио:', e) */});
            }
            
            // Обновляем состояние
            mediaPlayerState.activePlayer = audioPlayer;
            mediaPlayerState.currentFile = savedState.currentFile;
            mediaPlayerState.currentIndex = savedState.currentIndex;
        }
        
        // Обновляем плейлист и информацию о треке
        if (typeof updatePlaylistMenu === 'function') {
            updatePlaylistMenu();
        }
        
        // Обновляем информацию о треке
        if (savedState.currentFile) {
            const trackInfo = document.getElementById('media-track-info');
            if (trackInfo) {
                trackInfo.textContent = savedState.currentFile.name;
            }
        }
        
        // console.log('✅ Восстановлено состояние медиаплеера:', savedState);
    }, 300); // Увеличенная задержка для гарантии, что все элементы созданы
}

// Скрытие админ панели
function hideAdminPanel() {
    const adminPanel = document.getElementById('admin-panel');
    const adminOverlay = document.getElementById('admin-panel-overlay');

    // Сохраняем текущую активную секцию перед закрытием
    const activeSection = document.querySelector('.admin-section.active');
    if (activeSection) {
        const sectionId = activeSection.id.replace('section-', '');
        localStorage.setItem('adminLastActiveSection', sectionId);
        console.log('💾 Сохраняем текущую секцию при закрытии:', sectionId);
    }

    if (adminPanel) {
        adminPanel.classList.remove('show');
        // Убираем трансформацию после анимации
        setTimeout(() => {
            if (!adminPanel.classList.contains('show')) {
                adminPanel.style.display = 'none';
                // НЕ показываем мини-панель при обычном скрытии
                // Мини-панель показывается только при полном выходе из админки
            }
        }, 400);
    }
    if (adminOverlay) {
        adminOverlay.classList.remove('show');
    }
}

// Сворачивание/разворачивание админ панели (для боковой панели)
function toggleAdminPanel() {
    const adminPanel = document.getElementById('admin-panel');
    const adminDetails = document.getElementById('admin-details');
    const toggleButton = document.getElementById('toggle-admin-panel');

    if (adminPanel && adminDetails && toggleButton) {
        console.log('🔄 Переключаем админ панель (боковая)');

        if (adminDetails.style.display === 'none') {
            // Разворачиваем панель в полный размер
            console.log('📏 Разворачиваем боковую админ панель');
            adminDetails.style.display = 'block';
            toggleButton.innerHTML = '⤢';
            toggleButton.title = 'Компактный вид';
            adminPanel.style.width = '600px';
            adminPanel.style.height = '100vh';
            console.log('✅ Боковая админ панель развернута');
        } else {
            // Сворачиваем панель в компактный режим
            console.log('🗜️ Сворачиваем боковую админ панель');
            adminDetails.style.display = 'none';
            toggleButton.innerHTML = '⤡';
            toggleButton.title = 'Полный вид';
            adminPanel.style.width = '500px';
            adminPanel.style.height = '100vh';

            // Показываем компактный интерфейс
            showCompactAdminView();
            console.log('✅ Боковая админ панель свернута');
        }
    } else {
        console.warn('⚠️ Не все элементы админ панели найдены для переключения');
    }
}

