/**
 * Загружает информацию о коде владельца
 */
async function loadOwnerCodeInfo() {
    try {
        // Получаем текущий код владельца из localStorage
        let currentOwnerCode = localStorage.getItem('owner_code') || 'KEROS1980'; // код по умолчанию
        let lastUpdated = localStorage.getItem('owner_code_updated') || new Date().toISOString();
        
        // Обновляем отображение
        const displayElement = document.getElementById('current-owner-code-display');
        const updatedElement = document.getElementById('owner-code-updated');
        
        if (displayElement) {
            displayElement.textContent = '•'.repeat(currentOwnerCode.length);
        }
        
        if (updatedElement) {
            try {
                const lastUpdatedDate = new Date(lastUpdated);
                updatedElement.textContent = lastUpdatedDate.toLocaleString('ru-RU', {
                    year: 'numeric',
                    month: '2-digit',
                    day: '2-digit',
                    hour: '2-digit',
                    minute: '2-digit'
                });
            } catch (e) {
                updatedElement.textContent = 'Неизвестно';
            }
        }
        
    } catch (error) {
        console.error('❌ [loadOwnerCodeInfo] Ошибка загрузки кода владельца:', error);
    }
}

/**
 * Сменяет код владельца
 */
async function changeOwnerCode() {
    const currentCode = document.getElementById('current-owner-code').value;
    const newCode = document.getElementById('new-owner-code').value;
    const confirmCode = document.getElementById('confirm-owner-code').value;
    const resultElement = document.getElementById('owner-code-change-result');
    
    // Валидация
    if (!currentCode || !newCode || !confirmCode) {
        resultElement.textContent = '❌ Заполните все поля';
        resultElement.style.color = '#ff4757';
        return;
    }
    
    if (newCode.length < 6) {
        resultElement.textContent = '❌ Код должен содержать минимум 6 символов';
        resultElement.style.color = '#ff4757';
        return;
    }
    
    if (newCode !== confirmCode) {
        resultElement.textContent = '❌ Коды не совпадают';
        resultElement.style.color = '#ff4757';
        return;
    }
    
    try {
        // Получаем текущий код владельца из localStorage для проверки
        let currentOwnerCode = localStorage.getItem('owner_code') || 'KEROS1980';
        
        // console.log('🔑 [changeOwnerCode] Текущий код владельца:', currentOwnerCode);
        
        // Проверяем текущий код
        if (currentCode !== currentOwnerCode) {
            resultElement.textContent = '❌ Неверный текущий код владельца';
            resultElement.style.color = '#ff4757';
            return;
        }
        
        // Обновляем код владельца в localStorage
        localStorage.setItem('owner_code', newCode);
        localStorage.setItem('owner_code_updated', new Date().toISOString());
        
        // Обновляем отображение
        resultElement.textContent = '✅ Код владельца успешно изменен';
        resultElement.style.color = '#4CAF50';
        
        // Очищаем поля
        document.getElementById('current-owner-code').value = '';
        document.getElementById('new-owner-code').value = '';
        document.getElementById('confirm-owner-code').value = '';
        
        // Перезагружаем информацию о коде
        await loadOwnerCodeInfo();
        
        // Показываем уведомление
        showNotification('🔑 Код владельца успешно изменен', 'success', 3000);
        
    } catch (error) {
        console.error('❌ [changeOwnerCode] Ошибка смены кода владельца:', error);
        resultElement.textContent = '❌ Ошибка при смене кода: ' + error.message;
        resultElement.style.color = '#ff4757';
    }
}

