/**
 * Переключение видимости пароля (универсальная функция)
 * ИСПРАВЛЕНИЕ: Не меняем type поля, чтобы не нарушать работу браузерного менеджера паролей
 */
function togglePasswordVisibility(inputIdOrEvent, buttonElement) {
    let input, button;
    
    // Если первый параметр - это событие (старый формат)
    if (typeof inputIdOrEvent === 'object' && inputIdOrEvent.target) {
        const event = inputIdOrEvent;
        button = event.target;
        input = button.previousElementSibling;
    } 
    // Если первый параметр - это ID (новый формат)
    else if (typeof inputIdOrEvent === 'string') {
        input = document.getElementById(inputIdOrEvent);
        button = buttonElement;
    }
    
    // Проверяем, что элементы найдены
    if (!input) {
        console.error('❌ Поле ввода пароля не найдено');
        return;
    }
    
    if (!button) {
        console.error('❌ Кнопка переключения не найдена');
        return;
    }
    
    // Переключаем тип поля
    if (input.type === 'password') {
        input.type = 'text';
        button.textContent = '🙈';
        button.title = 'Скрыть пароль';
    } else {
        input.type = 'password';
        button.textContent = '👁️';
        button.title = 'Показать пароль';
    }
}

// Проверяем, что функция загрузилась
console.log('✅ Функция togglePasswordVisibility загружена');

/**
 * Обработчик смены пароля админ-панели (вторая форма)
 */
async function changeAdminPasswordAlt() {
    const currentPassword = document.getElementById('current-admin-password')?.value;
    const newPassword = document.getElementById('new-admin-password')?.value;
    const confirmPassword = document.getElementById('confirm-admin-password')?.value;
    const resultDiv = document.getElementById('password-change-result');
    
    // Проверяем, что все поля заполнены
    if (!currentPassword || !newPassword || !confirmPassword) {
        resultDiv.innerHTML = '<span style="color: #ff4757;">❌ Заполните все поля формы</span>';
        return;
    }
    
    // Проверяем длину нового пароля
    if (newPassword.length < 6) {
        resultDiv.innerHTML = '<span style="color: #ff4757;">❌ Новый пароль должен содержать минимум 6 символов</span>';
        return;
    }
    
    // Проверяем совпадение паролей
    if (newPassword !== confirmPassword) {
        resultDiv.innerHTML = '<span style="color: #ff4757;">❌ Новый пароль и подтверждение не совпадают</span>';
        return;
    }
    
    // Проверяем, что новый пароль отличается от текущего
    if (currentPassword === newPassword) {
        resultDiv.innerHTML = '<span style="color: #ffa502;">⚠️ Новый пароль должен отличаться от текущего</span>';
        return;
    }
    
    resultDiv.innerHTML = '<span style="color: #ffd700;">⏳ Проверка текущего пароля и смена...</span>';
    
    try {
        // Проверяем, что объект adminPanelSecurity существует
        if (!window.adminPanelSecurity || typeof window.adminPanelSecurity.changePassword !== 'function') {
            throw new Error('Модуль безопасности админ-панели не загружен');
        }
        
        const result = await window.adminPanelSecurity.changePassword(currentPassword, newPassword);
        
        if (result.success) {
            // Первое сообщение - успешная смен��
            resultDiv.innerHTML = '<span style="color: #4CAF50;">✅ ' + result.message + '</span>';
            
            // Очищаем поля формы
            document.getElementById('current-admin-password').value = '';
            document.getElementById('new-admin-password').value = '';
            document.getElementById('confirm-admin-password').value = '';
            
            // Второе сообщение через 1.5 секунды
            setTimeout(() => {
                resultDiv.innerHTML = '<span style="color: #2ecc71;">🔐 Пароль ��дм��н-панели ��с��ешно изменен! Используйте новый пароль при следующем входе.</span>';
            }, 1500);
            
            // Третье сообщение через 3 секунды и обновление интерфейса
            setTimeout(async () => {
                resultDiv.innerHTML = '<span style="color: #00b894;">✨ Пароль изменен! Информация обновлена...</span>';
                
                // Обновляем информацию о пароле
                await showAdminPasswordSettings();
                
                // Финальное сообщение
                setTimeout(() => {
                    const resultDiv = document.getElementById('password-change-result');
                    if (resultDiv) {
                        resultDiv.innerHTML = '<span style="color: #27ae60;">🎉 Пароль успешно изменен и сохранен в системе!</span>';
                    }
                }, 1000);
            }, 3000);
        } else {
            resultDiv.innerHTML = '<span style="color: #ff4757;">❌ ' + result.message + '</span>';
        }
    } catch (error) {
        console.error('❌ Ошибка смены пароля:', error);
        resultDiv.innerHTML = '<span style="color: #ff4757;">❌ ' + (error.message || 'Произошла ошибка при смене пароля') + '</span>';
    }
}

/**
 * Загружает Google Font если он еще не загружен
 */
function loadGoogleFont(fontFamily) {
    try {
        // Извлекаем название шрифта из строки
        const fontName = fontFamily.replace(/['"]/g, '').split(',')[0].trim();
        
        // Проверяем, что это Google Font
        const googleFonts = ['Fira Code', 'Roboto', 'Roboto Mono', 'Open Sans', 'Lato', 'Montserrat', 'Poppins', 'Raleway'];
        if (!googleFonts.some(gf => fontName.includes(gf))) {
            return; // Не Google Font, не загр��жаем
        }
        
        // Проверяем, что шрифт еще не загружен
        if (document.querySelector(`link[href*="fonts.googleapis.com/css?family=${fontName.replace(' ', '+')}"]`)) {
            return; // Уже загружен
        }
        
        // Создаем и добавляем link для загрузки шрифта
        const link = document.createElement('link');
        link.rel = 'stylesheet';
        link.href = `https://fonts.googleapis.com/css2?family=${fontName.replace(' ', '+')}&display=swap`;
        document.head.appendChild(link);
        
        console.log(`🔤 Google Font "${fontName}" загружается...`);
        
        // Добавляем fallback на случай ошибки загрузки
        link.onerror = () => {
            console.warn(`⚠️ Не удалось загрузить Google Font "${fontName}"`);
        };
        
    } catch (error) {
        console.error('❌ Ошибка загрузки Google Font:', error);
    }
}

/**
 * Генерирует CSS-строку на основе настроек и вставляет её в <style id="global-theme-styles">.
 * @param {object} settings - Объект с настройками темы.
 */
function applyGlobalTheme(settings) {
    const { primaryColor, secondaryColor, bgColor, textColor, mainFont, fontSize } = settings;

    // Загружаем Google Fonts если нужно
    if (mainFont.includes('Fira') || mainFont.includes('Roboto')) {
        loadGoogleFont(mainFont);
    }

    // Создаем CSS-правила. Использование !important необходимо для переопределения существующих стилей.
    const css = `
        :root {
            --primary-color: ${primaryColor};
            --secondary-color: ${secondaryColor};
            --bg-color: ${bgColor};
            --text-color: ${textColor};
            --main-font: ${mainFont} !important;
            --font-size: ${fontSize} !important;
        }
        
        /* Глобальные стили */
        body, html {
            background-color: ${bgColor} !important;
            color: ${textColor} !important;
            font-family: ${mainFont} !important;
            font-size: ${fontSize} !important;
        }
        
        /* Все элементы */
        * {
            color: ${textColor} !important;
            font-family: ${mainFont} !important;
        }
        
        /* Все текстовые элементы - расширенное применение шрифтов */
        body, html, div, span, p, a, h1, h2, h3, h4, h5, h6, li, td, th, label, input, select, textarea, button, .btn, .text, .content, .description, .title, .subtitle, .menu-item, .nav-item, .card-text, .modal-text, .form-text, .info-text, .message-text, .notification-text, .tooltip-text, .legend-text, .caption-text, .note-text, .warning-text, .error-text, .success-text {
            font-family: ${mainFont} !important;
        }
        
        /* Специальные текстовые классы */
        .main-text, .primary-text, .secondary-text, .accent-text, .highlight-text, .body-text, .paragraph-text, .section-text, .header-text, .footer-text, .sidebar-text, .content-text, .article-text, .post-text, .comment-text, .review-text, .description-text, .summary-text, .detail-text, .info-text, .status-text, .label-text, .value-text, .name-text, .email-text, .phone-text, .address-text, .date-text, .time-text, .price-text, .category-text, .tag-text, .badge-text, .score-text, .rating-text, .count-text, .number-text, .percent-text, .currency-text {
            font-family: ${mainFont} !important;
        }
        
        /* Контейнеры */
        .container, .content, .admin-content, .theme-settings-scroll, .main-container {
            background-color: ${bgColor} !important;
            color: ${textColor} !important;
            font-family: ${mainFont} !important;
        }
        
        /* Заголовки */
        h1, h2, h3, h4, h5, h6 {
            color: ${primaryColor} !important;
            font-family: ${mainFont} !important;
            text-shadow: 0 0 3px rgba(0,0,0,0.5) !important;
        }
        
        /* Подзаголовки и акценты */
        .logo-subtitle, .accent-text, .highlight {
            color: ${secondaryColor} !important;
            font-family: ${mainFont} !important;
        }
        
        /* Кнопки */
        .btn, button, .category-btn, .nav-btn {
            background-color: ${primaryColor} !important;
            border-color: ${secondaryColor} !important;
            color: ${bgColor} !important;
            font-family: ${mainFont} !important;
        }
        
        .btn:hover, button:hover, .category-btn:hover, .nav-btn:hover {
            background-color: ${secondaryColor} !important;
            color: ${bgColor} !important;
            font-family: ${mainFont} !important;
        }
        
        /* Активные кнопки */
        .btn.active, button.active, .category-btn.active, .nav-btn.active {
            background-color: ${secondaryColor} !important;
            color: ${bgColor} !important;
            box-shadow: 0 0 3px ${primaryColor} !important;
        }
        
        /* Поля ввода */
        input, select, textarea {
            background-color: rgba(10, 25, 47, 0.8) !important;
            border-color: ${secondaryColor} !important;
            color: ${textColor} !important;
            font-family: ${mainFont} !important;
        }
        
        input:focus, select:focus, textarea:focus {
            border-color: ${primaryColor} !important;
            box-shadow: 0 0 2px ${primaryColor} !important;
            font-family: ${mainFont} !important;
        }
        
        /* Цветовые поля ввода */
        input[type="color"] {
            background-color: ${bgColor} !important;
            border-color: ${secondaryColor} !important;
        }
        
        /* Option элементы */
        option {
            background-color: ${bgColor} !important;
            color: ${textColor} !important;
        }
        
        /* Checkbox */
        input[type="checkbox"] {
            background-color: ${bgColor} !important;
            border-color: ${primaryColor} !important;
            accent-color: ${primaryColor} !important;
        }
        
        /* Навигация */
        .navigation-bar, .nav-menu, .header {
            background-color: ${bgColor} !important;
            border-color: ${secondaryColor} !important;
        }
        
        .nav-item, .menu-item {
            color: ${textColor} !important;
            font-family: ${mainFont} !important;
        }
        
        .nav-item:hover, .menu-item:hover {
            color: ${primaryColor} !important;
            background-color: rgba(255,255,255,0.1) !important;
        }
        
        /* Карточки */
        .mod-card, .card, .panel {
            background-color: rgba(255,255,255,0.05) !important;
            border-color: ${secondaryColor} !important;
            color: ${textColor} !important;
        }
        
        /* Ссылки */
        a, .link {
            color: ${primaryColor} !important;
        }
        
        a:hover, .link:hover {
            color: ${secondaryColor} !important;
        }
        
        /* Модальные окна */
        .modal, .popup, .overlay {
            background-color: ${bgColor} !important;
            color: ${textColor} !important;
        }
        
        /* Таблицы */
        table, .table {
            background-color: ${bgColor} !important;
            color: ${textColor} !important;
            border-color: ${secondaryColor} !important;
        }
        
        th, .table-header {
            background-color: ${primaryColor} !important;
            color: ${bgColor} !important;
        }
        
        td, .table-cell {
            border-color: ${secondaryColor} !important;
        }
    `;

    let styleTag = document.getElementById('global-theme-styles');
    if (!styleTag) {
        // Создаем тег если его нет
        styleTag = document.createElement('style');
        styleTag.id = 'global-theme-styles';
        document.head.appendChild(styleTag);
        console.log('✅ Создан тег <style id="global-theme-styles">');
    }
    styleTag.innerHTML = css;

    // Принудительно обно����ляем все элементы для немедленного применения
    forceThemeUpdate(settings);
    
    // Дополнительное принудительное применение шрифтов ко всем элементам
    setTimeout(() => {
        const allElements = document.querySelectorAll('*');
        allElements.forEach(element => {
            if (element.textContent && element.textContent.trim()) {
                element.style.fontFamily = mainFont;
            }
        });
        console.log('🔤 Принудительно применен шрифт ко всем элементам страницы');
    }, 100);
    
    window.isGlobalThemeApplied = true;
    console.log('✅ Глобальная тема успешно применена');
    
    // УБРАЛИ УВЕДОМЛЕНИЕ - сообщения показываются только при изменении темы пользователем
    // showNotification('🎨 Тема успешно применена!', 'success');
}

/**
 * Сохраняет настройки темы в Supabase.
 * @param {object} settings - Объект с настройками темы.
 */
async function saveThemeToSupabase(settings) {
    try {
        console.log('💾 Попытка сохранения настроек темы:', settings);
        
        // Проверяем авторизацию
        const { data: { user }, error: userError } = await window.supabase.auth.getUser();
        if (userError || !user) {
            console.error('❌ Пользователь не авторизован');
            showNotification('❌ Ошибка: необходимо войти в систему для сохранения темы', 'error');
            return;
        }

        // Проверяем права администратора
        const { data: profile, error: profileError } = await window.supabase
            .from('profiles')
            .select('role')
            .eq('id', user.id)
            .single();

        if (profileError || !['admin', 'admin_senior', 'owner'].includes(profile?.role)) {
            console.error('❌ Недостаточно прав для изменения темы');
            showNotification('❌ Ошибка: недостаточно прав для изменения темы', 'error');
            return;
        }

        // Подготавливаем данные для обновления
        const rowsToUpsert = Object.entries(settings).map(([key, value]) => ({
            setting_key: key,
            setting_value: String(value),
            setting_type: 'string',
            updated_by: user.id
        }));

        // Выполняем обновление
        const { error } = await window.supabase
            .from('site_settings')
            .upsert(rowsToUpsert, { onConflict: 'setting_key' });

        if (error) {
            console.error('❌ Ошибка при сохранении настроек темы:', error);
            showNotification(`❌ Ошибка сохранения темы: ${error.message}`, 'error');
            return;
        }

        console.log('✅ Настройки темы успешно сохранены');
        showNotification('🎨 Тема успешно сохранена! Изменения применены у всех пользователей 🌐', 'success');
        
        // Принудительно уведомляем всех пользователей о смене темы
        setTimeout(() => {
            if (window.supabase) {
                window.supabase.channel('theme-broadcast').send({
                    type: 'broadcast',
                    event: 'theme_changed',
                    payload: { 
                        message: 'Тема сайта была обновлена администратором!',
                        settings: settings,
                        timestamp: new Date().toISOString()
                    }
                });
            }
        }, 100);
    } catch (error) {
        console.error('❌ Критическая ошибка при сохранении темы:', error);
        showNotification('❌ Не удалось сохранить тему. Пожалуйста, попробуйте снова.', 'error');
    }
}

// Функция для принудительного обновления всех элементов интерфейса
function forceThemeUpdate(settings) {
    console.log('🔄 Принудительное обновление темы для всех элементов...');
    
    try {
        // Обновляем все кнопки и ссылки
        const buttons = document.querySelectorAll('button, .btn');
        buttons.forEach(btn => {
            btn.style.borderColor = settings.secondaryColor + ' !important';
            btn.style.color = settings.textColor + ' !important';
        });
        
        // Обновляем все заголовки
        const headers = document.querySelectorAll('h1, h2, h3, h4, h5, h6');
        headers.forEach(header => {
            header.style.color = settings.primaryColor + ' !important';
        });
        
        // Обновляем body
        document.body.style.backgroundColor = settings.bgColor + ' !important';
        document.body.style.color = settings.textColor + ' !important';
        document.body.style.fontFamily = settings.mainFont + ' !important';
        document.body.style.fontSize = settings.fontSize + ' !important';
        
        // Обновляем навигационную панель
        const navBar = document.querySelector('.navigation-bar');
        if (navBar) {
            navBar.style.backgroundColor = settings.bgColor + ' !important';
        }
        
        // Обновляем карточки модов
        const modCards = document.querySelectorAll('.mod-card');
        modCards.forEach(card => {
            card.style.backgroundColor = 'rgba(10, 25, 47, 0.7) !important';
            card.style.borderColor = settings.secondaryColor + '33 !important';
        });
        
        // Обновляем активные категории
        const activeCategories = document.querySelectorAll('.category-btn.active');
        activeCategories.forEach(btn => {
            btn.style.backgroundColor = settings.primaryColor + ' !important';
            btn.style.color = settings.bgColor + ' !important';
            btn.style.boxShadow = `0 0 15px ${settings.primaryColor} !important`;
        });
        
        // console.log('✅ Все элементы интерфейса обновлены');
    } catch (error) {
        console.error('❌ Ошибка при обновлении элементов:', error);
    }
}

