// Глобальная функция применения пресетов тем
window.applyThemePreset = (presetKey) => {
    const preset = window.themePresets[presetKey];
    if (preset) {
        applyGlobalTheme(preset.settings);
        saveThemeToSupabase(preset.settings);
        console.log(`🎨 Применен пресет темы: ${preset.name}`);
        
        // 🎨 ОБНОВЛЯЕМ ПОЛЯ ФОРМЫ ПОСЛЕ ПРИМЕНЕНИЯ ПРЕСЕТА
        setTimeout(() => {
            const primaryColorEl = document.getElementById('primaryColor');
            const secondaryColorEl = document.getElementById('secondaryColor');
            const bgColorEl = document.getElementById('bgColor');
            const textColorEl = document.getElementById('textColor');
            const mainFontEl = document.getElementById('mainFont');
            const fontSizeEl = document.getElementById('font-size');
            const fontSizeValueEl = document.getElementById('font-size-value');
            
            if (primaryColorEl) primaryColorEl.value = preset.settings.primaryColor;
            if (secondaryColorEl) secondaryColorEl.value = preset.settings.secondaryColor;
            if (bgColorEl) bgColorEl.value = preset.settings.bgColor;
            if (textColorEl) textColorEl.value = preset.settings.textColor;
            if (mainFontEl) mainFontEl.value = preset.settings.mainFont;
            if (fontSizeEl) fontSizeEl.value = parseInt(preset.settings.fontSize);
            if (fontSizeValueEl) fontSizeValueEl.textContent = preset.settings.fontSize;
            
            console.log('🎨 Поля формы обновлены для пресета:', preset.settings);
        }, 100);
    } else {
        console.error(`❌ Пресет темы "${presetKey}" не найден`);
    }
};

/**
 * Инициализирует тему: загружает из Supabase и подписывается на обновления.
 */
async function initializeGlobalTheme() {
    // ✅ ИСПРАВЛЕНИЕ: Убрана проверка на администратора. Глобальная тема должна загружаться для ВСЕХ пользователей.
    try {
        console.log('🎨 Загрузка глобальных настроек темы для всех пользователей...');

        // 1. Загружаем настройки темы из Supabase
        console.log('🔍 Загрузка настроек темы из Supabase...');
        const { data: settingsData, error } = await window.supabase
            .from('site_settings')
            .select('setting_key, setting_value');

        if (error && error.code !== 'PGRST116') { // Игнорируем ошибку "not found"
            console.error('❌ Ошибка загрузки темы:', error);
            return;
        }

        if (settingsData && settingsData.length > 0) {
            // console.log('🎨 Применяем сохраненную тему из Supabase');
            // Преобразуем массив в объект настроек
            const settings = settingsData.reduce((acc, item) => {
                acc[item.setting_key] = item.setting_value;
                return acc;
            }, {});
            
            applyGlobalTheme(settings);
            window.isGlobalThemeApplied = true;
            // console.log('✅ Глобальная тема успешно применена');
            
            // УБРАЛИ УВЕДОМЛЕНИЕ - не показываем сообщение при загрузке страницы
            // showNotification('🎨 Сохраненная тема успешно применена!', 'success');
        } else {
            console.log('🎨 Тема в Supabase не найдена, используются стили по умолчанию.');
        }

        // 2. Подписываемся на обновления в реальном времени для ВСЕХ
        // 2. Подписываемся на обновления в реальном времени через Postgres Changes
        window.supabase
            .channel('public:site_settings')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'site_settings' }, async (payload) => {
                console.log('🎨 Получено обновление темы в реальном времени!', payload.new);
                showNotification('🎨 Дизайн сайта был обновлен администратором!', 'info');

                // ИСПРАВЛЕНИЕ: Вместо полной перезагрузки, применяем изменения на лету.
                // Загружаем все настройки, чтобы убедиться, что у нас есть полный набор.
                const { data: settingsData } = await window.supabase
                    .from('site_settings')
                    .select('setting_key, setting_value');

                if (settingsData) {
                    const settings = settingsData.reduce((acc, item) => {
                        acc[item.setting_key] = item.setting_value;
                        return acc;
                    }, {});
                    applyGlobalTheme(settings);
                }
            })
            .subscribe();

        // 3. Дополнительная подписка на broadcast события для немедленной синхронизации
        window.supabase
            .channel('theme-broadcast')
            .on('broadcast', { event: 'theme_changed' }, async (payload) => {
                console.log('🎨 Получено broadcast уведомление о смене темы!', payload);
                showNotification('🎨 ' + payload.payload.message, 'info');
                
                // Применяем тему немедленно
                if (payload.payload.settings) {
                    applyGlobalTheme(payload.payload.settings);
                }
            })
            .subscribe();

    } catch (error) {
        console.error('❌ Ошибка инициализации глобальной темы:', error);
    }
}

/**
 * Инициализирует приём broadcast-уведомлений о смене VIP статуса.
 */
async function initializeVipStatusSync() {
    try {
        // console.log('💎 Инициализация синхронизации VIP статуса...');
        
        // Проверяем доступность Supabase
        if (!window.supabase) {
            console.error('❌ Supabase не инициализирован!');
            return;
        }
        
        // console.log('✅ Supabase доступен, создаем канал...');
        
        // Создаем канал с расширенными опциями
        const vipChannel = window.supabase.channel('vip-status-broadcast', {
            config: {
                broadcast: { self: true },
                presence: { key: 'vip-sync' }
            }
        });
        
        // console.log('✅ Канал создан, подписываемся на события...');
        
        // Подписываемся на broadcast события для немедленной синхронизации VIP статуса
        vipChannel
            .on('broadcast', { event: 'vip_status_changed' }, async (payload) => {
                console.log('💎 ПОЛУЧЕНО BROADCAST УВЕДОМЛЕНИЕ!', payload);
                console.log('💎 Payload:', JSON.stringify(payload, null, 2));
                
                const { userId, isVip, action, username, expirationDate } = payload.payload;
                
                // Показываем уведомление
                const actionText = action === 'granted' ? 'выдан VIP-статус' : 'лишен VIP-статуса';
                const userText = username || `Пользователю ${userId}`;
                showNotification(`💎 ${userText} ${actionText}!`, 'info');
                
                // Если это текущий пользователь, немедленно обновляем его интерфейс
                if (window.authManager && window.authManager.currentUser && 
                    window.authManager.currentUser.id === userId) {
                    console.log(`💎 ЭТО ТЕКУЩИЙ ПОЛЬЗОВАТЕЛЬ! Обновляем VIP статус... Действие: ${action}`);
                    
                    // Принудительно обновляем сессию пользователя
                    console.log('🔄 Вызываем forceRefreshUserSession...');
                    if (window.authManager && typeof window.authManager.forceRefreshUserSession === 'function') {
                        await window.authManager.forceRefreshUserSession();
                        console.log('✅ forceRefreshUserSession выполнен');
                        
                        // 🔧 ИСПРАВЛЕНИЕ: Показываем VIP контент после обновления сессии
                        if (typeof window.authManager.checkAndShowVipContent === 'function') {
                            await window.authManager.checkAndShowVipContent();
                            console.log('✅ checkAndShowVipContent выполнен');
                        }
                    } else {
                        console.warn('⚠️ forceRefreshUserSession не найден');
                    }
                    
                    // ✅ АВТОМАТИЧЕСКОЕ ЗАКРЫТИЕ АДМИН-ПАНЕЛИ
                    console.log('🔄 Автоматически закрываем админ-панель...');
                    const adminModal = document.querySelector('.admin-modal');
                    if (adminModal) {
                        adminModal.remove();
                        console.log('✅ Админ-панель закрыта');
                    }
                    
                    // ✅ ПРИНУДИТЕЛЬНОЕ ОБНОВЛЕНИЕ МОДОВ
                    console.log('🔄 Принудительно обновляем моды...');
                    setTimeout(async () => {
                        // Обновляем все карточки модов на странице
                        const modCards = document.querySelectorAll('.mod-card');
                        modCards.forEach(card => {
                            const vipBadge = card.querySelector('.vip-badge');
                            const downloadBtn = card.querySelector('.download-btn');
                            const vipOnly = card.querySelector('.vip-only');
                            
                            if (isVip) {
                                // Показываем VIP элементы
                                if (vipBadge) {
                                    vipBadge.style.display = 'inline-block';
                                    vipBadge.textContent = '💎';
                                }
                                if (downloadBtn) {
                                    downloadBtn.disabled = false;
                                    downloadBtn.textContent = '📥 Скачать';
                                    downloadBtn.title = '';
                                }
                                if (vipOnly) vipOnly.style.display = 'block';
                            } else {
                                // Скрываем VIP элементы
                                if (vipBadge) vipBadge.style.display = 'none';
                                if (downloadBtn) {
                                    downloadBtn.disabled = true;
                                    downloadBtn.textContent = '🔒 VIP только';
                                    downloadBtn.title = 'Этот мод доступен только для VIP пользователей';
                                }
                                if (vipOnly) vipOnly.style.display = 'none';
                            }
                        });
                        
                        // Обновляем счетчики модов
                        const vipModsCount = document.querySelectorAll('.mod-card.vip-mod').length;
                        const totalModsCount = document.querySelectorAll('.mod-card').length;
                        
                        // Обновляем фильтры
                        const vipFilter = document.querySelector('[data-filter="vip"]');
                        if (vipFilter) {
                            vipFilter.textContent = `VIP (${vipModsCount})`;
                        }
                        
                        console.log(`✅ Моды принудительно обновлены: VIP=${vipModsCount}, всего=${totalModsCount}`);
                        
                        // Обновляем текущую категорию
                        const currentCategory = document.querySelector('.category-btn.active')?.dataset.category;
                        if (currentCategory && typeof loadModsByCategory === 'function') {
                            await loadModsByCategory(currentCategory);
                        }
                        
                        // Показываем уведомление об обновлении
                        const actionText = action === 'granted' ? 'выдан' : 'лишен';
                        showNotification(`💎 VIP статус ${actionText}! Моды обновлены.`, 'success');
                        
                    }, 500); // Небольшая задержка для обновления данных
                    
                    // Обновляем интерфейс пользователя
                    console.log('🔄 Обновляем интерфейс пользователя...');
                    if (typeof updateUserInterface === 'function') {
                        updateUserInterface();
                        console.log('✅ updateUserInterface выполнен');
                    }
                    
                    // Обновляем навигационные индикаторы
                    console.log('🔄 Обновляем навигационные индикаторы...');
                    if (typeof updateAdminNavIndicators === 'function') {
                        updateAdminNavIndicators();
                        console.log('✅ updateAdminNavIndicators выполнен');
                    }
                    
                    // Обновляем VIP информацию в магазине
                    console.log('🔄 Обновляем VIP информацию в магазине...');
                    if (window.shopManager && typeof window.shopManager.loadVipInfo === 'function') {
                        window.shopManager.loadVipInfo();
                        console.log('✅ loadVipInfo выполнен');
                    }
                    
                    // Если VIP статус был выдан, показываем дополнительное уведомление
                    if (action === 'granted' && isVip) {
                        const expiryText = expirationDate ? 
                            `до ${new Date(expirationDate).toLocaleDateString()}` : 
                            'навсегда';
                        showNotification(`🎉 Вам выдан VIP-статус ${expiryText}!`, 'success');
                    }
                } else {
                    console.log(`💎 Это не текущий пользователь. Текущий ID: ${window.authManager?.currentUser?.id}, ID из события: ${userId}`);
                }
                
                // Обновляем отображение модов для всех пользователей
                console.log('🔄 Обновляем отображение модов...');
                if (typeof window.refreshModsDisplay === 'function') {
                    window.refreshModsDisplay();
                    console.log('✅ refreshModsDisplay выполнен');
                }
                
                // Обновляем списки пользователей в админ-панели
                console.log('🔄 Обновляем списки пользователей...');
                if (typeof refreshUsersList === 'function') {
                    refreshUsersList();
                    console.log('✅ refreshUsersList выполнен');
                }
                
                // Обновляем списки заказов
                console.log('🔄 Обновляем списки заказов...');
                if (typeof loadOrders === 'function') {
                    loadOrders();
                    console.log('✅ loadOrders выполнен');
                }
            })
            .subscribe((status) => {
                console.log('💎 Статус подписки на VIP канал:', status);
                if (status === 'SUBSCRIBED') {
                    console.log('✅ Успешная подписка на VIP канал!');
                } else if (status === 'CHANNEL_ERROR') {
                    console.warn('⚠️ VIP канал временно недоступен (это не критично)');
                } else if (status === 'TIMED_OUT') {
                    console.warn('⚠️ Тайм-аут VIP канала (это не критично)');
                }
            });
            
        // console.log('✅ Синхронизация VIP статуса успешно инициализирована');
        
    } catch (error) {
        console.error('❌ Ошибка инициализации синхронизации VIP статуса:', error);
        console.error('❌ Stack trace:', error.stack);
    }
}

/**
 * Мгновенное обновление VIP модов без перезагрузки
 */
window.updateModsForVipChange = async function(userId, isVip) {
    // Защита от циклических вызовов
    const updateKey = `${userId}_${isVip}`;
    
    // Если блокировка активна и те же данные - пропускаем
    if (window.updateModsForVipChangeLock && window.lastVipUpdate === updateKey) {
        console.log('🔄 Пропускаем повторный вызов updateModsForVipChange - те же данные');
        return;
    }
    
    // Если блокировка активна но данные разные - ждем сброса
    if (window.updateModsForVipChangeLock) {
        console.log('🔄 Ожидаем сброса блокировки updateModsForVipChange');
        return;
    }
    
    // Устанавливаем блокировку
    window.updateModsForVipChangeLock = true;
    window.lastVipUpdate = updateKey;
    
    try {
        console.log(`🔄 Мгновенное обновление модов для пользователя ${userId}, VIP: ${isVip}`);
        
        // Если это текущий пользователь, обновляем его моды
        if (window.authManager && window.authManager.currentUser && 
            window.authManager.currentUser.id === userId) {
            
            // Обновляем все карточки модов на странице
            const modCards = document.querySelectorAll('.mod-card');
            modCards.forEach(card => {
                const isVipMod = card.classList.contains('vip-mod');
                const downloadBtn = card.querySelector('button[onclick*="handleDownloadClick"]');
                
                if (isVipMod) {
                    if (isVip) {
                        // Показываем и активируем VIP элементы
                        card.style.display = 'block';
                        if (downloadBtn) {
                            downloadBtn.disabled = false;
                            downloadBtn.style.background = 'linear-gradient(45deg, #ffd700, #ffed4e)';
                            downloadBtn.style.color = '#000';
                            downloadBtn.textContent = '⬇️ Скачать';
                            downloadBtn.style.cursor = 'pointer';
                            downloadBtn.style.opacity = '1';
                        }
                    } else {
                        // Скрываем или блокируем VIP элементы
                        if (downloadBtn) {
                            downloadBtn.disabled = true;
                            downloadBtn.style.background = 'linear-gradient(45deg, #9e9e9e, #757575)';
                            downloadBtn.style.color = '#fff';
                            downloadBtn.textContent = '🔒 VIP';
                            downloadBtn.style.cursor = 'not-allowed';
                            downloadBtn.style.opacity = '0.6';
                        }
                    }
                }
            });
            
            // Обновляем счетчики модов
            const vipModsCount = document.querySelectorAll('.mod-card.vip-mod').length;
            const totalModsCount = document.querySelectorAll('.mod-card').length;
            
            // Обновляем фильтры
            const vipFilter = document.querySelector('[data-filter="vip"]');
            if (vipFilter) {
                vipFilter.textContent = `VIP (${vipModsCount})`;
            }
            
            console.log(`✅ Моды обновлены: VIP=${vipModsCount}, всего=${totalModsCount}`);
        }
        
        // Обновляем текущую категорию
        const currentCategory = document.querySelector('.category-btn.active')?.dataset.category;
        if (currentCategory && typeof loadModsByCategory === 'function') {
            await loadModsByCategory(currentCategory);
        }
        
        // Если VIP статус активирован, загружаем VIP моды
        console.log('🔍 Проверка условий для загрузки VIP модов:', {
            isVip,
            loadModsByCategoryExists: typeof loadModsByCategory === 'function',
            loadModsByCategoryType: typeof loadModsByCategory
        });
        
        if (isVip && typeof loadModsByCategory === 'function') {
            console.log('💎 Загружаем VIP моды после активации статуса');
            await loadModsByCategory('vip_mods');
        } else {
            console.log('⚠️ VIP моды не загружены. Условия не выполнены:', {
                isVip,
                functionExists: typeof loadModsByCategory === 'function'
            });
        }
        
        // Показываем или скрываем VIP контейнеры в зависимости от статуса
        const vipContainers = document.querySelectorAll('.requires-vip');
        vipContainers.forEach(container => {
            if (isVip) {
                container.style.display = 'block';
                console.log('✅ Показываем VIP контейнер:', container.id);
            } else {
                container.style.display = 'none';
                console.log('❌ Скрываем VIP контейнер:', container.id);
            }
        });
        
        // Сбрасываем блокировку через небольшую задержку
        setTimeout(() => {
            window.updateModsForVipChangeLock = false;
            console.log('🔓 Блокировка updateModsForVipChange сброшена');
        }, 300);
        
    } catch (error) {
        console.error('❌ Ошибка обновления модов:', error);
        
        // Сбрасываем блокировку при ошибке
        window.updateModsForVipChangeLock = false;
        console.log('🔓 Блокировка updateModsForVipChange сброшена из-за ошибки');
    }
};

