/**
 * Устанавливает источник музыки и сохраняет его.
 * @param {string} src - URL аудиофай��а.
 * @param {string} name - Название трека.
 */
function setSiteMusic(src, name) {
    const musicPlayer = document.getElementById('siteMusicPlayer');
    if (!musicPlayer) return;

    musicPlayer.src = src;
    if (siteMusicEnabled) {
        musicPlayer.play().catch(e => console.error('Ошибка воспроизведения нового трека:', e));
    }

    // Сохраняем информацию о треке
    saveToLocalStorage('siteMusicTrack', { src, name });

    // Обновляем UI в админ-панели
    const trackNameEl = document.getElementById('current-track-name');
    if (trackNameEl) {
        trackNameEl.textContent = `Текущий трек: ${name}`;
    }
}

// Функция для перетаскивания элемента
function makeDraggable(element) {
    let offsetX = 0, offsetY = 0;

    // Область для перетаскивания (шапка панели) или вся панель, если шапка не найдена
    const dragHandle = element.querySelector('.admin-panel-header') || element;
    if (!dragHandle) {
        console.error('❌ Не найдена область для перетаскивания (.admin-panel-header)');
        return;
    }

    dragHandle.style.cursor = 'grab';

    dragHandle.onmousedown = dragMouseDown;

    function dragMouseDown(e) {
        e = e || window.event;
        // Игнорируем клики не левой кнопкой мыши и по кнопкам управления
        if (e.button !== 0 || e.target.tagName === 'BUTTON') return;
        e.preventDefault();

        // ������������������������������олучаем начальные координаты элемента
        const rect = element.getBoundingClientRect();
        offsetX = e.clientX - rect.left;
        offsetY = e.clientY - rect.top;

        // 🖱️ ЛОГ НАЧАЛА ПЕРЕТАСКИВАНИЯ
        console.log('🖱️ [DRAG START] Начало перетаскивания админ панели:', {
            startMousePosition: { x: e.clientX, y: e.clientY },
            elementStartPosition: { x: rect.left, y: rect.top },
            elementSize: { width: rect.width, height: rect.height }
        });

        document.onmouseup = closeDragElement;
        document.onmousemove = elementDrag;

        dragHandle.style.cursor = 'grabbing';
        element.style.transition = 'none';
    }

    function elementDrag(e) {
        e = e || window.event;
        e.preventDefault();

        // Новые координаты панели
        let newX = e.clientX - offsetX;
        let newY = e.clientY - offsetY;

        // Ограничиваем перемещение в пределах видимой области окна
        newX = Math.max(0, Math.min(newX, window.innerWidth - element.offsetWidth));
        newY = Math.max(0, Math.min(newY, window.innerHeight - element.offsetHeight));

        // Сбрасываем transform и устанавливаем позицию через top/left
        element.style.transform = 'none';
        element.style.left = newX + 'px';
        element.style.top = newY + 'px';

        // 🖱️ ЛОГИ ПЕРЕМЕЩЕНИЯ АДМИН ПАНЕЛИ МЫШКОЙ
        console.log('🖱️ [DRAG] Перемещение админ панели:', {
            mouseX: e.clientX,
            mouseY: e.clientY,
            newPosition: { x: newX, y: newY },
            elementSize: {
                width: element.offsetWidth,
                height: element.offsetHeight
            },
            windowSize: {
                width: window.innerWidth,
                height: window.innerHeight
            }
        });
    }

    function closeDragElement(e) {
        // Получаем финальные координаты элемента
        const finalRect = element.getBoundingClientRect();
        const finalX = finalRect.left;
        const finalY = finalRect.top;

        // 🖱️ ЛОГ ЗАВЕРШЕНИЯ ПЕРЕТАСКИВАНИЯ
        console.log('🖱️ [DRAG STOP] Завершение перетаскивания админ панели:', {
            finalPosition: { x: finalX, y: finalY },
            finalSize: { width: finalRect.width, height: finalRect.height }
        });

        document.onmouseup = null;
        document.onmousemove = null;

        dragHandle.style.cursor = 'grab';
        element.style.transition = 'all 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94)';
    }
}

// Функция для изменения размера элемента с помощью клавиатуры
function addKeyboardResize(element) {
    document.addEventListener('keydown', function(e) {
        // Проверяем, что фокус не на поле ввода, чтобы не мешать печатать
        if (document.activeElement.tagName === 'INPUT' || document.activeElement.tagName === 'TEXTAREA') {
            return;
        }

        // Используем Alt + стрелки для изменения размера
        if (e.altKey) {
            e.preventDefault();
            const currentWidth = parseInt(element.style.width, 10);
            const currentHeight = parseInt(element.style.height, 10);
            const step = 10; // Ша�� изменения в пикселях

            switch (e.key) {
                case 'ArrowRight':
                    element.style.width = (currentWidth + step) + 'px';
                    break;
                case 'ArrowLeft':
                    element.style.width = (currentWidth - step) + 'px';
                    break;
                case 'ArrowDown':
                    element.style.height = (currentHeight + step) + 'px';
                    break;
                case 'ArrowUp':
                    element.style.height = (currentHeight - step) + 'px';
                    break;
            }
        }
    });
}

