async function updateAdminUserRole() {
    const userRoleElement = document.getElementById('admin-user-role');
    if (!userRoleElement) return;

    if (typeof getUserRole === 'function') {
        const profile = await getUserRole();
        if (profile && profile.role) {
            const userRole = profile.role;
            const username = window.authManager?.currentUser?.user_metadata?.username || window.authManager?.currentUser?.email || 'Пользователь';
            
            const roleIcons = {
                'owner': '👑',
                'admin': '⚡',
                'admin_senior': '💎',
                'moderator': '🛡️',
                'moderator_senior': '🔥',
                'vip': '💎',
                'user': '👤'
            };

            const icon = roleIcons[userRole] || '👤';
            userRoleElement.textContent = `${icon} ${username}`;
            userRoleElement.style.color = '#4fc3f7'; // Голубой цвет для никнейма
        } else {
            const username = window.authManager?.currentUser?.user_metadata?.username || window.authManager?.currentUser?.email || 'Владелец системы';
            userRoleElement.textContent = `👑 ${username}`;
            userRoleElement.style.color = '#4CAF50';
        }

        // Показываем кнопку "Владелец" только для владельца
        // ИСПРАВЛЕНО: Убрана проверка is_owner, так как она может быть true у других ролей.
        // Теперь кнопка будет видна ТОЛЬКО если роль пользователя 'owner'.
        const ownerButtonContainer = document.getElementById('owner-section-button-container');
        if (ownerButtonContainer && profile && profile.role === 'owner') {
            ownerButtonContainer.style.display = 'block';
            ownerButtonContainer.innerHTML = `<button onclick="selectAdminSection('owner_tools')" class="hacker-btn" data-section="owner_tools" style="width: 100%; background: linear-gradient(135deg, #4a0e4e, #880e4f); color: #ffd700; border: 1px solid #ffd700; padding: 6px; border-radius: 4px; margin: 3px 0; cursor: pointer; font-weight: bold; font-size: 0.7rem; text-shadow: 0 0 5px #ffd700; box-shadow: 0 0 10px rgba(255,215,0,0.3); transition: all 0.2s;" onmouseover="this.style.boxShadow='0 0 15px #ffd700'" onmouseout="this.style.boxShadow='0 0 10px rgba(255,215,0,0.3)'">👑 ПАНЕЛЬ ВЛАДЕЛЬЦА</button>`;
            ownerButtonContainer.innerHTML += `<button onclick="selectAdminSection('audit_log')" class="hacker-btn" data-section="audit_log" style="width: 100%; background: linear-gradient(135deg, #4a0e4e, #880e4f); color: #ffd700; border: 1px solid #ffd700; padding: 6px; border-radius: 4px; margin: 3px 0; cursor: pointer; font-weight: bold; font-size: 0.7rem; text-shadow: 0 0 5px #ffd700; box-shadow: 0 0 10px rgba(255,215,0,0.3); transition: all 0.2s;" onmouseover="this.style.boxShadow='0 0 15px #ffd700'" onmouseout="this.style.boxShadow='0 0 10px rgba(255,215,0,0.3)'">📜 ЖУРНАЛ АУДИТА</button>`;
        } else if (ownerButtonContainer) {
            // Явно скрываем контейнер, если пользователь не владелец
            ownerButtonContainer.style.display = 'none';
        }
    } else {
        userRoleElement.textContent = 'Владелец системы';
        userRoleElement.style.color = '#4CAF50';
    }
}

