// Функция возврата назад в админ-панели
function goBackAdmin() {
    if (adminNavHistory.length > 1) {
        adminNavHistory.pop(); // Удаляем текущую страницу из истории
        const previousSection = adminNavHistory[adminNavHistory.length - 1];
        selectAdminSection(previousSection, false); // Переходим на предыдущую, не добавляя в историю
    } else if (adminNavHistory.length === 1) {
        // Если в истории остался только один (главный) раздел, очищаем ее и показываем главный экран
        adminNavHistory = [];
        const contentArea = document.getElementById('admin-content-area');
        if (contentArea) {
            loadDashboardContent();
        }
        // Сбрасываем активные кнопки и скрываем кнопку "Назад"
        selectAdminSection('dashboard', false);
    }
}

