/**
 * Рендерит карточку VIP-плана для админ-панели.
 * @param {object} plan - Объект VIP-плана.
 * @returns {string} HTML-код карточки.
 */
function renderVipPlanCard(plan) {
    // Определяем текущий тип срока и значение (duration_days теперь хранит минуты)
    let durationType = 'days';
    let durationValue = plan.duration_days || 0; // Это минуты!
    
    if (plan.duration_days >= 30.42 * 24 * 60) { // >= 1 месяц в минутах
        durationType = 'months';
        durationValue = Math.round(plan.duration_days / (30.42 * 24 * 60));
    } else if (plan.duration_days >= 24 * 60) { // >= 1 день в минутах
        durationType = 'days';
        durationValue = Math.round(plan.duration_days / (24 * 60));
    } else if (plan.duration_days >= 60) { // >= 1 час в минутах
        durationType = 'hours';
        durationValue = Math.round(plan.duration_days / 60);
    } else { // Меньше часа - минуты
        durationType = 'minutes';
        durationValue = Math.round(plan.duration_days); // Округляем на всякий случай
    }

    return `
        <div class="vip-plan-card" style="background: rgba(156,39,176,0.1); padding: 15px; border-radius: 8px; border: 1px solid rgba(156,39,176,0.3);">
            <div class="form-group" style="margin-bottom: 10px;">
                <label style="font-size: 0.8rem; color: #8892b0;">Название:</label>
                <input type="text" id="plan-name-${plan.id}" value="${plan.name}" class="hacker-input" style="border-color: #9c27b0;">
            </div>
            <div class="form-group" style="margin-bottom: 10px;">
                <label style="font-size: 0.8rem; color: #8892b0;">Описание:</label>
                <input type="text" id="plan-desc-${plan.id}" value="${plan.description || ''}" class="hacker-input" style="border-color: #9c27b0;">
            </div>
            <div class="form-group" style="margin-bottom: 10px;">
                <label style="font-size: 0.8rem; color: #8892b0;">Тип срока:</label>
                <select id="plan-duration-type-${plan.id}" onchange="updatePlanDurationHint('${plan.id}')" class="hacker-input" style="border-color: #9c27b0;">
                    <option value="minutes" ${durationType === 'minutes' ? 'selected' : ''}>Минуты</option>
                    <option value="hours" ${durationType === 'hours' ? 'selected' : ''}>Часы</option>
                    <option value="days" ${durationType === 'days' ? 'selected' : ''}>Дни</option>
                    <option value="months" ${durationType === 'months' ? 'selected' : ''}>Месяцы</option>
                </select>
            </div>
            <div class="form-group" style="margin-bottom: 10px;" id="plan-duration-group-${plan.id}">
                <label style="font-size: 0.8rem; color: #8892b0;">Количество:</label>
                <input type="number" id="plan-duration-value-${plan.id}" value="${durationValue}" min="1" class="hacker-input" style="border-color: #9c27b0;">
                <small id="plan-duration-hint-${plan.id}" style="color: #8892b0; font-size: 0.7rem;">${getDurationHint(durationType)}</small>
            </div>
            <div style="display: flex; gap: 10px; margin-bottom: 10px;">
                <div class="form-group" style="flex: 1;">
                    <label style="font-size: 0.8rem; color: #8892b0;">Цена (₽):</label>
                    <input type="number" id="plan-price-${plan.id}" value="${plan.price}" class="hacker-input" style="border-color: #9c27b0;">
                </div>
                <div class="form-group" style="flex: 1;">
                    <label style="font-size: 0.8rem; color: #8892b0;">Старая цена (₽):</label>
                    <input type="number" id="plan-old-price-${plan.id}" value="${plan.old_price || ''}" class="hacker-input" style="border-color: #9c27b0;">
                </div>
            </div>
            <div style="display: flex; justify-content: space-between; align-items: center; margin-top: 10px;">
                <div style="display: flex; align-items: center; gap: 8px;">
                    <label for="plan-active-${plan.id}" class="hacker-switch">
                        <input type="checkbox" id="plan-active-${plan.id}" ${plan.is_active !== false ? 'checked' : ''} onchange="toggleVipPlanActive('${plan.id}', this.checked)">
                        <span class="slider round"></span>
                    </label>
                    <span style="color: #4CAF50; font-size: 0.8rem; font-weight: bold;">Активен</span>
                </div>
                <div style="display: flex; gap: 8px;">
                    <button onclick="deleteVipPlan('${plan.id}')" class="hacker-btn" style="background: #f44336; padding: 8px 16px; font-size: 0.8rem;">🗑️ Удалить</button>
                    <button onclick="saveVipPlan('${plan.id}')" class="hacker-btn" style="background: #4CAF50;">Сохранить</button>
                </div>
            </div>
        </div>
    `;
}

/**
 * Возвращает подсказку для типа срока.
 */
function getDurationHint(type) {
    switch(type) {
        case 'minutes': return 'Укажите количество минут (от 1 до 60)';
        case 'hours': return 'Укажите количество часов (от 1 до 24)';
        case 'days': return 'Укажите количество дней (от 1 до 365)';
        case 'months': return 'Укажите количество месяцев (от 1 до 12, 12 мес = 1 год)';
        default: return '';
    }
}

/**
 * Обновляет подсказку для срока действия плана.
 */
function updatePlanDurationHint(planId) {
    const type = document.getElementById(`plan-duration-type-${planId}`).value;
    const hint = document.getElementById(`plan-duration-hint-${planId}`);
    const valueInput = document.getElementById(`plan-duration-value-${planId}`);
    
    hint.textContent = getDurationHint(type);
    
    // Обновляем placeholder и ограничения
    switch(type) {
        case 'minutes':
            valueInput.placeholder = '60';
            valueInput.min = '1';
            valueInput.max = '60';
            break;
        case 'hours':
            valueInput.placeholder = '24';
            valueInput.min = '1';
            valueInput.max = '24';
            break;
        case 'days':
            valueInput.placeholder = '7';
            valueInput.min = '1';
            valueInput.max = '365';
            break;
        case 'months':
            valueInput.placeholder = '1';
            valueInput.min = '1';
            valueInput.max = '12';
            break;
    }
}

/**
 * Сохраняет изменения в VIP-плане.
 */
async function saveVipPlan(planId) {
    const name = document.getElementById(`plan-name-${planId}`).value;
    const description = document.getElementById(`plan-desc-${planId}`).value;
    const price = parseFloat(document.getElementById(`plan-price-${planId}`).value);
    const old_price = parseFloat(document.getElementById(`plan-old-price-${planId}`).value) || null;
    const durationType = document.getElementById(`plan-duration-type-${planId}`).value;
    const durationValue = document.getElementById(`plan-duration-value-${planId}`).value;
    const isActive = document.getElementById(`plan-active-${planId}`).checked;

    if (!name || isNaN(price)) {
        showNotification('❌ Название и цена обязательны!', 'error');
        return;
    }

    if (!durationValue || parseInt(durationValue) < 1) {
        showNotification('❌ Укажите корректный срок действия!', 'error');
        return;
    }

    // Расчет срока в минутах (duration_days теперь хранит минуты)
    let durationDays = null;
    
    switch(durationType) {
        case 'minutes':
            durationDays = parseInt(durationValue); // Минуты
            break;
        case 'hours':
            durationDays = parseInt(durationValue) * 60; // Часы в минуты
            break;
        case 'days':
            durationDays = parseInt(durationValue) * 24 * 60; // Дни в минуты
            break;
        case 'months':
            durationDays = parseInt(durationValue) * 30.42 * 24 * 60; // Месяцы в минуты
            break;
    }

    try {
        const { error } = await window.supabase
            .from('products')
            .update({ 
                name, 
                description, 
                price, 
                old_price, 
                duration_days: durationDays,
                is_active: isActive
            })
            .eq('id', planId);

        if (error) throw error;
        showNotification('✅ VIP-план успешно сохранен!', 'success');
    } catch (err) {
        showNotification(`❌ Ошибка сохранения: ${err.message}`, 'error');
    }
}

/**
 * Удаляет VIP-план.
 */
async function deleteVipPlan(planId) {
    try {
        // Проверяем, есть ли связанные заказы
        const { data: orders, error: checkError } = await window.supabase
            .from('orders')
            .select('id')
            .eq('product_id', planId)
            .limit(1);

        if (checkError) throw checkError;

        if (orders && orders.length > 0) {
            showNotification('❌ Нельзя удалить VIP-план, так как есть связанные заказы! Сначала деактивируйте план.', 'error');
            return;
        }

        if (!confirm('⚠️ Вы уверены, что хотите удалить этот VIP-план? Это действие нельзя отменить!')) {
            return;
        }

        const { error } = await window.supabase
            .from('products')
            .delete()
            .eq('id', planId);

        if (error) throw error;
        
        showNotification('✅ VIP-план успешно удален!', 'success');
        
        // Обновляем список планов
        showShopManagement();
    } catch (err) {
        showNotification(`❌ Ошибка удаления: ${err.message}`, 'error');
    }
}

/**
 * Переключает активность VIP-плана.
 */
async function toggleVipPlanActive(planId, isActive) {
    try {
        const { error } = await window.supabase
            .from('products')
            .update({ is_active: isActive })
            .eq('id', planId);

        if (error) throw error;
        
        showNotification(`✅ Статус плана изменен на: ${isActive ? 'Активен' : 'Отключен'}`, 'success');
    } catch (err) {
        showNotification(`❌ Ошибка изменения статуса: ${err.message}`, 'error');
    }
}

/**
 * Обновляет поле ввода срока в зависимости от выбранного типа
 */
function updateDurationInput() {
    const type = document.getElementById('new-plan-duration-type').value;
    const valueGroup = document.getElementById('duration-value-group');
    const valueInput = document.getElementById('new-plan-duration-value');
    const hint = document.getElementById('duration-hint');
    
    if (type === 'unlimited') {
        valueGroup.style.display = 'none';
    } else {
        valueGroup.style.display = 'block';
        
        switch(type) {
            case 'minutes':
                hint.textContent = 'Укажите количество минут (от 1 до 60)';
                valueInput.placeholder = '60';
                valueInput.min = '1';
                valueInput.max = '60';
                break;
            case 'hours':
                hint.textContent = 'Укажите количество часов (от 1 до 24)';
                valueInput.placeholder = '24';
                valueInput.min = '1';
                valueInput.max = '24';
                break;
            case 'days':
                hint.textContent = 'Укажите количество дней (от 1 до 365)';
                valueInput.placeholder = '7';
                valueInput.min = '1';
                valueInput.max = '365';
                break;
            case 'months':
                hint.textContent = 'Укажите количество месяцев (от 1 до 12, 12 мес = 1 год)';
                valueInput.placeholder = '1';
                valueInput.min = '1';
                valueInput.max = '12';
                break;
        }
    }
}

