/**
 * Добавляет новый VIP-план в базу данных.
 */
async function addNewVipPlan() {
    const name = document.getElementById('new-plan-name').value.trim();
    const description = document.getElementById('new-plan-description').value.trim();
    const durationType = document.getElementById('new-plan-duration-type').value;
    const durationValue = document.getElementById('new-plan-duration-value').value;
    const price = parseFloat(document.getElementById('new-plan-price').value);
    const oldPrice = document.getElementById('new-plan-old-price').value;
    const isActive = document.getElementById('new-plan-active').checked;

    // Валидация
    if (!name) {
        showNotification('❌ Укажите название плана!', 'error');
        return;
    }
    
    if (isNaN(price) || price < 0) {
        showNotification('❌ Укажите корректную цену!', 'error');
        return;
    }
    
    if (!durationValue || parseInt(durationValue) < 1) {
        showNotification('❌ Укажите корректный срок действия!', 'error');
        return;
    }

    // Расчет срока в минутах (хранится как целые числа в duration_days)
    let durationDays = null; // На самом деле это минуты!
    let durationText = '';
    
    switch(durationType) {
        case 'minutes':
            durationDays = parseInt(durationValue); // Храним минуты как есть
            durationText = `${durationValue} мин.`;
            break;
        case 'hours':
            durationDays = parseInt(durationValue) * 60; // Храним часы в минутах
            durationText = `${durationValue} час(ов)`;
            break;
        case 'days':
            durationDays = parseInt(durationValue) * 24 * 60; // Храним дни в минутах
            durationText = `${durationValue} дн.`;
            break;
        case 'months':
            durationDays = Math.round(parseInt(durationValue) * 30.42 * 24 * 60); // Храним месяцы в минутах
            durationText = `${durationValue} мес.`;
            break;
    }

    try {
        const productData = {
            name: name,
            description: description || `VIP-статус на ${durationText}`,
            category: 'vip',
            price: price,
            duration_days: durationDays,
            is_active: isActive
        };
        
        // Добавляем старую цену только если она указана
        if (oldPrice && !isNaN(oldPrice) && parseFloat(oldPrice) > price) {
            productData.old_price = parseFloat(oldPrice);
        }

        console.log('🔍 [DEBUG] Данные для создания VIP-плана:', productData);
        console.log('🔍 [DEBUG] Тип duration_days:', typeof durationDays, 'Значение:', durationDays);

        const { data, error } = await window.supabase.from('products').insert(productData);

        if (error) {
            console.error('🔍 [DEBUG] Ошибка Supabase:', error);
            console.error('🔍 [DEBUG] Детали ошибки:', {
                message: error.message,
                details: error.details,
                hint: error.hint,
                code: error.code
            });
            throw error;
        }

        console.log('✅ [DEBUG] VIP-план успешно создан:', data);

        showNotification('✅ Новый VIP-план успешно добавлен!', 'success');
        document.querySelector('.auth-modal').remove();
        showShopManagement(); // Обновляем список планов
    } catch (err) {
        showNotification(`❌ Ошибка добавления: ${err.message}`, 'error');
    }
}

