// Функция поиска пользователей для сброса пароля
async function searchUsersForReset(query) {
    const searchResults = document.getElementById('searchResults');
    if (!searchResults) return;

    if (!query || query.length < 2) {
        searchResults.innerHTML = '<p style="color: #8892b0; text-align: center; margin: 0; font-size: 13px;">Начните вводить имя пользователя или email</p>';
        return;
    }

    try {
        console.log('🔍 Поиск пользователей для сброса пароля:', query);

        // Проверяем доступность supabase
        if (typeof supabase === 'undefined') {
            throw new Error('Supabase клиент не инициализирован');
        }

        // Ищем пользователей по username или email
        const { data: users, error } = await window.supabase
            .from('profiles')
            .select('*')
            .or(`username.ilike.%${query}%,email.ilike.%${query}%`)
            .limit(10);

        if (error) {
            console.error('❌ Ошибка поиска пользователей:', error);
            searchResults.innerHTML = `<p style="color: #f44336; text-align: center; margin: 0; font-size: 13px;">Ошибка поиска: ${error.message}</p>`;
            return;
        }

        if (!users || users.length === 0) {
            searchResults.innerHTML = '<p style="color: #8892b0; text-align: center; margin: 0; font-size: 13px;">Пользователи не найдены</p>';
            return;
        }

        let resultsHtml = '';

        users.forEach(user => {
            const roleBadge = getRoleBadge(user.role, user.vip_expires_at);
            const statusColor = user.is_banned ? '#f44336' : '#4caf50';
            const statusText = user.is_banned ? 'Заблокирован' : 'Активен';

            resultsHtml += `
                <div style="background: rgba(79, 195, 247, 0.1); padding: 10px; margin: 5px 0; border-radius: 5px; border-left: 3px solid #4fc3f7;">
                    <div style="display: flex; justify-content: space-between; align-items: center;">
                        <div style="flex: 1;">
                            <div style="display: flex; align-items: center; gap: 8px; margin-bottom: 5px;">
                                <strong style="color: #4fc3f7;">${user.username || 'Без имени'}</strong>
                                ${roleBadge}
                            </div> 
                            <span style="color: #8892b0; font-size: 12px;">${user.email}</span>
                            <div style="margin-top: 3px;">
                                <span style="color: ${statusColor}; font-size: 11px; font-weight: bold;">${statusText}</span>
                            </div>
                        </div>
                        <button onclick="resetUserPassword('${user.email}')" style="background: #ff9800; color: white; border: none; padding: 6px 12px; border-radius: 4px; cursor: pointer; font-size: 12px; font-weight: bold;">
                            🔑 Сбросить пароль
                        </button>
                    </div>
                </div>
            `;
        });

        searchResults.innerHTML = resultsHtml;
        console.log(`✅ Найдено пользователей: ${users.length}`);

    } catch (error) {
        console.error('❌ Критическая ошибка поиска:', error);
        searchResults.innerHTML = `<p style="color: #f44336; text-align: center; margin: 0; font-size: 13px;">Критическая ошибка: ${error.message}</p>`;
    }
}

// Функция сброса пароля пользователя админом
async function resetUserPassword(userEmail) {
    if (!userEmail) {
        showNotification('❌ Email пользователя не указан', 'error');
        return;
    }

    if (!confirm(`Вы уверены что хотите сбросить пароль для пользователя ${userEmail}?`)) {
        return;
    }

    try {
        // Проверяем доступность supabase
            if (typeof supabase === 'undefined' || !supabase) {
            throw new Error('Supabase клиент не инициализирован');
        }

        console.log('🔑 Сбрасываем пароль для пользователя:', userEmail);

        // Отправляем сброс пароля через Supabase
        const { error } = await window.supabase.auth.resetPasswordForEmail(userEmail, {
            redirectTo: window.location.origin + '/reset-password.html'
        });

        if (error) {
            console.error('❌ Ошибка сброса пароля:', error);

            let errorMessage = 'Произошла ошибка при сбросе пароля';
            if (error.message.includes('Email not confirmed')) {
                errorMessage = 'Email адрес не под��ве��жд��н';
            } else if (error.message.includes('Invalid email')) {
                errorMessage = 'Неверный формат email адреса';
            } else if (error.message.includes('User not found')) {
                errorMessage = 'Пользователь не найден';
            }

            showNotification(`❌ ${errorMessage}`, 'error');
            return;
        }

        showNotification(`✅ Инструкции по сбросу пароля отправлены на ${email}`, 'success');

        // Очищаем поле поиска
        const searchInput = document.getElementById('searchUserInput');
        if (searchInput) {
            searchInput.value = '';
            searchUsersForReset(''); // Показываем пустой результат
        }

        console.log('✅ Пароль ��спешно сброшен дл��:', email);

    } catch (error) {
        console.error('❌ Критическая ошибка сброса пароля:', error);
        showNotification('❌ Критическая ошибка сброса пароля', 'error');
    }
}

// Функция отправки сброса пароля на email
async function sendPasswordReset() {
    const email = document.getElementById('resetEmail').value;
    const resetMessage = document.getElementById('resetMessage');

    if (!email) {
        showResetMessage('Пожалуйста, введите email адрес', 'error');
        return;
    }

    if (!isValidEmail(email)) {
        showResetMessage('Пожалуйста, введите корректный email адрес', 'error');
        return;
    }

    try {
        // Показываем индикатор загрузки
        const submitButton = document.querySelector('#passwordResetModal button[onclick="sendPasswordReset()"]');
        const originalText = submitButton.textContent;
        submitButton.textContent = '⏳ Отправляем...';
        submitButton.disabled = true;

        // Проверяем доступность supabase
        if (typeof supabase === 'undefined') {
            throw new Error('Supabase клиент не инициализирован');
        }

        // Отправляем запрос на сброс пароля через Supabase
        const { error } = await window.supabase.auth.resetPasswordForEmail(email, {
            redirectTo: window.location.origin + '/reset-password.html'
        });

        if (error) {
            console.error('❌ Ошибка сброса пароля:', error);

            let errorMessage = 'Произошла ошибка при сбросе пароля';
            if (error.message.includes('Email not confirmed')) {
                errorMessage = 'Email адрес не подтвержден';
            } else if (error.message.includes('Invalid email')) {
                errorMessage = 'Неверный формат email адреса';
            } else if (error.message.includes('User not found')) {
                errorMessage = 'Пользователь не найден';
            }

            showNotification(`❌ ${errorMessage}`, 'error');
            return;
        }

        showNotification(`✅ Инструкции по сбросу пароля отправлены на ${email}`, 'success');

        // Очищаем поле поиска
        const searchInput = document.getElementById('searchUserInput');
        if (searchInput) {
            searchInput.value = '';
            searchUsersForReset(''); // Показываем пустой результат
        }

        console.log('✅ Пароль успешно сброшен для:', userEmail);

    } catch (error) {
        console.error('❌ Критическая ошибка сброса пароля:', error);
        showNotification('❌ Критическая ошибка сброса пароля', 'error');
    }
}

// Функция показа сообщения в форме сброса пароля
function showResetMessage(message, type) {
    const resetMessage = document.getElementById('resetMessage');
    if (resetMessage) {
        resetMessage.textContent = message;
        resetMessage.style.display = 'block';

        if (type === 'error') {
            resetMessage.style.background = 'rgba(244, 67, 54, 0.1)';
            resetMessage.style.border = '1px solid rgba(244, 67, 54, 0.3)';
            resetMessage.style.color = '#f44336';
        } else if (type === 'success') {
            resetMessage.style.background = 'rgba(76, 175, 80, 0.1)';
            resetMessage.style.border = '1px solid rgba(76, 175, 80, 0.3)';
            resetMessage.style.color = '#4caf50';
        }

        // Анимация появления
        resetMessage.style.animation = 'fadeInUp 0.3s ease';
    }
}

