// Поиск пользователя для выдачи VIP
window.searchUserForVip = async function() {
    const email = document.getElementById('vipUserEmailInput').value.trim().toLowerCase();
    
    if (!email) {
        showNotification('❌ Введите email пользователя', 'error', 3000);
        return;
    }

    try {
        const { data: user, error } = await supabase
            .from('profiles')
            .select('id, username, email, role, is_vip, vip_expires_at')
            .eq('email', email)
            .single();

        if (error || !user) {
            showNotification('❌ Пользователь с таким email не найден', 'error', 3000);
            return;
        }

        // Показываем информацию о пользователе
        const userInfoDiv = document.getElementById('vip-user-info');
        const userDetailsDiv = document.getElementById('vip-user-details');
        
        if (user.is_vip || user.role === 'vip') {
            userDetailsDiv.innerHTML = `
                <div style="color: #ffd700 !important;">💎 ${user.username || user.email}</div>
                <div style="color: #ff9800 !important; margin-top: 5px;">⚠️ Уже имеет VIP статус</div>
            `;
            userInfoDiv.style.display = 'block';
            userInfoDiv.style.background = 'rgba(255, 152, 0, 0.1)';
            userInfoDiv.style.borderColor = 'rgba(255, 152, 0, 0.3)';
            document.getElementById('confirmVipBtn').style.display = 'none';
        } else {
            userDetailsDiv.innerHTML = `
                <div style="color: #00ff41 !important;">💎 ${user.username || user.email}</div>
                <div style="color: #ccc !important; margin-top: 5px;">📧 ${user.email}</div>
                <div style="color: #2196F3 !important; margin-top: 5px;">🎭 Роль: ${user.role || 'user'}</div>
            `;
            userInfoDiv.style.display = 'block';
            userInfoDiv.style.background = 'rgba(0, 255, 65, 0.1)';
            userInfoDiv.style.borderColor = 'rgba(0, 255, 65, 0.3)';
            document.getElementById('confirmVipBtn').style.display = 'block';
            
            // Сохраняем ID пользователя для последующей выдачи
            window.selectedVipUserId = user.id;
        }

    } catch (error) {
        console.error('Ошибка поиска пользователя:', error);
        showNotification('❌ Ошибка поиска пользователя', 'error', 3000);
    }
};

// Подтверждение выдачи VIP администратором
window.confirmGiveVipByAdmin = async function() {
    const password = document.getElementById('vipAdminPasswordInput').value;
    const userId = window.selectedVipUserId;

    if (!password) {
        showNotification('❌ Введите VIP пароль', 'error', 3000);
        return;
    }

    if (!userId) {
        showNotification('❌ Пользователь не выбран', 'error', 3000);
        return;
    }

    try {
        // Получаем текущий VIP пароль из localStorage
        let currentVipPassword = localStorage.getItem('vip_password') || 'VIP2026KEROS';

        // Проверяем VIP пароль
        if (password !== currentVipPassword) {
            showNotification('❌ Неверный VIP пароль! Доступ запрещен.', 'error', 3000);
            return;
        }

        // Выдаем VIP статус
        const { error } = await supabase
            .from('profiles')
            .update({
                is_vip: true,
                role: 'vip',
                vip_expires_at: null // Бессрочный VIP
            })
            .eq('id', userId);

        if (error) throw error;

        showNotification('✅ VIP статус успешно выдан!', 'success', 3000);
        
        // Закрываем модальное окно
        const modal = document.querySelector('.vip-give-modal');
        if (modal) modal.remove();

        // Обновляем список пользователей
        if (typeof showVipUsersList === 'function') {
            showVipUsersList();
        }

        // Логируем в аудит
        console.log(`✅ VIP выдан пользователю ID: ${userId}`);

    } catch (error) {
        console.error('Ошибка выдачи VIP:', error);
        showNotification('❌ Ошибка выдачи VIP статуса', 'error', 3000);
    }
};

