// Функция подтверждения выдачи VIP
window.confirmGiveVip = async function(userId) {
    const password = document.getElementById('vipPasswordInput').value;
    
    if (!password) {
        showNotification('❌ Введите VIP пароль', 'error', 3000);
        return;
    }
    
    try {
        // Получаем текущий VIP пароль из localStorage (временное решение)
        let currentVipPassword = localStorage.getItem('vip_password') || 'VIP2026KEROS';
        
        // console.log('🔑 [confirmGiveVip] VIP пароль из localStorage:', currentVipPassword);
        // console.log('🔑 [confirmGiveVip] Введенный пароль:', password);
        // console.log('🔑 [confirmGiveVip] Текущий пароль для сравнения:', currentVipPassword);
        
        // Проверяем VIP пароль
        if (password !== currentVipPassword) {
            // console.log('❌ [confirmGiveVip] Пароли не совпадают!');
            showNotification('❌ Неверный VIP пароль! Доступ запрещен.', 'error', 3000);
            return;
        }

        // Получаем данные пользователя
        const { data: profile, error: profileError } = await window.supabase
            .from('profiles')
            .select('*')
            .eq('id', userId)
            .single();

        if (profileError) throw profileError;

        // 🔧 ИСПРАВЛЕНИЕ: Обновляем все VIP поля
        const { error: updateError } = await window.supabase
            .from('profiles')
            .update({
                role: 'vip',
                is_vip: true,
                vip_started_at: new Date().toISOString(),
                vip_expires_at: new Date(Date.now() + 60 * 60 * 1000).toISOString(), // 1 час
                updated_at: new Date().toISOString()
            })
            .eq('id', userId);

        if (updateError) throw updateError;

        console.log('✅ [confirmGiveVip] VIP статус обновлён в БД:', {
            user_id: userId,
            role: 'vip',
            is_vip: true,
            vip_started_at: new Date().toISOString(),
            vip_expires_at: new Date(Date.now() + 60 * 60 * 1000).toISOString()
        });
        
        // Логирование отключено (таблица admin_logs не существует)
        console.log('📝 [confirmGiveVip] VIP статус присвоен пользователю:', profile.username || profile.email);

        // Закрываем модальное окно
        document.querySelector('.vip-modal')?.remove();

        // Показываем уведомление
        showNotification(`💎 Пользователю ${profile.username || profile.email} присвоен VIP-статус`, 'success', 3000);

        // 🔧 ИСПРАВЛЕНИЕ: Перезагружаем страницу через 3 секунды для применения VIP статуса
        // Это гарантирует, что все компоненты (VIP кнопка, категории, моды) корректно инициализируются
        showNotification('🔄 Страница будет перезагружена для применения VIP статуса...', 'info', 3000);
        setTimeout(() => {
            window.location.reload();
        }, 3000);

        // Обновляем список пользователей
        if (typeof loadUsersList === 'function') {
            loadUsersList();
        }
        
        // Отправляем broadcast об обновлении роли
        if (window.supabase) {
            try {
                const channel = window.supabase.channel('role_changes');
                await channel.send({
                    type: 'broadcast',
                    event: 'role_updated',
                    payload: {
                        user_id: userId,
                        new_role: 'vip',
                        old_role: profile.role,
                        username: profile.username || profile.email,
                        timestamp: Date.now()
                    }
                });
            } catch (error) {
                console.log('🔄 [confirmGiveVip] Не удалось отправить событие:', error.message);
            }
        }
        
        // Альтернативная синхронизация через localStorage
        localStorage.setItem('role_update_' + userId, JSON.stringify({
            user_id: userId,
            new_role: 'vip',
            old_role: profile.role,
            username: profile.username || profile.email,
            timestamp: Date.now()
        }));
        
        // Обновляем статистику после изменения роли
        setTimeout(() => {
            refreshAllStats();
        }, 500);
        
    } catch (error) {
        console.error('❌ [confirmGiveVip] Ошибка:', error);
        showNotification('❌ Ошибка при присвоении VIP-статуса: ' + error.message, 'error', 5000);
    }
};

