/**
 * Обновляет отображение статистики с плавной анимацией
 */
function updateStatisticDisplay(elementId, value) {
    console.log(`📊 Обновление элемента ${elementId}:`, { found: !!document.getElementById(elementId), value });
    const element = document.getElementById(elementId);
    if (element) {
        // Защита от undefined значений
        const displayValue = value !== undefined && value !== null ? value : 0;
        const oldValue = parseInt(element.textContent) || 0;
        const newValue = parseInt(displayValue) || 0;
        
        // Плавная анимация изменения числа
        if (oldValue !== newValue) {
            const duration = 500; // 0.5 секунды
            const steps = 20;
            const increment = (newValue - oldValue) / steps;
            let currentStep = 0;
            
            const animation = setInterval(() => {
                currentStep++;
                const currentValue = Math.round(oldValue + increment * currentStep);
                element.textContent = currentValue;
                
                if (currentStep >= steps) {
                    clearInterval(animation);
                    element.textContent = newValue;
                    
                    // Добавляем подсветку при завершении
                    element.style.color = '#00ff41';
                    element.style.textShadow = '0 0 10px #00ff41';
                    setTimeout(() => {
                        element.style.color = '';
                        element.style.textShadow = '';
                    }, 200);
                }
            }, duration / steps);
        }
    }
}

// Экспортируем функцию в глобальную область видимости
window.updateStatisticDisplay = updateStatisticDisplay;

