/**
 * Показывает детальную информацию о пользователях по категориям
 */
async function showUserCategoryDetails(category) {
    try {
        console.log(`🔍 Загрузка детальной информации по категории: ${category}`);
        showNotification(`🔍 Загрузка информации...`, 'info', 2000);
        
        // Получаем всех пользователей
        const { data: allUsers, error: allError } = await supabase
            .from('profiles')
            .select('*');
            
        if (allError) throw allError;
        
        const now = new Date(); // Текущее время
        
        // Фильтруем пользователей по категории
        let filteredUsers = [];
        let categoryTitle = '';
        let categoryColor = '';
        
        switch(category) {
            case 'total':
                filteredUsers = allUsers;
                categoryTitle = '👥 Все пользователи';
                categoryColor = '#2196F3';
                break;
                        case 'vip':
                filteredUsers = allUsers.filter(u => u.role === 'vip' || u.is_vip);
                categoryTitle = '💎 VIP пользователи';
                categoryColor = '#ffd700';
                break;
            case 'banned':
                filteredUsers = allUsers.filter(u => u.is_banned);
                categoryTitle = '🚫 Заблокированные пользователи';
                categoryColor = '#f44336';
                break;
            case 'admin':
                filteredUsers = allUsers.filter(u => ['admin', 'admin_senior', 'owner'].includes(u.role));
                categoryTitle = '⚡ Администраторы';
                categoryColor = '#9c27b0';
                break;
            case 'moderator':
                filteredUsers = allUsers.filter(u => ['moderator', 'moderator_senior'].includes(u.role));
                categoryTitle = '🛡️ Модераторы';
                categoryColor = '#ff9800';
                break;
            case 'new':
                const sevenDaysAgo = new Date();
                sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
                filteredUsers = allUsers.filter(u => {
                    const createdAt = new Date(u.created_at);
                    return createdAt > sevenDaysAgo;
                });
                categoryTitle = '🆕 Новые пользователи (7 дней)';
                categoryColor = '#00bcd4';
                break;
            case 'active':
                const thirtyDaysAgo = new Date();
                thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
                filteredUsers = allUsers.filter(u => {
                    const updatedTime = new Date(u.updated_at || u.created_at);
                    return updatedTime > thirtyDaysAgo;
                });
                categoryTitle = '🔥 Активные пользователи (30 дней)';
                categoryColor = '#ff5722';
                break;
        }
        
        // Получаем дополнительную статистику
        const stats = await getCategoryStats(filteredUsers, category);
        
        // Показываем модальное окно с детальной информацией
        showUserListModal(filteredUsers, categoryTitle, categoryColor, stats);
        
    } catch (error) {
        console.error('❌ Ошибка загрузки детальной информации:', error);
        showNotification('❌ Ошибка загрузки информации', 'error');
    }
}

/**
 * Получает статистику по категории пользователей (НОВАЯ ВЕРСИЯ)
 */
async function getCategoryStats(users, category) {
    let vipCount = 0;
    
    users.forEach(user => {
        // VIP статус
        if (user.is_vip || user.role === 'vip') {
            vipCount++;
        }
    });
    
    const stats = {
        total: users.length,
        vip: vipCount,
        banned: users.filter(u => u.is_banned).length,
        commentBanned: 0,
        totalDownloads: 0,
        avgDownloads: 0
    };
    
    // Получаем информацию о блокировках комментариев
    if (users.length > 0) {
        const userIds = users.map(u => u.id).filter(id => id);
        if (userIds.length > 0) {
            const now = new Date().toISOString();

            // Запрос 1: Бессрочные блокировки (ends_at is null)
            let commentBans = [];
            const { data: nullCommentBans, error: nullBansError } = await supabase
                .from('comment_bans')
                .select('user_id')
                .is('ends_at', null)
                .in('user_id', userIds);

            if (!nullBansError && nullCommentBans && nullCommentBans.length > 0) {
                commentBans = nullCommentBans;
            } else {
                // Запрос 2: Активные блокировки (ends_at > now)
                const { data: activeCommentBans, error: activeBansError } = await supabase
                    .from('comment_bans')
                    .select('user_id')
                    .gt('ends_at', now)
                    .in('user_id', userIds);

                if (!activeBansError && activeCommentBans) {
                    commentBans = activeCommentBans;
                }
            }

            if (commentBans) {
                stats.commentBanned = commentBans.length;
            }
        }
    }
    
    stats.totalDownloads = users.reduce((sum, user) => sum + (user.downloads_count || 0), 0);
    stats.avgDownloads = users.length > 0 ? Math.round(stats.totalDownloads / users.length) : 0;
    
    return stats;
}

