// Функция для получения описания категории
function getCategoryDescription(title) {
    const descriptions = {
        '👥 Все пользователи': 'Всего пользователей',
        '💎 VIP пользователи': 'VIP пользователей',
        '🚫 Заблокированные пользователи': 'Заблокировано',
        '⚡ Администраторы': 'Администраторов',
        '🛡️ Модераторы': 'Модераторов',
        '🆕 Новые пользователи (7 дней)': 'Новых',
        '🔥 Активные пользователи (30 дней)': 'Активных'
    };
    
    return descriptions[title] || 'Пользователей';
}

/**
 * Закрывает модальное окно с детальной информацией
 */
function closeUserListModal() {
    const modal = document.getElementById('user-details-modal');
    if (modal) {
        modal.remove();
        // Восстанавливаем прокрутку основного контента
        document.body.style.overflow = '';
    }
}

