/**
 * Показывает только заблокированных пользователей.
 */
async function showBannedUsersList() {
    const contentArea = document.getElementById('admin-content-area');
    if (!contentArea) return;

    // Добавляем кнопку "Назад"
    const backButtonHtml = `
        <div style="margin-bottom: 15px; text-align: left;">
            <button onclick="showUsersManagement()" style="
                background: linear-gradient(135deg, #00ff41, #00dd41);
                color: #000;
                border: none;
                padding: 10px 20px;
                border-radius: 8px;
                cursor: pointer;
                font-weight: bold;
                font-size: 0.9rem;
                box-shadow: 0 2px 4px rgba(0, 255, 65, 0.3);
            " onmouseover="this.style.transform='scale(1.05)'" onmouseout="this.style.transform='scale(1)'">
                ← Назад к пользователям
            </button>
        </div>
    `;

    contentArea.innerHTML = `
        ${backButtonHtml}
        <div style="color: #f44336; padding: 10px;">🚫 Загрузка черного списка...</div>
    `;
    showNotification('🚫 Загрузка черного списка...', 'info', 2000);

    try {
        const { data: users, error } = await supabase
            .from('profiles')
            .select('*')
            .not('banned_until', 'is', null)
            .order('created_at', { ascending: false });

        if (error) throw error;

        // Получаем информацию об администраторах для отображения имен
        const adminIds = [...new Set(users.map(u => u.banned_by).filter(Boolean))];
        const { data: admins } = adminIds.length > 0 ? 
            await supabase
                .from('profiles')
                .select('id, username, email, role')
                .in('id', adminIds) : 
            { data: [], error: null };

        let listHtml = `
        ${backButtonHtml}
        <h5 style="color: #f44336; text-align: center; margin-bottom: 15px;">🚫 Заблокированные пользователи (${users.length})</h5>
    `;

        if (users.length === 0) {
            listHtml += `<div style="color: #00ff41; padding: 1rem; text-align: center;">Черный список пуст.</div>`;
            contentArea.innerHTML = listHtml;
            return;
        }

        // Здесь будет логика рендеринга списка заблокированных пользователей
        // Горизонтальный формат в одну строку
        listHtml += '<div style="display: flex; flex-direction: column; gap: 8px;">';
        users.forEach(user => {
            // Вычисляем оставшееся время блокировки
            let banDuration = 'Навсегда';
            if (user.banned_until) {
                const banUntilDate = new Date(user.banned_until);
                const now = new Date();
                if (banUntilDate > now) {
                    const remainingMs = banUntilDate.getTime() - now.getTime();
                    const remainingDays = Math.ceil(remainingMs / (1000 * 60 * 60 * 24));
                    if (remainingDays === 1) {
                        banDuration = '1 день';
                    } else if (remainingDays < 30) {
                        banDuration = `${remainingDays} дней`;
                    } else if (remainingDays < 365) {
                        const months = Math.floor(remainingDays / 30);
                        banDuration = `${months} мес.`;
                    } else {
                        const years = Math.floor(remainingDays / 365);
                        banDuration = `${years} год${years > 1 ? 'а' : ''}`;
                    }
                }
            }
            
            // Находим информацию о том, кто заблокировал
            let bannedByInfo = 'Неизвестно';
            if (user.banned_by && admins) {
                const admin = admins.find(a => a.id === user.banned_by);
                if (admin) {
                    const roleDisplay = {
                        'owner': 'ВЛАДЕЛЕЦ',
                        'admin_senior': 'СТАРШИЙ АДМИН', 
                        'admin': 'АДМИН',
                        'moderator': 'МОДЕРАТОР'
                    }[admin.role] || 'АДМИН';
                    bannedByInfo = `${admin.username || admin.email} (${roleDisplay})`;
                }
            }
            
            listHtml += `
                <div style="
                    background: rgba(244, 67, 54, 0.1); 
                    border: 1px solid #f44336; 
                    border-radius: 6px; 
                    padding: 8px 12px; 
                    color: #ff9800;
                    display: flex;
                    align-items: center;
                    gap: 15px;
                    font-size: 12px;
                ">
                    <span style="color: #00ccff; font-weight: bold;">${user.email}</span>
                    <span style="color: #fff; font-weight: bold;">${user.username || 'Без имени'}</span>
                    <span style="color: #ffd700;">Причина: ${user.ban_reason || 'не указана'}</span>
                    <span style="color: #ffd700;">⏰ ${banDuration}</span>
                    <div style="
                        background: #f44336; 
                        color: white; 
                        padding: 2px 6px; 
                        border-radius: 10px; 
                        font-size: 9px;
                        font-weight: bold;
                        margin-left: auto;
                        display: flex;
                        align-items: center;
                        gap: 4px;
                    ">
                        🚫 ЗАБЛОКИРОВАН 👮 ${bannedByInfo}
                    </div>
                    <button 
                        onclick="window.unbanUserCompletely('${user.id}', '${user.username || 'Пользователь'}')" 
                        style="
                            background: linear-gradient(135deg, #4CAF50, #45a049); 
                            color: white; 
                            border: none; 
                            padding: 4px 8px; 
                            border-radius: 4px; 
                            cursor: pointer; 
                            font-weight: bold; 
                            font-size: 10px;
                            margin-left: 10px;
                        "
                        onmouseover="this.style.background='linear-gradient(135deg, #45a049, #3d8b40)'" 
                        onmouseout="this.style.background='linear-gradient(135deg, #4CAF50, #45a049)'"
                        title="Разблокировать пользователя"
                    >
                        🔓
                    </button>
                </div>
            `;
        });
        listHtml += '</div>';

        contentArea.innerHTML = listHtml;
        showNotification(`✅ Найдено заблокированных: ${users.length}`, 'success');

    } catch (error) {
        console.error('❌ Ошибка загрузки заблокированных пользователей:', error);
        showNotification('❌ Ошибка загрузки черного списка', 'error');
        contentArea.innerHTML = `<div style="color: #f44336; padding: 1rem; text-align: center;">Ошибка загрузки черного списка.</div>`;
    }
}

// Экспортируем функции для доступа из других скриптов
window.unbanUserCompletely = window.unbanUserCompletely || async function(userId, username) {
    if (!userId) {
        alert('❌ ID пользователя не указан');
        return;
    }

    // ЗАЩИТА: Проверяем роль пользователя перед разблокировкой
    try {
        const { data: userProfile, error: profileError } = await supabase
            .from('profiles')
            .select('role')
            .eq('id', userId)
            .single();

        if (!profileError && userProfile?.role === 'owner') {
            alert('🛡️ ЗАПРЕЩЕНО: Владелец сайта не может быть разблокирован через эту функцию!');
            return;
        }
    } catch (error) {
        console.warn('⚠️ Не удалось проверить роль пользователя:', error);
    }

    if (!confirm(`🔓 ПОЛНОСТЬЮ разблокировать пользователя "${username}"?\n\nПользователь снова сможет заходить на сайт и использовать все функции.`)) {
        return;
    }

    try {
        // Разблокируем пользователя в profiles
        const { error: profileError } = await supabase
            .from('profiles')
            .update({ 
                is_banned: false,
                ban_reason: null,
                banned_at: null
            })
            .eq('id', userId);

        if (profileError) {
            console.error('❌ Ошибка полной разблокировки:', profileError);
            alert(`❌ Ошибка: ${profileError.message}`);
            return;
        }

// Также деактивируем все блокировки комментариев
const { error: commentError } = await supabase
.from('comment_bans')
.update({ 
ends_at: new Date().toISOString()
})
.eq('user_id', userId);

if (commentError) {
console.warn('⚠️ Ошибка деактивации блокировок комментариев:', commentError);
}

        showNotification('✅ Пользователь полностью разблокирован! Доступ к сайту восстановлен.', 'success');
        
        // Обновляем список заблокированных пользователей
        setTimeout(() => {
            if (typeof showBannedUsersList === 'function') {
                showBannedUsersList();
            }
            // Статистика пользователей удалена
        }, 1000); // Небольшая задержка чтобы увидеть уведомление
        
    } catch (error) {
        console.error('❌ Ошибка:', error);
        showNotification('❌ Произошла ошибка при разблокировке', 'error');
    }
};

/**
 * Показывает список всех VIP-пользователей.
 */
async function showVipUsersList() {
    const contentArea = document.getElementById('admin-content-area');
    if (!contentArea) return;

    contentArea.innerHTML = `<div style="color: #ffd700; padding: 10px;">💎 Загрузка списка VIP-пользователей...</div>`;
    showNotification('💎 Загрузка VIP-пользователей...', 'info', 2000);

    try {
        const { data: users, error } = await supabase
            .from('profiles')
            .select('*')
            .or('is_vip.eq.true,role.in.("moderator","moderator_senior","admin","admin_senior","owner")') // ИСПРАВЛЕНИЕ: Включаем модераторов и админов в список VIP
            .order('username', { ascending: true });

        if (error) throw error;

        let listHtml = `
            <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 15px;">
                <h5 style="color: #ffd700; text-align: center; margin: 0;">💎 VIP-пользователи (${users.length})</h5>
                <button onclick="selectAdminSection('users')" class="hacker-btn" style="background: #00ccff; color: #000; padding: 4px 10px; font-size: 0.7rem;">&larr; К списку</button>
            </div>
        `;

        if (users.length === 0) {
            listHtml += `<div style="color: #8892b0; padding: 1rem; text-align: center;">VIP-пользователи не найдены.</div>`;
            contentArea.innerHTML = listHtml;
            return;
        }

        listHtml += '<div style="max-height: 450px; overflow-y: auto; padding-right: 10px;">';
        listHtml += '<table style="width: 100%; border-collapse: collapse; font-size: 0.8rem;">';
        listHtml += `
            <thead>
                <tr style="border-bottom: 1px solid rgba(255,215,0,0.3);">
                    <th style="padding: 8px; text-align: left; color: #00ccff;">Пользователь</th>
                    <th style="padding: 8px; text-align: center; color: #00ccff;">Роль</th>
                    <th style="padding: 8px; text-align: right; color: #00ccff;">VIP до</th>
                </tr>
            </thead>
            <tbody>
        `;

        users.forEach(user => {
            const roleBadge = getRoleBadge(user.role, user.vip_expires_at);
            let vipTime = 'Бессрочно';
            if (user.vip_expires_at) {
                const diffTime = new Date(user.vip_expires_at) - new Date();
                if (diffTime > 0) {
                    // Если время больше 10 лет, показываем "Бессрочно"
                    const tenYearsInMs = 10 * 365 * 24 * 60 * 60 * 1000;
                    if (diffTime > tenYearsInMs) {
                        vipTime = 'Бессрочно';
                    } else {
                        const remainingDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
                        const remainingHours = Math.floor((diffTime % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
                        vipTime = `${remainingDays}д ${remainingHours}ч`;
                    }
                } else { 
                    vipTime = 'Истёк'; 
                }
            }

            listHtml += `
                <tr style="border-bottom: 1px solid rgba(255,215,0,0.1); cursor: pointer;" onclick="showUserDetailsModal('${user.id}')">
                    <td style="padding: 8px; font-weight: bold; color: #ffd700;">${user.username}</td>
                    <td style="padding: 8px; text-align: center;">${roleBadge}</td>
                    <td style="padding: 8px; text-align: right; color: #4CAF50;">${vipTime}</td>
                </tr>
            `;
        });

        listHtml += '</tbody></table></div>';
        contentArea.innerHTML = listHtml;
        showNotification(`✅ Найдено VIP-пользователей: ${users.length}`, 'success');

    } catch (error) {
        console.error('❌ Ошибка загрузки VIP-пользователей:', error);
        showNotification('❌ Ошибка загрузки VIP-пользователей', 'error');
        contentArea.innerHTML = `<div style="color: #f44336; padding: 1rem; text-align: center;">Ошибка загрузки списка.</div>`;
    }
}

/**
 * ЕДИНАЯ функция статистики для всего сайта
 */
async function loadUnifiedSiteStats() {
    try {
        console.log('🔄 [loadUnifiedSiteStats] Начало загрузки статистики...');
        
        const { data: users, error } = await window.supabase.from('profiles').select('id, role, banned_until, created_at, username, email, is_vip, vip_expires_at, last_seen');
        
        if (error) {
            console.error('❌ [loadUnifiedSiteStats] Ошибка загрузки пользователей:', error);
            throw error;
        }
        
        console.log(`📊 [loadUnifiedSiteStats] Загружено ${users.length} пользователей`);
        
        const [{ count: modsCount }, { count: vipModsCount }, { count: productsCount }, { count: pendingOrdersCount }] = await Promise.all([
            window.supabase.from('mods').select('*', { count: 'exact', head: true }),
            window.supabase.from('mods').select('*', { count: 'exact', head: true }).eq('is_private', true),
            window.supabase.from('products').select('*', { count: 'exact', head: true }),
            window.supabase.from('orders').select('id', { count: 'exact', head: true }).eq('status', 'pending')
        ]);

        const totalUsers = users.length;
        const bannedUsers = users.filter(u => u.is_banned).length;
        const today = new Date().toISOString().slice(0, 10);
        const newUsersToday = users.filter(u => u.created_at.slice(0, 10) === today).length;

        console.log(`📈 [loadUnifiedSiteStats] Базовая статистика: всего=${totalUsers}, забанено=${bannedUsers}, сегодня=${newUsersToday}`);

        // Пороги активности (как в правильной статистике)
        const ACTIVITY_THRESHOLDS = {
            ACTIVE: 30000,    // 30 секунд
            AWAY: 120000,     // 2 минуты
            OFFLINE: 300000,  // 5 минут
            LEFT: 1800000     // 30 ��инут
        };
        
        const now = new Date();
        
        // Считаем активность как в правильной статистике
        let onlineUsers = 0;
        let offlineUsers = 0;
        
        users.forEach(user => {
            if (user.is_banned) return; // Пропускаем забаненных
            
            if (!user.last_seen) {
                offlineUsers++; // Нет данных о последней активности - считаем офлайн
            } else {
                const lastSeen = new Date(user.last_seen);
                const inactiveTime = now - lastSeen;
                
                if (inactiveTime < ACTIVITY_THRESHOLDS.ACTIVE) {
                    onlineUsers++; // Активные
                } else {
                    offlineUsers++; // Неактивные
                }
            }
        });

        const rolesCount = users.reduce((acc, user) => {
            // Исключаем VIP пользователей из подсчета ������������ругих ролей
            if (user.role !== 'vip' && !user.is_vip) {
                acc[user.role] = (acc[user.role] || 0) + 1;
            }
            return acc;
        }, {});

        console.log('👥 [loadUnifiedSiteStats] Распределение по ролям:', rolesCount);

        const vipUsers = users.filter(u => u.role === 'vip' || u.is_vip);
        console.log(`💎 [loadUnifiedSiteStats] Найдено ${vipUsers.length} VIP пользователей`);
        
        // Создаем Map для уникальных пользователей по ID
        const uniqueVipMap = new Map();
        
        vipUsers.forEach(user => {
            if (!uniqueVipMap.has(user.id)) {
                uniqueVipMap.set(user.id, user);
            } else {
                console.log(`❌ Дубликат VIP: ${user.id} - пользователь уже добавлен`);
            }
        });
        
        const uniqueVipUsers = Array.from(uniqueVipMap.values());
        console.log(`✅ [loadUnifiedSiteStats] Уникальных VIP пользователей: ${uniqueVipUsers.length}`);

        const result = {
            totalUsers, bannedUsers, newUsersToday,
            modsCount: modsCount || 0, vipModsCount: vipModsCount || 0,
            productsCount: productsCount || 0, pendingOrdersCount: pendingOrdersCount || 0,
            rolesCount, vipUsers: uniqueVipUsers, vipCount: uniqueVipUsers.length,
            onlineUsers, offlineUsers
        };

        console.log('✅ [loadUnifiedSiteStats] Статистика успешно загружена:', result);
        return result;
    } catch (error) {
        console.error('❌ [loadUnifiedSiteStats] Ошибка загрузки статистики:', error);
        showNotification('❌ Ошибка загрузки статистики', 'error');
        return null;
    }
}

/**
 * Обновляет все элементы статистики на странице
 */
async function updateAllStatsElements() {
    try {
        const stats = await loadUnifiedSiteStats();
        if (!stats) return;

        // Обновляем мини-статистику
        updateMiniStats(stats);
        
        // Обновляем счетчики активности
        updateActivityCounters(stats);
        
        // Обновляем статистику в боковой панели
        updateSidebarStats(stats);
        
        console.log('✅ Все элементы статистики обновлены');
    } catch (error) {
        console.error('❌ Ошибка обновления статистики:', error);
    }
}

/**
 * Обновляет мини-статистику
 */
function updateMiniStats(stats) {
    const elements = {
        'total-users-count': stats.totalUsers,
        'vip-users-count': stats.vipCount,
        'banned-users-count': stats.bannedUsers,
        'mods-count': stats.modsCount
    };
    
    Object.entries(elements).forEach(([id, value]) => {
        updateStatisticDisplay(id, value);
    });
}

/**
 * Обновляет счетчики активности
 */
function updateActivityCounters(stats) {
    const elements = {
        'new-users-today': stats.newUsersToday,
        'pending-orders': stats.pendingOrdersCount,
        'products-count': stats.productsCount,
        'vip-mods-count': stats.vipModsCount
    };
    
    Object.entries(elements).forEach(([id, value]) => {
        updateStatisticDisplay(id, value);
    });
}

/**
 * Обновляет статистику в боковой панели
 */
function updateSidebarStats(stats) {
    const sidebarStats = document.getElementById('sidebar-stats');
    if (sidebarStats) {
        sidebarStats.innerHTML = `
            <div style="color: #00ff41; font-size: 0.7rem;">
                <p>👥 Всего: ${stats.totalUsers}</p>
                <p>💎 VIP: ${stats.vipCount}</p>
                <p>🚫 Заблокировано: ${stats.bannedUsers}</p>
                <p>🎮 Модов: ${stats.modsCount}</p>
            </div>
        `;
    }
}

