// window.editMod = editMod; - УДАЛЕНО: используется обёртка в конце файла (admin-panel-fixed.js)
window.clearOldOrders = clearOldOrders;
window.showMakeOwnerModal = showMakeOwnerModal;
window.transferOwnership = transferOwnership;
window.deleteMod = deleteMod;
window.downloadMod = async function(modId) {
    try {
        console.log('🔐 [GLOBAL DOWNLOAD] Запрос на скачивание мода:', modId);
        
        // Проверяем авторизацию пользователя
        const { data: { user } } = await window.supabase.auth.getUser();

        if (!user) {
            showNotification('Необходимо войти в систему для скачивания модов', 'error');
            showLoginModal();
            return;
        }

        // Используем защищенную систему скачивания если доступна
        if (window.secureDownloadManager) {
            console.log('🔐 [GLOBAL DOWNLOAD] Используем защищенное скачивание...');
            await window.secureDownloadManager.downloadModSecure(modId);
            return;
        }

        // Fallback к старому методу
        console.log('⚠️ [GLOBAL DOWNLOAD] Защищенное скачивание недоступно, используем старый метод...');
        
        // Проверяем, не забанен ли пользователь
        const { data: profile, error: profileError } = await supabase
            .from('profiles')
            .select('is_banned, role, is_vip, vip_expires_at')
            .eq('id', user.id)
            .single();

        if (profileError) throw profileError;

        // Проверяем, является ли мод приватным
        const isPrivateMod = mod.is_private || false;

        if (isPrivateMod) {
            console.log('💎 [GLOBAL DOWNLOAD] VIP мод, проверяем доступ...');
            
            // Проверяем права доступа
            const vipRoles = ['vip', 'moderator', 'moderator_senior', 'admin', 'admin_senior', 'owner'];
            const hasRoleAccess = profile && vipRoles.includes(profile.role);
            const hasVipFlag = profile?.is_vip === true;
            const isNotExpired = !profile?.vip_expires_at || new Date(profile.vip_expires_at) > new Date();
            const hasVipAccess = (hasRoleAccess || hasVipFlag) && isNotExpired;

            console.log('🔍 [GLOBAL DOWNLOAD] VIP проверка:', {
                hasRoleAccess,
                hasVipFlag,
                isNotExpired,
                hasVipAccess,
                role: profile?.role,
                is_vip: profile?.is_vip,
                vip_expires_at: profile?.vip_expires_at
            });

            if (!hasVipAccess) {
                alert('❌ Этот мод доступен только для VIP пользователей!\n\nПолучите VIP статус для доступа к пр��ватным модам.');
                return;
            }
        }

        // Увеличиваем счетчик скачиваний
        await supabase
            .from('mods')
            .update({ download_count: (mod.download_count || 0) + 1 })
            .eq('id', modId);

        // Создаем ссылку для скачивания
        const downloadLink = document.createElement('a');
        downloadLink.href = mod.download_url;
        downloadLink.target = '_blank';
        downloadLink.rel = 'noopener noreferrer';
        downloadLink.download = mod.name || 'mod.zip';
        
        // Добавляем на страницу и кликаем
        document.body.appendChild(downloadLink);
        downloadLink.click();
        document.body.removeChild(downloadLink);

        showNotification(`✅ Мод "${mod.name}" успешно скачивается!`, 'success');

    } catch (error) {
        console.error('❌ [GLOBAL DOWNLOAD] Ошибка скачивания:', error);
        showNotification('❌ Ошибка при скачивании мода: ' + error.message, 'error');
    }
};

