// Функция для показа модального окна жалобы
async function showReportModal(reportedUsername, isAdminOrOwner = false, userRole = null) {
    return new Promise((resolve) => {
        // Создаем модальное окно
        const modal = document.createElement('div');
        modal.style.cssText = `
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: rgba(0, 0, 0, 0.7);
            display: flex;
            justify-content: center;
            align-items: center;
            z-index: 10000;
        `;

        const modalContent = document.createElement('div');
        modalContent.style.cssText = `
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            border-radius: 20px;
            padding: 30px;
            max-width: 500px;
            width: 90%;
            box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
            position: relative;
            animation: modalSlideIn 0.3s ease-out;
        `;

        // Добавляем CSS анимацию
        const style = document.createElement('style');
        style.textContent = `
            @keyframes modalSlideIn {
                from {
                    opacity: 0;
                    transform: translateY(-50px) scale(0.9);
                }
                to {
                    opacity: 1;
                    transform: translateY(0) scale(1);
                }
            }
            .report-modal-title {
                color: white;
                font-size: 24px;
                font-weight: bold;
                margin-bottom: 15px;
                text-align: center;
            }
            .report-modal-warning {
                background: rgba(255, 255, 255, 0.2);
                border-left: 4px solid #ff6b6b;
                padding: 15px;
                border-radius: 10px;
                margin-bottom: 20px;
                color: white;
            }
            .report-modal-input {
                width: 100%;
                padding: 15px;
                border: none;
                border-radius: 10px;
                font-size: 16px;
                background: rgba(255, 255, 255, 0.9);
                margin-bottom: 20px;
                box-sizing: border-box;
            }
            .report-modal-buttons {
                display: flex;
                gap: 10px;
                justify-content: flex-end;
            }
            .report-modal-btn {
                padding: 12px 25px;
                border: none;
                border-radius: 10px;
                font-size: 16px;
                font-weight: bold;
                cursor: pointer;
            }
            .report-modal-btn-cancel {
                background: rgba(255, 255, 255, 0.3);
                color: white;
            }
            .report-modal-btn-cancel:hover {
                background: rgba(255, 255, 255, 0.4);
            }
            .report-modal-btn-submit {
                background: #ff6b6b;
                color: white;
            }
            .report-modal-btn-submit:hover {
                background: #ff5252;
                transform: translateY(-2px);
            }
            .report-modal-close {
                position: absolute;
                top: 15px;
                right: 15px;
                width: 30px;
                height: 30px;
                background: rgba(255, 255, 255, 0.2);
                border: none;
                border-radius: 50%;
                color: white;
                font-size: 18px;
                cursor: pointer;
                display: flex;
                align-items: center;
                justify-content: center;
            }
            .report-modal-close:hover {
                background: rgba(255, 255, 255, 0.3);
                transform: rotate(90deg);
            }
        `;
        document.head.appendChild(style);

        // Заголовок
        const title = document.createElement('h3');
        title.className = 'report-modal-title';
        
        // Определяем роль для отображения
        const roleDisplayNames = {
            'owner': 'владельца сайта',
            'admin_senior': 'старшего администратора',
            'admin': 'администратора',
            'moderator_senior': 'старшего модератора',
            'moderator': 'модератора',
            'vip': 'VIP пользователя',
            'user': 'пользователя'
        };
        const roleDisplay = roleDisplayNames[userRole] || 'пользователя';
        
        title.textContent = `🚨 Жалоба на комментарий ${roleDisplay} ${reportedUsername}`;

        // Предупреждение если это администратор или владелец
        let warningHtml = '';
        if (isAdminOrOwner && userRole === 'owner') {
            // Показываем предупреждение только для настоящего владельца сайта
            warningHtml = `
                <div class="report-modal-warning">
                    <strong>⚠️ ВНИМАНИЕ!</strong><br>
                    ${reportedUsername} - это Владелец сайта!<br>
                    Администраторы имеют иммунитет от автоматической блокировки.<br>
                    Убедитесь, что жалоба обоснована.
                </div>
            `;
        } else if (isAdminOrOwner) {
            // Для администраторов показываем менее строгое предупреждение
            const roleNames = {
                'admin_senior': 'Старший администратор',
                'admin': 'Администратор'
            };
            warningHtml = `
                <div class="report-modal-warning">
                    <strong>⚠️ ВНИМАНИЕ!</strong><br>
                    ${reportedUsername} - это ${roleNames[userRole] || userRole} сайта!<br>
                    Администраторы имеют иммунитет от автоматической блокировки.<br>
                    Убедитесь, что жалоба обоснована.
                </div>
            `;
        }

        modalContent.innerHTML = `
            ${warningHtml}
            <div class="report-modal-title">Почему вы жалуетесь на комментарий ${roleDisplay} ${reportedUsername}?</div>
            <textarea class="report-modal-input" placeholder="Опишите причину жалобы..." rows="4" maxlength="500"></textarea>
            <div class="report-modal-buttons">
                <button class="report-modal-btn report-modal-btn-cancel">Отмена</button>
                <button class="report-modal-btn report-modal-btn-submit">Отправить жалобу</button>
            </div>
            <button class="report-modal-close">×</button>
        `;

        modal.appendChild(modalContent);
        document.body.appendChild(modal);

        const textarea = modalContent.querySelector('.report-modal-input');
        const cancelBtn = modalContent.querySelector('.report-modal-btn-cancel');
        const submitBtn = modalContent.querySelector('.report-modal-btn-submit');
        const closeBtn = modalContent.querySelector('.report-modal-close');

        // Обработчики
        const closeModal = () => {
            modal.remove();
            style.remove();
            resolve(null);
        };

        const submitReport = () => {
            const reason = textarea.value.trim();
            if (!reason) {
                textarea.style.borderColor = '#ff6b6b';
                textarea.placeholder = 'Пожалуйста, укажите причину жалобы...';
                return;
            }
            modal.remove();
            style.remove();
            resolve(reason);
        };

        cancelBtn.addEventListener('click', closeModal);
        closeBtn.addEventListener('click', closeModal);
        submitBtn.addEventListener('click', submitReport);

        // Закрытие по клику на фон
        modal.addEventListener('click', (e) => {
            if (e.target === modal) {
                closeModal();
            }
        });

        // Закрытие по Escape
        const handleEscape = (e) => {
            if (e.key === 'Escape') {
                closeModal();
                document.removeEventListener('keydown', handleEscape);
            }
        };
        document.addEventListener('keydown', handleEscape);

        // Фокус на textarea
        setTimeout(() => textarea.focus(), 100);
    });
}

// Функция для удаления всех рейтингов мода
async function deleteModRatings(modId) {
    if (!confirm('Вы уверены, что хотите удалить все рейтинги этого мода?\n\nЭто действие удалит все оценки пользователей и сбросит рейтинг мода до 0.')) {
        return;
    }

    try {
        // Удаляем все рейтинги для этого мода
        const { error } = await supabase
            .from('mod_ratings')
            .delete()
            .eq('mod_id', modId);

        if (error) throw error;

        // Обновляем рейтинг мода в таблице mods
        const { error: updateError } = await window.supabase
            .from('mods')
            .update({ 
                rating: 0, 
                rating_count: 0,
                updated_at: new Date().toISOString()
            })
            .eq('id', modId);

        if (updateError) throw updateError;

        showNotification('✅ Все рейтинги мода успешно удалены!', 'success');

        // Закрываем и переоткрываем модальное окно для обновления данных
        const modal = document.querySelector('.user-details-modal');
        if (modal) {
            modal.remove();
            // Переоткрываем модальное окно
            setTimeout(() => {
                showModDetails(modId);
            }, 300);
        }

    } catch (error) {
        console.error('Ошибка удаления рейтингов:', error);
        showNotification('❌ Ошибка удаления рейтингов: ' + error.message, 'error');
    }
}

// Функция для удаления мода
async function deleteMod(modId, modName) {
    if (!confirm(`Вы уверены, что хотите удалить мод "${modName}"?\n\nЭто действие необратимо!`)) {
        return;
    }

    try {
        // Проверяем права пользователя
        const profile = await window.authManager.getUserRole();
        if (!profile || !['owner', 'admin_senior', 'admin', 'moderator_senior', 'moderator'].includes(profile.role)) {
            showNotification('❌ У вас нет прав для удаления модов', 'error');
            return;
        }

        showNotification('🗑️ Удаление мода...', 'info');

        // Показываем индикатор загрузки на кнопке если она есть
        const deleteButton = document.querySelector(`button[onclick*="deleteMod('${modId}'"]`);
        if (deleteButton) {
            deleteButton.innerHTML = '⏳ Удаление...';
            deleteButton.disabled = true;
            deleteButton.style.opacity = '0.7';
        }

        // Удаляем связанные комментарии
        await supabase
            .from('mod_comments')
            .delete()
            .eq('mod_id', modId);

        // Удаляем связанные рейтинги
        await supabase
            .from('mod_ratings')
            .delete()
            .eq('mod_id', modId);

        // Удаляем сам мод
        const { error } = await supabase
            .from('mods')
            .delete()
            .eq('id', modId);

        if (error) throw error;

        showNotification(`✅ Мод "${modName}" успешно удален!`, 'success');

        // Немедленно закрываем все модальные окна
        const allModals = document.querySelectorAll('.user-details-modal');
        allModals.forEach(modal => modal.remove());
        
        // Также закрываем другие возможные модальные окна
        const otherModals = document.querySelectorAll('[class*="modal"]');
        otherModals.forEach(modal => {
            if (modal.style.position === 'fixed') {
                modal.remove();
            }
        });

        // Автоматическое обновление интерфейса
        setTimeout(() => {
            // Обновляем админ-панель если открыта
            if (typeof window.loadModsForModeration === 'function') {
                try {
                    window.loadModsForModeration();
                } catch (error) {
                    console.warn('⚠️ Ошибка при вызове loadModsForModeration:', error);
                }
            }
            
            // Обновляем основную страницу модов
            const activeCategory = document.querySelector('.category-btn.active')?.textContent.trim() || 'Все';
            const currentGameVersion = document.querySelector('.game-btn.active')?.dataset.game || 'fs25';
            
            if (typeof loadModsByCategory === 'function') {
                loadModsByCategory(activeCategory, currentGameVersion);
            }
            
            console.log('🔄 Интерфейс автоматически обновлен после удаления мода');
        }, 300);

    } catch (error) {
        console.error('Ошибка удаления мода:', error);
        showNotification(`❌ Ошибка удаления мода: ${error.message}`, 'error');
    }
}

// Вспомогательная функция для форматирования размера файла

function formatFileSize(bytes) {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
}


async function updateOrderStatus(orderId, newStatus, userId = null, username = null) { // ✅ ИСПРАВЛЕНИЕ: Принимаем username
    // ✅ ИСПРАВЛЕНИЕ: Добавляем перевод статуса на русский язык для окна подтверждения.
    const statusTranslations = {
        'completed': 'Завершен',
        'cancelled': 'Отменен',
        'pending': 'В обработке'
    };
    const translatedStatus = statusTranslations[newStatus] || newStatus;

    if (!confirm(`Вы уверены, что хотите изменить статус заказа на "${translatedStatus}"?`)) return;
    try {
        const { error } = await supabase
            .from('orders')
            .update({ status: newStatus })
            .eq('id', orderId);

        if (error) throw error;

        const statusNames = {
            'completed': 'Завершен',
            'cancelled': 'Отменен',
            'pending': 'В обработке'
        };
        const statusName = statusNames[newStatus] || newStatus;
        showNotification(`✅ Статус заказа изменен на: ${statusName}`, 'success');

        // Если статус 'completed' и передан userId, выдаем VIP
        if (newStatus === 'completed' && userId) {
            // ⭐️ ИСПРАВЛЕНИЕ: Теперь сначала вызывается completeOrder,
            // а уже ВНУТРИ него будет окно подтверждения.
            // Это гарантирует, что VIP не будет выдан без подтверждения администратора.
            await completeOrder(orderId, userId, username);
        }

        // Обновляем список заказов
        loadOrders();

        // ⭐️ ИСПРАВЛЕНИЕ: Принудительно обновляем индикаторы в навигации
        // после изменения статуса заказа.
        updateAdminNavIndicators();

    } catch (error) {
        console.error('Ошибка изменения статуса заказа:', error);
        showNotification(`❌ Ошибка: ${error.message}`, 'error');
    }

}
