// Функция для предупреждения пользователя (универсальная)
async function warnUser(userId, username = null, commentId = null, modId = null) {
    // Если username не передан, получаем его из профиля
    if (!username) {
        try {
            const { data: profile } = await supabase
                .from('profiles')
                .select('username')
                .eq('id', userId)
                .single();
            username = profile?.username || 'Пользователь';
        } catch (error) {
            username = 'Пользователь';
        }
    }
    
    // Показываем модальное окно предупреждения
    showWarningModal(userId, username, commentId, modId);
}

