                    // Ищем все ячейки в строке
                    const cells = userRow.querySelectorAll('td');
                    console.log(`📊 Найдено ячеек: ${cells.length}`);
                    
                    cells.forEach((cell, index) => {
                        console.log(`📊 Ячейка ${index}:`, cell.innerHTML.substring(0, 100) + '...');
                    });
                    
                    // Пробуем найти ячейку статуса по разным селекторам
                    let statusCell = null;
                    
                    // Способ 1: td:nth-child(3)
