// Глобальная функция для тестирования применения шрифтов
window.testFontApplication = function(fontName) {
    const mainFontSelect = document.getElementById('mainFont');
    if (mainFontSelect) {
        // Находим опцию с нужным шрифтом
        const options = mainFontSelect.options;
        for (let i = 0; i < options.length; i++) {
            if (options[i].text.toLowerCase().includes(fontName.toLowerCase())) {
                mainFontSelect.value = options[i].value;
                console.log('🧪 Тестирование шрифта:', options[i].text, 'value:', options[i].value);
                
                // Принудительно применяем тему
                const settings = {
                    mainFont: options[i].value,
                    primaryColor: document.getElementById('primaryColor')?.value || '#00cc33',
                    secondaryColor: document.getElementById('secondaryColor')?.value || '#e6b800',
                    bgColor: document.getElementById('bgColor')?.value || '#0a192f',
                    textColor: document.getElementById('textColor')?.value || '#ccd6f6',
                    fontSize: document.getElementById('font-size')?.value + 'px' || '16px'
                };
                applyGlobalTheme(settings);
                console.log('🧪 Тестовый шрифт применен:', options[i].value);
                return true;
            }
        }
        console.log('❌ Шрифт с названием "', fontName, '" не найден');
        return false;
    } else {
        console.log('❌ Элемент mainFont не найден');
        return false;
    }
};

