window.testMatrixFont = function() {
    // console.log('🧪 Тестирование шрифта Матрица...');
    
    // Сначала применяем готовую тему Матрица
    if (window.applyThemePreset && window.themePresets && window.themePresets.matrix) {
        // console.log('🎨 Применяем готовую тему Матрица...');
        window.applyThemePreset('matrix');
        
        setTimeout(() => {
            // console.log('🔍 Теперь проверяем значение в select...');
            const mainFontSelect = document.getElementById('mainFont');
            if (mainFontSelect) {
                // console.log('📋 Текущее значение mainFont:', mainFontSelect.value);
                // console.log('📋 Текущий текст выбранной опции:', mainFontSelect.options[mainFontSelect.selectedIndex]?.text);
                
                // Теперь пробуем изменить вручную
                // console.log('🔄 Теперь пробуем изменить шрифт вручную...');
                mainFontSelect.value = "'Courier New', Courier, monospace";
                
                // Триггерим события
                const event = new Event('change', { bubbles: true });
                mainFontSelect.dispatchEvent(event);
                
                const inputEvent = new Event('input', { bubbles: true });
                mainFontSelect.dispatchEvent(inputEvent);
                
                // console.log('⚡ События change и input отправлены');
            }
        }, 1000);
    } else {
        // console.log('❌ Функция applyThemePreset или тема matrix не найдены');
    }
};

