// Глобальная функция для обновления даты последней смены пароля
window.updatePasswordChangeDate = async function() {
    try {
        // console.log('🔧 Обновление даты последней смены пароля...');
        
        const now = new Date().toISOString();
        const { error } = await window.supabase
            .from('admin_settings')
            .upsert({
                setting_key: 'password_last_changed',
                setting_value: now,
                setting_type: 'timestamp',
                description: 'Время последней смены пароля',
                updated_by: window.currentUser?.email || 'unknown'
            });
        
        if (error) {
            console.error('❌ Ошибка обновления даты:', error);
            return false;
        }
        
        // console.log('✅ Дата последней смены пароля обновлена:', now);
        
        // Обновляем отображение
        if (typeof showAdminPasswordSettings === 'function') {
            await showAdminPasswordSettings();
        }
        
        return true;
    } catch (error) {
        console.error('❌ Ошибка:', error);
        return false;
    }
};

