// Создаем вспомогательные функции для совместимости
window.saveToLocalStorage = function(key, value) {
    try {
        if (typeof storageManager !== 'undefined' && typeof storageManager.setLocalStorage === 'function') {
            storageManager.setLocalStorage(key, value);
        } else {
            localStorage.setItem(key, value);
        }
    } catch (error) {
        console.error('❌ Ошибка сохранения в localStorage:', error);
    }
};

