/**
 * Добавить персональное уведомление (для админ-панели)
 */
window.addPersonalNotification = async function(title, message, userId = null, type = 'info', priority = 1, styleConfig = {}, expiresAt = null) {
    try {
        console.log('🔔 [ADMIN] Добавление персонального уведомления:', { title, message, userId, type, priority });
        
        const { data, error } = await window.supabase
            .rpc('add_personal_notification', {
                p_title: title,
                p_message: message,
                p_user_id: userId,
                p_type: type,
                p_priority: priority,
                p_style_config: styleConfig,
                p_expires_at: expiresAt
            });
            
        if (error) {
            console.error('❌ [ADMIN] Ошибка добавления уведомления:', error);
            return { success: false, error };
        }
        
        console.log('✅ [ADMIN] Персональное уведомление добавлено:', data);
        
        // Обновляем бегущую строку для пользователя если он онлайн
        if (userId && window.notificationTicker) {
            await showUserPersonalNotifications(userId);
        }
        
        return { success: true, data };
    } catch (error) {
        console.error('❌ [ADMIN] Ошибка в addPersonalNotification:', error);
        return { success: false, error };
    }
};

