/**
 * Получить все персональные уведомления (для админ-панели)
 */
window.getPersonalNotifications = async function(userId = null) {
    try {
        let query = window.supabase
            .from('personal_notifications')
            .select('*, profiles!inner(username, email)')
            .order('priority DESC, created_at DESC');
            
        if (userId) {
            query = query.eq('user_id', userId);
        }
        
        const { data, error } = await query;
        
        if (error) {
            console.error('❌ [ADMIN] Ошибка получения уведомлений:', error);
            return { success: false, error };
        }
        
        return { success: true, data };
    } catch (error) {
        console.error('❌ [ADMIN] Ошибка в getPersonalNotifications:', error);
        return { success: false, error };
    }
};

