// Инициализация глобального медиаплеера при загрузке страницы
document.addEventListener('DOMContentLoaded', async function() {
    console.log('🚀 DOM загружен, начинаем инициализацию...');
    
    // 🔧 УДАЛЯЕМ ВСЕ VIP-МОДАЛЬНЫЕ ОКНА ПРИ ЗАГРУЗКЕ
    const existingVipModals = document.querySelectorAll('.vip-section-modal, .vip-modal');
    if (existingVipModals.length > 0) {
        console.warn(`🧹 Найдено ${existingVipModals.length} VIP-модальных окон, удаляем...`);
        existingVipModals.forEach(modal => modal.remove());
    }
    
    // 🔧 НАБЛЮДАТЕЛЬ ЗА СОЗДАНИЕМ VIP-МОДАЛЬНЫХ ОКНАМИ
    const vipModalObserver = new MutationObserver(function(mutations) {
        mutations.forEach(function(mutation) {
            mutation.addedNodes.forEach(function(node) {
                if (node.nodeType === 1) { // Element node
                    // Проверяем сам узел
                    if (node.classList && (node.classList.contains('vip-section-modal') || node.classList.contains('vip-modal'))) {
                        console.log('ℹ️ [VIP-WATCHER] Обнаружено VIP-окно, проверяем источник...', node);
                        // Не удаляем автоматически, только логируем
                        return;
                    }

                    // Проверяем дочерние элементы
                    const vipModals = node.querySelectorAll ? node.querySelectorAll('.vip-section-modal, .vip-modal') : [];
                    if (vipModals.length > 0) {
                        console.log('ℹ️ [VIP-WATCHER] Обнаружены VIP-окна внутри:', vipModals);
                        // Не удаляем автоматически, только логируем
                    }
                }
            });
        });
    });
    
    // Начинаем наблюдение за всем документом
    vipModalObserver.observe(document.body, {
        childList: true,
        subtree: true
    });
    
    console.log('🔧 VIP-модальный наблюдатель активирован');
    
    // Инициализация бегущей строки
    initNotificationTicker();
    
    // Загружаем настройки сайта при загрузке страницы
    await loadSiteSettings();
    
    // Проверяем и защищаем текущего пользователя от автоматической блокировки
    // Ждем авторизации с несколькими попытками
    let attempts = 0;
    const maxAttempts = 5;
    const checkUser = async () => {
        const currentUser = typeof getCurrentUser === 'function' ? getCurrentUser() : null;
        
        if (currentUser && currentUser.id) {
            console.log('👤 [INIT] Найден текущий пользователь:', currentUser.email);
            
            // Проверяем существование таблиц перед вызовом
            console.log('🔍 [INIT] Проверяем таблицы уведомлений...');
            try {
                const { data: testData, error: testError } = await window.supabase
                    .from('user_active_notifications')
                    .select('*')
                    .limit(1);
                    
                if (testError) {
                    console.error('❌ [INIT] Таблица user_active_notifications не найдена:', testError);
                    console.log('⚠️ [INIT] SQL файл create_warnings_tables_fixed.sql не выполнен!');
                    
                    // Добавляем тестовое сообщение напрямую в бегущую строку
                    if (window.notificationTicker) {
                        window.notificationTicker.addInfoMessage('🔧 ВЫПОЛНИТЕ SQL ФАЙЛ create_warnings_tables_fixed.sql В SUPABASE!');
                    }
                } else {
                    console.log('✅ [INIT] Таблицы найдены, загружаем персональные уведомления...');
                    // Показываем персональные уведомления для пользователя
                    await showUserPersonalNotifications(currentUser.id);
                }
            } catch (error) {
                console.error('❌ [INIT] Ошибка проверки таблиц:', error);
            }
        } else {
            attempts++;
            if (attempts < maxAttempts) {
                console.log(`👤 [INIT] Пользователь еще не авторизован, попытка ${attempts}/${maxAttempts}...`);
                setTimeout(checkUser, 1000); // Проверяем через 1 секунду
            } else {
                console.log('👤 [INIT] Пользователь не авторизован после всех попыток');
            }
        }
    };
    
    // Начинаем проверку через 1 секунду
    setTimeout(checkUser, 1000);
    
    // Обновляем видимость кнопки загрузки мода в навигации
    updateUploadModButtonVisibility();
    
    // 🎨 Применяем цветовые классы к активным контейнерам категорий
    setTimeout(() => {
        applyCategoryColors();
    }, 500);
    
    // 🔥 ФИНАЛЬНАЯ ПРОВЕРКА: Применяем цвета еще раз через 2 секунды
    setTimeout(() => {
        applyCategoryColors();
        console.log('🎨 Финальное применение цветовых классов завершено');
        
        // 🔧 ДЕБАГ: Выводим информацию о контейнерах
        if (window.debugCategoryColors) {
            setTimeout(() => {
                console.log('🔧 Запуск дебаг функции для проверки цветов...');
                window.debugCategoryColors();
            }, 500);
        }
    }, 2000);
    
    // 🔥 УСТАНАВЛИВАЕМ НАЧАЛЬНЫЙ АТРИБУТ АКТИВНОЙ ИГРЫ
    if (currentGameVersion) {
        document.body.setAttribute('data-active-game', currentGameVersion);
        console.log(`🎮 Установлен атрибут data-active-game: ${currentGameVersion}`);
    } else {
        console.warn('⚠️ currentGameVersion не определена, используем значение по умолчанию');
        document.body.setAttribute('data-active-game', 'fs25');
    }
    
    setTimeout(() => {
        // Плеер выключен по умолчанию - не создаем его автоматически
        console.log('🎵 Плеер администратора выключен по умолчанию. Используйте раздел "🎵 ПЛЕЕР" в админ-панели для включения.');
    }, 1000);
});

