// Глобальные функции для подсветки звезд рейтинга
window.highlightRatingStars = function(star, rating, modId) {
    const container = document.getElementById('rating-stars-' + modId);
    if (!container) return;
    
    const stars = container.querySelectorAll('span');
    stars.forEach((s, index) => {
        if (index < rating) {
            s.style.color = '#ff4444';
            s.style.transform = 'scale(1.2)';
            s.style.textShadow = '0 0 15px rgba(255, 68, 68, 0.8)';
        } else {
            s.style.color = '#666';
            s.style.transform = 'scale(1)';
            s.style.textShadow = 'none';
        }
    });
};

window.resetRatingStars = function(modId) {
    const container = document.getElementById('rating-stars-' + modId);
    if (!container) return;
    
    const stars = container.querySelectorAll('span');
    stars.forEach(s => {
        s.style.color = '#666';
        s.style.transform = 'scale(1)';
        s.style.textShadow = 'none';
    });
};

// Глобальная функция для показа модального окна загрузки мода
window.showPublicUploadModModal = async function() {
    console.log('🚀 Открытие публичного модального окна загрузки мода');
    
    // Проверяем политику загрузки модов
    try {
        // Проверяем существование объекта политики
        if (!window.modUploadPolicy || typeof window.modUploadPolicy.canUserUploadMod !== 'function') {
            console.error('❌ Объект политики загрузки модов не найден');
            showNotification('❌ Система проверки политики загрузки недоступна', 'error');
            return;
        }
        
        const policyCheck = await window.modUploadPolicy.canUserUploadMod();
        console.log('🔐 Проверка политики загрузки:', policyCheck);
        
        if (!policyCheck || !policyCheck.allowed) {
            showNotification('❌ ' + (policyCheck?.reason || 'Ошибка проверки политики загрузки'), 'error');
            return;
        }
        
        // Показываем информацию о политике если есть предупреждения
        if (policyCheck.requiresModeration && !policyCheck.bypassPolicy) {
            console.log('⏳ Мод будет отправлен на модерацию');
        }
    } catch (error) {
        console.error('❌ Ошибка проверки политики загрузки:', error);
        showNotification('❌ Ошибка проверки политики загрузки мода', 'error');
        return;
    }
    
    // Принудительно загружаем настройки перед открытием модального окна
    try {
        console.log('🔄 Принудительная загрузка настроек сайта...');
        if (typeof window.loadSiteSettings === 'function') {
            await window.loadSiteSettings();
            console.log('✅ Настройки загружены:', {
                userModUploadsEnabled: window.userModUploadsEnabled,
                modApprovalRequired: window.modApprovalRequired
            });
            
            // Небольшая задержка чтобы убедиться что настройки применились
            await new Promise(resolve => setTimeout(resolve, 100));
            
            console.log('🔍 Финальная проверка настроек:', {
                userModUploadsEnabled: window.userModUploadsEnabled,
                modApprovalRequired: window.modApprovalRequired
            });
        }
    } catch (error) {
        console.error('❌ Ошибка принудительной загрузки настроек:', error);
    }
    
    // Проверяем авторизацию
    if (!window.authManager || !window.authManager.isAuthenticated()) {
        showNotification('❌ Для загрузки модов необходимо авторизоваться!', 'error');
        return;
    }
    
    const currentUser = window.authManager.getCurrentUser();
    if (!currentUser) {
        showNotification('❌ Для загрузки модов необходимо авторизоваться!', 'error');
        return;
    }
    
    // Создаем модальное окно
    const modalOverlay = document.createElement('div');
    modalOverlay.id = 'upload-mod-modal-overlay';
    modalOverlay.style.cssText = `
        position: fixed;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background: rgba(0, 0, 0, 0.8);
        display: flex;
        justify-content: center;
        align-items: center;
        z-index: 10000;
    `;
    
    // Определяем текст в зависимости от настроек модерации
    console.log('🔍 DEBUG: window.modApprovalRequired =', window.modApprovalRequired);
    console.log('🔍 DEBUG: window.userModUploadsEnabled =', window.userModUploadsEnabled);
    
    const moderationText = window.modApprovalRequired ? 
        'Мод будет отправлен на модерацию и появится на сайте после проверки' : 
        'Мод появится на сайте сразу после загрузки';
    
    const moderationIcon = window.modApprovalRequired ? '⏳' : '✅';
    
    modalOverlay.innerHTML = `
        <div style="background: #0a192f; border: 2px solid #4fc3f7; border-radius: 15px; padding: 30px; max-width: 800px; width: 90%; max-height: 90vh; overflow-y: auto; position: relative;">
            <button onclick="this.closest('#upload-mod-modal-overlay').remove()" style="position: absolute; top: 15px; right: 15px; background: #ff4444; color: white; border: none; width: 30px; height: 30px; border-radius: 50%; cursor: pointer; font-size: 16px;">×</button>
            
            <!-- Горизонтальные табы в ряд -->
            <div style="display: flex; gap: 8px; margin-bottom: 20px; border-bottom: 2px solid rgba(79, 195, 247, 0.3); padding-bottom: 10px; flex-wrap: nowrap; align-items: center;">
                <button onclick="showUploadFormTab()" id="upload-form-tab" style="background: linear-gradient(45deg, #4fc3f7, #2980b9); color: white; border: none; padding: 8px 16px; border-radius: 6px; cursor: pointer; font-weight: bold; font-size: 0.9rem; white-space: nowrap; flex-shrink: 0;">🚀 Загрузка</button>
                <button onclick="showUploadedModsTab()" id="uploaded-mods-tab" style="background: linear-gradient(45deg, #333, #555); color: white; border: none; padding: 8px 16px; border-radius: 6px; cursor: pointer; font-weight: bold; font-size: 0.9rem; white-space: nowrap; flex-shrink: 0;">📋 Загруженные</button>
                <button onclick="showUploadSettingsTab()" id="upload-settings-tab" style="background: linear-gradient(45deg, #333, #555); color: white; border: none; padding: 8px 16px; border-radius: 6px; cursor: pointer; font-weight: bold; font-size: 0.9rem; white-space: nowrap; flex-shrink: 0;">⚙️ Настройки</button>
            </div>
            
            <!-- Контент табов -->
            <div id="upload-tab-content">
                <!-- Содержимое будет загружено динамически -->
            </div>
        </div>
    `;
    
    // Добавляем модальное окно на страницу
    document.body.appendChild(modalOverlay);
    
    // Показываем таб загрузки по умолчанию
    showUploadFormTab();
    
    // Делаем функции глобальными
    window.showUploadFormTab = showUploadFormTab;
    window.showUploadedModsTab = showUploadedModsTab;
    window.showUploadSettingsTab = showUploadSettingsTab;
};

