// Функция показа таба загруженных модов
async function showUploadedModsTab() {
    const content = document.getElementById('upload-tab-content');
    if (!content) return;

    // Обновляем стили кнопок табов
    updateUploadTabStyles('uploaded');

    // Получаем текущего пользователя
    const user = typeof getCurrentUser === 'function' ? getCurrentUser() : (window.authManager?.getCurrentUser() || null);
    if (!user) {
        content.innerHTML = `
            <div style="background: rgba(79, 195, 247, 0.1); border: 1px solid rgba(79, 195, 247, 0.3); border-radius: 8px; padding: 20px;">
                <h3 style="color: #4fc3f7; margin-top: 0; margin-bottom: 20px;">📋 Загруженные моды</h3>
                <p style="color: #8892b0; text-align: center;">⚠️ Вы должны войти в систему для просмотра своих модов.</p>
            </div>
        `;
        return;
    }

    // Показываем индикатор загрузки
    content.innerHTML = `
        <div style="background: rgba(79, 195, 247, 0.1); border: 1px solid rgba(79, 195, 247, 0.3); border-radius: 8px; padding: 20px;">
            <h3 style="color: #4fc3f7; margin-top: 0; margin-bottom: 20px;">📋 Загруженные моды</h3>
            <p style="color: #8892b0; text-align: center;">⏳ Загрузка модов...</p>
        </div>
    `;

    try {
        // Загружаем моды текущего пользователя
        const { data: mods, error } = await window.supabase
            .from('mods')
            .select('*')
            .eq('user_id', user.id)
            .order('created_at', { ascending: false });

        if (error) throw error;

        // Считаем моды по версиям игр
        const fs25Count = mods ? mods.filter(m => m.game_version === 'fs25').length : 0;
        const fs22Count = mods ? mods.filter(m => m.game_version === 'fs22').length : 0;
        const fs19Count = mods ? mods.filter(m => m.game_version === 'fs19').length : 0;
        const totalCount = mods ? mods.length : 0;

        // Формируем HTML со счётчиком (по цветам игр)
        content.innerHTML = `
            <div style="background: rgba(79, 195, 247, 0.1); border: 1px solid rgba(79, 195, 247, 0.3); border-radius: 8px; padding: 20px;">
                <h3 style="color: #4fc3f7; margin-top: 0; margin-bottom: 20px;">
                    📋 Загруженные моды 
                    <span style="background: rgba(79, 195, 247, 0.2); padding: 2px 8px; border-radius: 12px; font-size: 0.8rem;">Всего: ${totalCount}</span>
                    <span style="background: rgba(76, 175, 80, 0.3); color: #4CAF50; padding: 2px 8px; border-radius: 12px; font-size: 0.8rem; margin-left: 5px; font-weight: bold;">🟢 FS25: ${fs25Count}</span>
                    <span style="background: rgba(33, 150, 243, 0.3); color: #2196F3; padding: 2px 8px; border-radius: 12px; font-size: 0.8rem; margin-left: 5px; font-weight: bold;">🔵 FS22: ${fs22Count}</span>
                    <span style="background: rgba(255, 193, 7, 0.3); color: #FFC107; padding: 2px 8px; border-radius: 12px; font-size: 0.8rem; margin-left: 5px; font-weight: bold;">🟡 FS19: ${fs19Count}</span>
                </h3>
                ${mods && mods.length > 0 ? `
                    <div style="max-height: 400px; overflow-y: auto; margin-top: 15px;">
                        ${mods.map(mod => {
                            const gv = mod.game_version?.toLowerCase();
                            let gameVersionBadge;
                            if (gv === 'fs25') {
                                gameVersionBadge = '<span style="background: rgba(76,175,80,0.2); color: #4CAF50; padding: 2px 6px; border-radius: 4px; font-size: 0.75rem; font-weight: bold;">🟢 FS25</span>';
                            } else if (gv === 'fs22') {
                                gameVersionBadge = '<span style="background: rgba(33,150,243,0.2); color: #2196F3; padding: 2px 6px; border-radius: 4px; font-size: 0.75rem; font-weight: bold;">🔵 FS22</span>';
                            } else if (gv === 'fs19') {
                                gameVersionBadge = '<span style="background: rgba(255,193,7,0.2); color: #FFC107; padding: 2px 6px; border-radius: 4px; font-size: 0.75rem; font-weight: bold;">🟡 FS19</span>';
                            } else {
                                gameVersionBadge = `<span style="color: #8892b0; font-size: 0.75rem;">${mod.game_version?.toUpperCase() || 'FS25'}</span>`;
                            }
                            return `
                            <div style="background: rgba(10, 25, 47, 0.5); border: 1px solid rgba(79, 195, 247, 0.2); border-radius: 8px; padding: 12px; margin-bottom: 10px;">
                                <div style="display: flex; justify-content: space-between; align-items: center;">
                                    <div>
                                        <strong style="color: #4fc3f7;">${mod.name}</strong>
                                        <span style="color: #8892b0; font-size: 0.85rem; margin-left: 10px;">
                                            ${gameVersionBadge} • ${getRussianCategoryName(mod.category)}
                                        </span>
                                    </div>
                                    <span style="padding: 4px 8px; border-radius: 4px; font-size: 0.75rem; ${mod.is_approved ? 'background: rgba(76, 175, 80, 0.2); color: #4CAF50;' : 'background: rgba(255, 152, 0, 0.2); color: #FF9800;'}">
                                        ${mod.is_approved ? '✅ Одобрен' : '⏳ На модерации'}
                                    </span>
                                </div>
                                <div style="color: #8892b0; font-size: 0.85rem; margin-top: 8px;">
                                    📅 Загружен: ${new Date(mod.created_at).toLocaleString('ru-RU', { day: '2-digit', month: '2-digit', year: '2-digit', hour: '2-digit', minute: '2-digit' })}
                                </div>
                            </div>
                            `;
                        }).join('')}
                    </div>
                ` : `
                    <p style="color: #8892b0; text-align: center; margin-top: 20px;">📭 У вас пока нет загруженных модов.</p>
                `}
                <div style="display: flex; justify-content: center; margin-top: 20px;">
                    <button onclick="showUploadedModsTab()" style="background: linear-gradient(45deg, #4fc3f7, #2980b9); color: white; border: none; padding: 10px 20px; border-radius: 6px; cursor: pointer; font-weight: bold;">
                        🔄 Обновить список
                    </button>
                </div>
            </div>
        `;

    } catch (error) {
        console.error('Ошибка загрузки загруженных модов:', error);
        content.innerHTML = `
            <div style="background: rgba(79, 195, 247, 0.1); border: 1px solid rgba(79, 195, 247, 0.3); border-radius: 8px; padding: 20px;">
                <h3 style="color: #4fc3f7; margin-top: 0; margin-bottom: 20px;">📋 Загруженные моды</h3>
                <p style="color: #ff5722; text-align: center;">❌ Ошибка загрузки: ${error.message}</p>
            </div>
        `;
    }
}

// Функция показа таба настроек
function showUploadSettingsTab() {
    const content = document.getElementById('upload-tab-content');
    if (!content) return;

    // Обновляем стили кнопок табов
    updateUploadTabStyles('settings');

    content.innerHTML = `
        <div style="background: rgba(79, 195, 247, 0.1); border: 1px solid rgba(79, 195, 247, 0.3); border-radius: 8px; padding: 20px;">
            <h3 style="color: #4fc3f7; margin-top: 0; margin-bottom: 20px;">⚙️ Настройки загрузки</h3>
            <p style="color: #8892b0;">Здесь будут находиться настройки для загрузки модов.</p>
        </div>
    `;
}

// Функция об��овле��ия стилей табов
function updateUploadTabStyles(activeTab) {
    const tabs = ['form', 'uploaded', 'settings'];
    const activeColors = 'linear-gradient(45deg, #4fc3f7, #2980b9)';
    const inactiveColors = 'linear-gradient(45deg, #333, #555)';
    
    tabs.forEach(tab => {
        const button = document.getElementById(`upload-${tab}-tab`);
        if (button) {
            if (tab === activeTab) {
                button.style.background = activeColors;
                button.style.color = 'white';
            } else {
                button.style.background = inactiveColors;
                button.style.color = 'white';
            }
        }
    });
}

// Создаем алиас для обратной совместимости
window.showAddModModal = window.showPublicUploadModModal;

// Функция для предпросмотра изображений в публичном модальном окне
window.previewPublicModImage = function(imageNumber) {
    const fileInput = document.getElementById(`public-mod-image-${imageNumber}`);
    const previewDiv = document.getElementById(`public-preview-file-${imageNumber}`);
    
    if (fileInput.files && fileInput.files[0]) {
        const reader = new FileReader();
        reader.onload = function(e) {
            previewDiv.innerHTML = `<img src="${e.target.result}" style="max-width: 100%; max-height: 100%; object-fit: cover;">`;
        };
        reader.readAsDataURL(fileInput.files[0]);
    }
};

// Функция для обработки заг��узки мода из публичного модального окна
window.handlePublicModUpload = async function() {
    console.log('🚀 Начинаем загрузку мода из публичного модального окна');
    
    try {
        const currentUser = window.authManager.getCurrentUser();
        if (!currentUser) {
            showNotification('❌ Вы не авторизованы!', 'error');
            return;
        }

        // Собираем данные формы
        const modData = {
            name: document.getElementById('public-mod-name')?.value?.trim(),
            category: document.getElementById('public-mod-category')?.value,
            gameVersion: document.getElementById('public-mod-game-version')?.value,
            version: document.getElementById('public-mod-version')?.value?.trim(),
            author: document.getElementById('public-mod-author')?.value?.trim(),
            description: document.getElementById('public-mod-description')?.value?.trim(),
            downloadUrl: document.getElementById('public-mod-download-url')?.value?.trim(),
            youtubeLink: document.getElementById('public-youtube-link')?.value?.trim(),
            vkLink: document.getElementById('public-vk-link')?.value?.trim(),
            rutubeLink: document.getElementById('public-rutube-link')?.value?.trim()
        };

        console.log('📋 Данные мода:', modData);

        // Валидация данных через политику
        const validation = window.validateModData(modData);
        if (!validation.isValid) {
            showNotification('❌ Ошибки в форме: ' + validation.errors.join(', '), 'error');
            return;
        }

        // Показываем предупреждения если есть
        if (validation.warnings.length > 0) {
            console.warn('⚠️ Предупреждения:', validation.warnings);
        }

        // Финальная проверка политики перед загрузкой
        // Проверяем существование объекта политики
        if (!window.modUploadPolicy || typeof window.modUploadPolicy.canUserUploadMod !== 'function') {
            console.error('❌ Объект политики загрузки модов не найден');
            showNotification('❌ Система проверки политики загрузки недоступна', 'error');
            return;
        }
        
        const policyCheck = await window.modUploadPolicy.canUserUploadMod();
        if (!policyCheck || !policyCheck.allowed) {
            showNotification('❌ ' + (policyCheck?.reason || 'Ошибка проверки политики загрузки'), 'error');
            return;
        }

        // Показываем индикатор заг��уз��и
        const submitButton = document.querySelector('#public-upload-mod-form button[type="submit"]');
        const originalText = submitButton.innerHTML;
        submitButton.innerHTML = '⏳ Загрузка...';
        submitButton.disabled = true;

        // Подготовка данных для отправки
        const modPayload = {
            name: modData.name,
            category: modData.category,
            game_version: modData.gameVersion,
            version: modData.version,
            author: modData.author,
            description: modData.description,
            download_url: modData.downloadUrl,
            youtube_link: modData.youtubeLink,
            vk_link: modData.vkLink,
            rutube_link: modData.rutubeLink,
            user_id: currentUser.id, // Используем user_id вместо author_id
            is_approved: !policyCheck.requiresModeration, // Статус одобрения зависит от политики
            is_private: false,
            is_vip_mod: false
        };

        console.log('📤 Отправка мода:', modPayload);

        // Отправка в Supabase
        const { data, error } = await window.supabase
            .from('mods')
            .insert([modPayload])
            .select();

        if (error) {
            console.error('❌ Ошибка загрузки мода:', error);
            showNotification('❌ Ошибка загрузки мода: ' + error.message, 'error');
        } else {
            console.log('✅ Мод успешно заг��ужен:', data);
            
            // Показываем соответствующее сообщение
            if (policyCheck.requiresModeration && !policyCheck.bypassPolicy) {
                showNotification('✅ Мод успешно отправлен на модерацию! Он будет опубликован после пр��верки администратором.', 'success');
            } else {
                showNotification('✅ Мод успешно загружен и опубликован на сайте!', 'success');
            }

            // Закрываем модальное окно
            document.getElementById('upload-mod-modal-overlay')?.remove();
            
            // Обновляем список модов
            if (typeof loadModsByCategory === 'function') {
                await loadModsByCategory('Все', currentGameVersion);
            }
        }

        // Восстанавливаем кнопку
        submitButton.innerHTML = originalText;
        submitButton.disabled = false;

    } catch (error) {
        console.error('❌ Критическая ошибка при загрузке мода:', error);
        showNotification('❌ Произошла ошибка при загрузке мода. Попробуйте еще раз.', 'error');
        
        // Восстанавливаем кнопку
        const submitButton = document.querySelector('#public-upload-mod-form button[type="submit"]');
        if (submitButton) {
            submitButton.innerHTML = '🚀 Загрузить мод';
            submitButton.disabled = false;
        }
    }
};

