// Функция переключения видимости пароля
window.togglePasswordVisibility = function(inputId) {
    const input = document.getElementById(inputId);
    if (input) {
        input.type = input.type === 'password' ? 'text' : 'password';
    }
};

// Функция смены админ пароля
window.changeAdminPassword = async function(event) {
    // Если event не передан, создаём пустой объект для предотвращения ошибок
    if (!event) {
        event = { preventDefault: function() {} };
    }
    event.preventDefault();
    
    const currentPassword = document.getElementById('currentPassword').value;
    const newPassword = document.getElementById('newPassword').value;
    const confirmPassword = document.getElementById('confirmPassword').value;
    
    if (newPassword !== confirmPassword) {
        showNotification('❌ Новые пароли не совпадают', 'error', 3000);
        return;
    }
    
    try {
        // Проверяем текущий пароль (здесь должна быть ваша логика проверки)
        const { data: settings, error: fetchError } = await window.supabase
            .from('security_settings')
            .select('admin_password')
            .eq('id', 'admin_panel')
            .single();
            
        if (fetchError) throw fetchError;
        
        if (settings.admin_password !== currentPassword) {
            showNotification('❌ Текущий пароль неверен', 'error', 3000);
            return;
        }
        
        // Обновляем пароль
        const { error: updateError } = await window.supabase
            .from('security_settings')
            .update({
                admin_password: newPassword,
                updated_at: new Date().toISOString()
            })
            .eq('id', 'admin_panel');
            
        if (updateError) throw updateError;
        
        showNotification('✅ Пароль админ-панели успешно изменен', 'success', 3000);
        document.getElementById('changePasswordForm').reset();
        showSettingsManagement(); // Перезагружаем настройки
        
    } catch (error) {
        console.error('❌ Ошибка смены пароля:', error);
        showNotification('❌ Ошибка при смене пароля: ' + error.message, 'error', 3000);
    }
};

// Функция смены VIP пароля в настройках безопасности
window.changeVipPasswordFromSettings = async function() {
    const currentPassword = document.getElementById('current-vip-password').value;
    const newPassword = document.getElementById('new-vip-password').value;
    const confirmPassword = document.getElementById('confirm-vip-password').value;
    
    if (!currentPassword || !newPassword || !confirmPassword) {
        document.getElementById('vip-password-change-result').innerHTML = '<span style="color: #ff4757;">❌ Заполните все поля</span>';
        return;
    }
    
    if (newPassword.length < 6) {
        document.getElementById('vip-password-change-result').innerHTML = '<span style="color: #ff4757;">❌ Новый пароль должен быть не менее 6 символов</span>';
        return;
    }
    
    if (newPassword !== confirmPassword) {
        document.getElementById('vip-password-change-result').innerHTML = '<span style="color: #ff4757;">❌ Новые пароли не совпадают</span>';
        return;
    }
    
    try {
        // Получаем текущий VIP пароль из localStorage
        let currentVipPassword = localStorage.getItem('vip_password') || 'VIP2026KEROS';
        
        // console.log('🔑 [changeVipPasswordFromSettings] Текущий VIP пароль:', currentVipPassword);
        
        // Проверяем текущий VIP пароль
        if (currentPassword !== currentVipPassword) {
            document.getElementById('vip-password-change-result').innerHTML = '<span style="color: #ff4757;">❌ Текущий VIP пароль неверен</span>';
            return;
        }
        
        // Обновляем VIP пароль в localStorage
        localStorage.setItem('vip_password', newPassword);
        localStorage.setItem('vip_password_updated', new Date().toISOString());
        
        document.getElementById('vip-password-change-result').innerHTML = '<span style="color: #4CAF50;">✅ VIP пароль успешно изменен</span>';
        
        // Очищаем поля
        document.getElementById('current-vip-password').value = '';
        document.getElementById('new-vip-password').value = '';
        document.getElementById('confirm-vip-password').value = '';
        
        showNotification('💎 VIP пароль успешно изменен', 'success', 3000);
        
    } catch (error) {
        console.error('❌ [changeVipPasswordFromSettings] Ошибка:', error);
        document.getElementById('vip-password-change-result').innerHTML = '<span style="color: #ff4757;">❌ Ошибка при смене пароля</span>';
        showNotification('❌ Ошибка при смене VIP пароля: ' + error.message, 'error', 3000);
    }
};

