// Функция смены VIP пароля
window.changeVipPassword = async function(event) {
    if (event) {
        event.preventDefault();
    }
    
    const currentPassword = document.getElementById('current-vip-password').value;
    const newPassword = document.getElementById('new-vip-password').value;
    const confirmPassword = document.getElementById('confirm-vip-password').value;
    
    if (newPassword !== confirmPassword) {
        showNotification('❌ Новые VIP пароли не совпадают', 'error', 3000);
        return;
    }
    
    try {
        // Получаем текущий VIP пароль из localStorage
        const storedVipPassword = localStorage.getItem('vip_password') || 'VIP2026KEROS';
        
        // Проверяем текущий VIP пароль
        if (currentPassword !== storedVipPassword) {
            showNotification('❌ Текущий VIP пароль неверен', 'error', 3000);
            return;
        }
        
        // Обновляем VIP пароль в localStorage
        localStorage.setItem('vip_password', newPassword);
        
        showNotification('💎 VIP пароль успешно изменен', 'success', 3000);
        document.getElementById('changeVipPasswordForm').reset();
        showSettingsManagement(); // Перезагружаем настройки
        
    } catch (error) {
        console.error('❌ Ошибка смены VIP пароля:', error);
        showNotification('❌ Ошибка при смене VIP пароля: ' + error.message, 'error', 3000);
    }
};

// Функция обновления кнопок админ-панели
window.updateAdminButtons = function() {
    console.log('🔄 [updateAdminButtons] Обновление кнопок админ-панели...');
    
    const profile = window.authManager?.currentUserProfile;
    if (!profile) return;
    
    const userRole = profile.role;
    console.log('🔄 [updateAdminButtons] Текущая роль:', userRole);
    
    // Обновляем видимость кнопок в зависимости от роли
    const buttons = {
        'admin-mods-btn': ['owner', 'admin_senior', 'admin', 'moderator_senior', 'moderator'].includes(userRole),
        'admin-users-btn': ['owner', 'admin_senior', 'admin'].includes(userRole),
        'admin-vip-btn': ['owner', 'admin_senior', 'admin'].includes(userRole),
        'admin-settings-btn': ['owner', 'admin_senior', 'admin'].includes(userRole)
    };
    
    Object.entries(buttons).forEach(([buttonId, visible]) => {
        const button = document.getElementById(buttonId);
        if (button) {
            button.style.display = visible ? 'block' : 'none';
        }
    });
};

