// Слушатель для обновления ролей в реальном времени
if (window.supabase) {
    const roleChannel = window.supabase.channel('role_changes');
    
    roleChannel.on('broadcast', { event: 'role_updated' }, (payload) => {
        console.log('🔄 [roleChannel] Получено обновление роли:', payload);
        
        const data = payload.payload || payload;
        
        // Если это текущий пользователь, обновляем его сессию
        const currentUser = getCurrentUser();
        if (currentUser && currentUser.id === data.user_id) {
            console.log('🔄 [roleChannel] Обновление роли текущего пользователя:', data.new_role);

            // Показываем уведомление об изменении роли
            showNotification(`🔄 Ваша роль изменена на ${getRoleName(data.new_role)}`, 'info', 5000);

            // Принудительно обновляем сессию
            setTimeout(async () => {
                await window.authManager.getUserRole(true);
                // 🔧 ИСПРАВЛЕНИЕ: Показываем VIP контент после обновления роли
                if (typeof window.authManager.checkAndShowVipContent === 'function') {
                    await window.authManager.checkAndShowVipContent();
                }
                // 🔧 ИСПРАВЛЕНИЕ: Обновляем моды для VIP статуса
                if (typeof window.updateModsForVipChange === 'function') {
                    const isVip = data.new_role === 'vip' || data.new_role === 'moderator' || 
                                  data.new_role === 'moderator_senior' || data.new_role === 'admin' || 
                                  data.new_role === 'admin_senior' || data.new_role === 'owner';
                    window.updateModsForVipChange(currentUser.id, isVip);
                }
                if (typeof loadDashboardContent === 'function') {
                    loadDashboardContent();
                }
                console.log('🔄 [roleChannel] Сессия и интерфейс обновлены');
            }, 1000);
        }
        
        // Обновляем интерфейс для всех админов
        if (typeof loadDashboardContent === 'function') {
            setTimeout(() => {
                loadDashboardContent();
                console.log('🔄 [roleChannel] Интерфейс обновлен для всех');
            }, 500);
        }
        
        // Обновляем статистику на всем сайте
        setTimeout(() => {
            refreshAllStats();
        }, 1000);
    });
    
    roleChannel.subscribe((status) => {
        console.log('🔄 [roleChannel] Статус подписки:', status);
    });
    
    console.log('✅ Канал обновления ролей подписан');
}

// Слушатель localStorage для синхронизации между вкладками
window.addEventListener('storage', (e) => {
    if (e.key && e.key.startsWith('role_update_')) {
        try {
            const data = JSON.parse(e.newValue);
            console.log('🔄 [localStorage] Получено обновление роли:', data);
            
            // Если это текущий пользователь, обновляем его сессию
            const currentUser = getCurrentUser();
            if (currentUser && currentUser.id === data.user_id) {
                console.log('🔄 [localStorage] Обновление роли текущего пользователя:', data.new_role);

                // Показываем уведомление об изменении роли
                showNotification(`🔄 Ваша роль изменена на ${getRoleName(data.new_role)}`, 'info', 5000);

                // Принудительно обновляем сессию
                setTimeout(async () => {
                    await window.authManager.getUserRole(true);
                    // 🔧 ИСПРАВЛЕНИЕ: Показываем VIP контент после обновления роли
                    if (typeof window.authManager.checkAndShowVipContent === 'function') {
                        await window.authManager.checkAndShowVipContent();
                    }
                    // 🔧 ИСПРАВЛЕНИЕ: Обновляем моды для VIP статуса
                    if (typeof window.updateModsForVipChange === 'function') {
                        const isVip = data.new_role === 'vip' || data.new_role === 'moderator' || 
                                      data.new_role === 'moderator_senior' || data.new_role === 'admin' || 
                                      data.new_role === 'admin_senior' || data.new_role === 'owner';
                        window.updateModsForVipChange(currentUser.id, isVip);
                    }
                    if (typeof loadDashboardContent === 'function') {
                        loadDashboardContent();
                    }
                    console.log('🔄 [localStorage] Сессия и интерфейс обновлены');
                }, 1000);
            }
            
            // Обновляем интерфейс для всех админов
            if (typeof loadDashboardContent === 'function') {
                setTimeout(() => {
                    loadDashboardContent();
                    console.log('🔄 [localStorage] Интерфейс обновлен для всех');
                }, 500);
            }
        } catch (error) {
            console.error(' [localStorage] Ошибка обработки обновления роли:', error);
        }
    }
});

